-- Poems batch 322
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('6d9c6685-e330-43d6-9cce-c91de0fcda8b','江豚詩','孔武仲','宋','宋诗','song-poetry','','[]','黑者江豚，白者白塈。',240,'全唐诗/poet.song.49000.json','["黑者江豚，白者白塈。", "狀異名殊，同宅大水。", "淵有羣魚，掠以肥已。", "是謂小害，顧有可喜。", "大川夷平，縞素不起。", "兩兩出没，矜其頰嘴。", "若俛若仰，若躍若跪。", "舟人相語，驚瀾將作。", "亟入灣浦，踣檣布筰。", "俄頃風至，簸山搖岳。", "浪如車輪，氛霧相薄。", "舟人燕安，如在城郭。", "先事而告，昭哉爾功。", "鰐啗牛馬，頭象鼉龍。", "暴殄天物，安得爾同。", "于人無害，所欲易充。", "暴露形體，告人以忠。", "又多膏油，以助汝工。", "江湖下貧，機杼以農。", "烏鵲知風，商羊識雨。", "大厦之下，風雨何苦。", "豈知舟航，方在積險。", "以爾占天，蓍蔡之驗。", "古之報祭，不遺微蟲。"]'),
('044d1b3e-11bb-42c0-b2cc-16147585503b','臨江鮑守示詩二篇因寄之','孔武仲','宋','宋诗','song-poetry','','[]','官居無時節，簿領去復迴。',144,'全唐诗/poet.song.49000.json','["官居無時節，簿領去復迴。", "脅息文網中，壯心安在哉。", "積雪滿西峰，中天白皚皚。", "簾幄晝生寒，復見詩筒來。", "煩襟得洗瀹，耳目亡氛埃。", "紀德無可陳，詩情如七哀。", "昔聞參軍逸，今見太守才。", "况有循吏政，養民如嬰孩。", "窮山虎豹伏，曠野桑麻開。", "邂逅春色滿，百卉東風催。", "吾鄉足山水，使宅佳池臺。", "篇章日愈多，無惜分瓊瑰。"]'),
('5406f4ec-7219-444c-ad62-397cda58ea49','堤下','孔武仲','宋','宋诗','song-poetry','','[]','堤下人家喧笑語，高揭青帘椎瓦鼓。',96,'全唐诗/poet.song.49000.json','["堤下人家喧笑語，高揭青帘椎瓦鼓。", "黄流滚滚經簷甍，一任征夫作船苦。", "緑榆覆水平如盃，前灣旋放水頭來。", "深如怒虎著船底，玉石磊砢相喧豗。", "黄河雖斷隋渠急，舟楫舒遲行旋澀。", "獨上平堤望遠天，衣裘已畏西風入。"]'),
('a771edcc-886f-45b2-b86c-f9b661012b9b','寄襄邑宰丁陽叔','孔武仲','宋','宋诗','song-poetry','','[]','溪上一杯酒，送君今幾時。',288,'全唐诗/poet.song.49000.json','["溪上一杯酒，送君今幾時。", "譬如霜林籜，浩蕩從風吹。", "初飄清湘濵，今落濁汴湄。", "蹉跎雖漸老，相見更容怡。", "尚賴城市俗，籃輿遠追隨。", "鳴騶驚雁鶩，笑語在空陂。", "會食古道場，僧房静簾帷。", "敗荷覆一水，落葉鳴軒墀。", "偶坐亦無事，幽來更何之。", "旁有宋襄墓，高墳映深祠。", "爐烟已寂寞，拱木相蔽虧。", "意象宛如在，興亡真可悲。", "寥寥千餘年，華采幾紛披。", "有如蛙争水，頃刻成枯池。", "池盡復爲陸，陸黍秋離離。", "追惟泓之戰，語濶氣甚夷。", "狗頸不急搦，干將仍倒持。", "欲將烏合衆，慕彼鷹揚師。", "首領幾不完，身復爲囚覊。", "好大不量力，荒哉徒爾爲。", "曾不如勾踐，潜軍卷旌麾。", "夜上姑蘇臺，吳人猶不知。", "用兵貴權謀，高言竟何施。", "從兹以名邑，留作永世規。"]'),
('4d2d9bdd-9549-4328-b137-71403815e845','猩猩毛筆與黄魯直同賦','孔武仲','宋','宋诗','song-poetry','','[]','染血以爲衣，稍親日月光。',96,'全唐诗/poet.song.49000.json','["染血以爲衣，稍親日月光。", "封唇以佐酒，衆饌登華堂。", "誰令拔其毛，萬里歸文房。", "纎妍依象管，寂寞伴螢囊。", "生已多言語，死猶近文章。", "一身皆有用，豈卹軀幹傷。", "鼠須固微細，兔毫亦尋常。", "物以異爲貴，嗟哉俱自戕。"]'),
('9871a67c-e331-48ab-94a7-b8b067bf8560','汴河','孔武仲','宋','宋诗','song-poetry','','[]','{禜示=石}渠斜與昆河接，河遠渠慳幾可涉。',245,'全唐诗/poet.song.49000.json','["{禜示=石}渠斜與昆河接，河遠渠慳幾可涉。", "狂霖一漲高十尋，迅瀉東來比三峽。", "崩騰下與淮泗會，清泚亦容伊雒雜。", "横空九闕真垂虹，怒捲千艘如敗葉。", "祇堪平地看洶湧，何事乘危理舟楫。", "共夫鵝鸛行天上，遙與谷中相應答。", "但憂心手一乖迕，巨舶高檣兩摧折。", "而余進退久安命，掲厲以望初不懾。", "妻孥亦已慣江湖，笑語猶如泛山陿。", "鳴弓擊柝驚夜盜，掘茹撈鰕佐晨饁。", "時登絕逕步榆柳，或面荒陂看鳬鴨。", "我生東南趣向野，揮弄清溪看苕霅。", "枕流潄石真所便，履濁凌險終未愜。", "觚稜漸喜金闕近，釜甑何憂米塩乏。", "渾如海客泛枯槎，繚繞明河望閶闔。"]'),
('942a6415-577b-4fc4-a440-d41e9e80762e','汴河汲井','孔武仲','宋','宋诗','song-poetry','','[]','解纜古城陰，繫舟緑榆影。',132,'全唐诗/poet.song.49000.json','["解纜古城陰，繫舟緑榆影。", "浩蕩觀濁流，咫尺有甘井。", "譬如坐湯鑊，傍觀冰玉冷。", "望之首不回，清泉逐修綆。", "餘香入新稻，真味添細茗。", "蒸骨爲之凉，醉魄一以醒。", "昔有少陵翁，卜居在遐境。", "美味當百金，修筒接千嶺。", "我今渾不費，汲取在俄頃。", "川路遠迢迢，客愁長耿耿。", "得此稍忘憂，無殊卧箕潁。"]'),
('5594311d-954a-4a2c-9c46-c10acd384687','試院看月呈子駿明叔','孔武仲','宋','宋诗','song-poetry','','[]','禁城遙想催銀箭，燈火相望人語斷。',120,'全唐诗/poet.song.49000.json','["禁城遙想催銀箭，燈火相望人語斷。", "門外流塵任自高，中秋好月來相伴。", "依樓委砌冰皎潔，射隙侵櫺雪凌亂。", "同僚二公迹見親，相應頋影爲三人。", "吟咏清景臨佳樹，骨爽襟寒不能去。", "頗疑宵夢到蟾宫，欲把秋毫分玉兔。", "中山美酒生微波，銀瓶快瀉金叵羅，相邀一醉君如何。"]'),
('419250dd-a2b6-4c27-97bf-a4ece71fded5','食蛤蜊呈子駿明叔','孔武仲','宋','宋诗','song-poetry','','[]','兩君霜夜兩相過，有酒無肴争奈何。',264,'全唐诗/poet.song.49000.json','["兩君霜夜兩相過，有酒無肴争奈何。", "蛤蜊買得雖不多，百枚包以一枯荷。", "呼奴再濯清泠波，玉石磊落聲相磨。", "乾薪烈焰稍駢羅，暴殄天物真煩苛。", "閉關拒敵難揮戈，劃然雙闢如嘘呵。", "天然甘露貯玉窠，不須易牙爲調和。", "争先賈勇手自拏，莫笑擎盤無翠娥。", "釪明肉净絕泥沙，棄擲頑殻如投梭。", "宫醅灧灧鸚鵡螺，滿飲不惜朱顔酡。", "念初搜索從海涯，千斤秪載雙駱駝。", "都城觀闕雲峨峨，時新首到王公家。", "吾儕得啖已蹉跎，勢力不敵怨則那。", "往歲端居臨漕河，此物堆積如山坡。", "蟶𧍧淡菜暨車蛾，其實氣味俱同科。", "但嫌咀嚼費齒牙，何嘗珍惜如京華。", "物雖難得味乃佳，一壺千金古所嗟，三嗅而興君爲歌。"]'),
('e01ef60b-efcc-41e7-a243-dfdaf13f7f88','魚石二首  其一','孔武仲','宋','宋诗','song-poetry','','[]','人疑魚託石，我謂石爲魚。',48,'全唐诗/poet.song.49000.json','["人疑魚託石，我謂石爲魚。", "持以贈君子，端能辟蠧書。", "無情逐波浪，有此璠與璵。", "坐得江湖意，蕭然亦起予。"]'),
('1f085d11-6154-4d36-afe1-2a5e95de6bbf','魚石二首  其二','孔武仲','宋','宋诗','song-poetry','','[]','鬐鬛真可辨，精研真入神。',48,'全唐诗/poet.song.49000.json','["鬐鬛真可辨，精研真入神。", "得非造化境，亦有雕鎪人。", "頗疑著妄想，歲久積成真。", "兹理不足怪，方屏藏月輪。"]'),
('7de84803-d892-4c91-ab57-49b4d9f512ed','遣百朋赴太學補試','孔武仲','宋','宋诗','song-poetry','','[]','冉冉浪相逐，江湖今十年。',156,'全唐诗/poet.song.49000.json','["冉冉浪相逐，江湖今十年。", "念使從遠學，家貧乏鞍韀。", "一官來京都，環堵當西阡。", "學省咫尺近，彷彿聞誦弦。", "暫當辭家庭，裘馬去翩翩。", "英豪多出此，切琢期勉旃。", "昔我遠方來，算里近五千。", "清燈耿殘月，積雪堆窮年。", "對經必斂衽，求師欣執鞭。", "絢藻頗不乏，屢貢多士先。", "所願克堂構，使我安食眠。", "爾祖最爾愛，置膝自撫憐。", "追恨不及見，泪下如湧泉。"]'),
('8b33efb5-0fe0-4e81-bb7e-503e547b8e95','李公擇山房','孔武仲','宋','宋诗','song-poetry','','[]','石磴不容步，喬林森迴還。',60,'全唐诗/poet.song.49000.json','["石磴不容步，喬林森迴還。", "聞昔有威鳳，養羽留此山。", "乘此去翺翔，得意今不還。", "餘音落何處，尚在雲泉間。", "陳迹雖可尋，飛轍誰能攀。"]'),
('25cef364-12a9-4c18-bad5-968977b40548','葉師迎娶還吳省親遂之官達州以詩見意','孔武仲','宋','宋诗','song-poetry','','[]','言止蘇臺駕，遂泛荆江舟。',120,'全唐诗/poet.song.49000.json','["言止蘇臺駕，遂泛荆江舟。", "京師訣别易，不以樽俎留。", "念書片言贈，俚音謝珠球。", "飛飛雙鳳凰，指日還故丘。", "更翔西南天，江雲慘高秋。", "尊公今季鷹，菰蓴契良謀。", "恩威在兩部，所至膏澤流。", "弟當繼華門，不愧古箕裘。", "高風長堤柳，挂帨已雄牛。", "相望以功業，毋爲置書郵。"]'),
('cab337f6-09a2-4f6d-8560-90e4e2f6986b','送趙正夫使江東','孔武仲','宋','宋诗','song-poetry','','[]','酌我一樽酒，送君千里行。',72,'全唐诗/poet.song.49000.json','["酌我一樽酒，送君千里行。", "青天連上黨，秋雁回汾并。", "戍壘鞠芳草，耕夫歌太平。", "庶獄須照膽，多士在提衡。", "暫往喻上意，還歸對承明。", "無爲厭朝集，寂寞戀邊城。"]'),
('10488ae7-0150-481d-bed2-3227f213b330','送畢公叔使河北','孔武仲','宋','宋诗','song-poetry','','[]','東觀久寂寥，君王念多士。',120,'全唐诗/poet.song.49000.json','["東觀久寂寥，君王念多士。", "鸞鳳望青雲，聯翩羽翰起。", "英英畢公叔，聲價動天子。", "劇談時利害，如瀉九江水。", "驊騮厭覊縻，放步即千里。", "間關北門道，牽車從此始。", "蓬瀛墨寶爛，原隰皇華美。", "英氣掃豺狼，清風回獄市。", "雖牽倚門念，猶勝捧檄喜。", "書止慰索居，時付黄河鯉。"]'),
('74b12656-b2f8-4a3d-ba39-1f40dcb281a6','書館買粟飯取閤門水以接晝饑','孔武仲','宋','宋诗','song-poetry','','[]','食粟淡有味，飲泉甘且清。',108,'全唐诗/poet.song.49000.json','["食粟淡有味，飲泉甘且清。", "粟白來天市，泉美汲官城。", "斜暉轉西窗，饑腸蚯蚓鳴。", "暫時簞瓢趣，無計邱壑情。", "華堂發八珍，甘鮮雜鹹腥。", "挾取既不專，棄餘飼蒼蠅。", "何如簡且易，月夜泛瑤瓊。", "快汲不留咽，殊勝豆與粳。", "井冽有真甘，復不糝藜羮。"]'),
('dff073cd-a34b-4927-8847-5f82a4b76556','遊善題寺二首 李長者畫像','孔武仲','宋','宋诗','song-poetry','','[]','磥砢一居士，娉婷雙少年。',36,'全唐诗/poet.song.49000.json','["磥砢一居士，娉婷雙少年。", "對景如無有，著書方浩然。", "分身聊示現，誰悟此因緣。"]'),
('0bdde8d9-10d7-46d6-a309-c7f950725f9b','遊善題寺二首 殿西','孔武仲','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','步屧出廣殿，花木何陰陰。',36,'全唐诗/poet.song.49000.json','["步屧出廣殿，花木何陰陰。", "鳥聲來迎客，幽趣是山林。", "當年曾如此，遍入匡廬深。"]'),
('a1089511-4653-4dfa-8c4f-18006ea77861','五月望參','孔武仲','宋','宋诗','song-poetry','','[]','起夜詠庭燎，晨裝候當門。',108,'全唐诗/poet.song.49000.json','["起夜詠庭燎，晨裝候當門。", "雙飛劃天起，萬馬散雲屯。", "王喬背城郭，飛鸞從遠村。", "入綴外朝列，每瞻天帝尊。", "時值甘雨足，大官復牢飱。", "殿開宸極正，日映玉顔温。", "抃舞効百獸，飛翔侣羣鴛。", "復轉千步廊，峥嶸望西昆。", "朋簮談笑餘，經史多討論。"]'),
('1c3dcb48-4bd0-4a52-8998-524df71cd822','謁蘇子瞻因寄','孔武仲','宋','宋诗','song-poetry','','[]','華嚴長者貌古奇，紫瞳奕奕雙眉垂。',88,'全唐诗/poet.song.49000.json','["華嚴長者貌古奇，紫瞳奕奕雙眉垂。", "顔如桃花兩侍兒，問其姓名自不知。", "囁嚅欲吐新奇詞，豈亦有虎來護持。", "維摩高卧盡不應，蓬山藏史策馬馳。", "三豪兀坐渾如痴，錯認醍醐是酒巵，誰將此景付畫師。"]'),
('8c0131de-143f-42c1-af67-206da14caad4','五月廿八日雨後','孔武仲','宋','宋诗','song-poetry','','[]','黄昏雨一雨，稍覺襟袖凉。',156,'全唐诗/poet.song.49000.json','["黄昏雨一雨，稍覺襟袖凉。", "中宵如河決，浩渺不可當。", "浮雲合四溟，無復窺神光。", "門巷失舊徑，北鄰有頽墻。", "恐地俱蟄龍，難安三尺床。", "閽人亟來告，客土壞溝防。", "坐此不疏達，漸漬室與堂。", "我迷忽復悟，豈暇立徬徨。", "荷鍤裒衆力，畚土逾百筐。", "坎窗快不隔，飛流復湯湯。", "中庭燥如舊，漠漠蘭芷香。", "廼知天下事，壅塞成疽瘡。", "决水復不難，吾有扁鵲方。"]'),
('0efbf916-275c-4df4-acd3-f3615723d9a0','籍田觀荷花','孔武仲','宋','宋诗','song-poetry','','[]','緑水滿平郊，江蓮輝幽渚。',48,'全唐诗/poet.song.49000.json','["緑水滿平郊，江蓮輝幽渚。", "偷香一霎風，逞響無邊雨。", "波間的皪笑，竹裏嬋娟舞。", "異境看仙姿，蕭然失煩暑。"]'),
('9dc7f697-306e-4ff4-883d-6b3625737363','送蘇邁尉酸棗','孔武仲','宋','宋诗','song-poetry','','[]','酷暑日逾退，凉風生早秋。',72,'全唐诗/poet.song.49000.json','["酷暑日逾退，凉風生早秋。", "翩翩蘇公子，一官不遠遊。", "仕養兩得意，人生復何求。", "駿馬如飛星，錦带垂吴鈎。", "到邑嚚訟少，官閑吏兵休。", "還當有佳吟，吟到黄河頭。"]'),
('ca6cfd83-81c3-4109-a2ad-ed1ca0bc0faf','嚴子陵釣臺和友人韻','董循','宋','宋诗','song-poetry','','[]','子陵垂釣逐江流，相與登臺作共遊。',64,'全唐诗/poet.song.5000.json','["子陵垂釣逐江流，相與登臺作共遊。", "紅葉黄花三峽雨，高風亮節一天秋。", "四圍黛色迷青眼，滿幅煙雲鎖綠洲。", "誰到嚴灘同玩賞，往來七里聽漁謳。"]'),
('6d1fd47a-0954-404e-9089-00ec63c3e446','睢陽五老圖詩','畢世長','宋','宋诗','song-poetry','','[]','非才最忝預高年，分務由來近挂冠。',64,'全唐诗/poet.song.5000.json','["非才最忝預高年，分務由來近挂冠。", "敢造鉅賢論軌躅，幸依都府得盤桓。", "篇章捧和慚風雅，眷待優隆荷歲寒。", "儻許衰容參盛列，願憑繪事永傳看。"]'),
('c8056fda-d0fb-40f5-90ef-c766ec4fa050','禮佛迴向偈','釋遵式','宋','宋诗','song-poetry','','[]','見聞獲安隠，莫不信向心。',120,'全唐诗/poet.song.5000.json','["見聞獲安隠，莫不信向心。", "是故我歸依，願普如世尊。", "甚深浄戒聚，功德難思議。", "受者獲安隠，福慧日夜生。", "諸佛常護念，萬行漸滿盈。", "六度四等意，普度諸羣盲。", "手足初莫犯，節言慎所行。", "常樂在定意，是真優婆塞。", "質直離諂曲，常與賢聖俱。", "愛衆猶養己，是名真菩薩。"]'),
('251a706d-5696-4426-9d02-46a66a1d805f','每日念佛懺悔發願文','釋遵式','宋','宋诗','song-poetry','','[]','我今稱念阿彌陀，真實功德佛名號。',160,'全唐诗/poet.song.5000.json','["我今稱念阿彌陀，真實功德佛名號。", "惟願慈悲垂攝受，證知懺悔及所願。", "我昔所造諸惡業，皆由無始貪嗔癡。", "從身□意之所生，一切我今皆懺悔。", "願我臨欲命終時，盡除一切諸障礙。", "面見彼佛阿彌陀，即得往生安樂剎。", "彼佛衆會咸清浄，我時於勝蓮華生。", "親見如來無量光，現前授我菩提記。", "蒙彼如來授記已，化身無數百俱胝。", "知力廣大徧十方，普利一切衆生界。"]'),
('75453e32-abdc-455e-a1c6-93b1f995a57d','放生慈濟法門','釋遵式','宋','宋诗','song-poetry','','[]','我比丘某甲，今爲傍生類。',282,'全唐诗/poet.song.5000.json','["我比丘某甲，今爲傍生類。", "發佛大慈悲，懺彼六情根。", "無始業障海，眼根著諸色。", "耳界聞亂聲，鼻染一切香。", "舌生諸惡刺，身如機關主。", "六賊游戲中，心想如猿猴。", "無有暫停時。", "如此等六法，名爲六情根。", "一切業因緣，皆從妄想起。", "妄想如幻焰，亦若空中花。", "迷倒不覺知，爲諸惑業縛。", "永墮三途界，沒在衆苦中。", "不聞正法音，何曾知懺悔。", "惟願十方佛，菩薩衆大師。", "慈力與冥加，令其知發露。", "無始一切惡，今日悉消除。", "畢故不造新，常當修梵行。", "未脫傍生難，餘命願安樂。", "筌網及虞羅，願不相值遇。", "飲啄隨時足，饑渴永不逢。", "相見起慈心，願不相吞噉。", "當承三寶力，誓脫衆塵勞。", "畢此苦類身，願生諸佛國。", "彌陀廣慈願，不捨一切生。"]'),
('3d6c400b-02a4-4d26-90df-517b015a02f3','誡酒肉慈慧法門','釋遵式','宋','宋诗','song-poetry','','[]','南無佛法僧，大慈三寶海。',288,'全唐诗/poet.song.5000.json','["南無佛法僧，大慈三寶海。", "我今欲依教，普勸諸衆生。", "莫殺莫食肉，同藴仁慈行。", "無病保長齡，未來成佛道。", "諸佛大菩薩，常爲救衆生。", "捨頭目身命，不計河沙數。", "代鴿棄王身，全螘委龍命。", "流水濟枯魚，薩埵充饑虎。", "歷劫徧行慈，慈善力成就。", "佛無一切心，唯有慈心在。", "若有行慈者，不殺不食肉。", "仰願佛威神，世世常加護。", "殺生佛所說，即殺自父母。", "亦殺自妻女，兄弟及姊妹。", "一切男女攝，皆曾爲父母。", "生生所受胎，從之稟遺體。", "受一畜生形，骨血如山海。", "一一類中身，生生不可計。", "輪迴六道間，展轉爲親屬。", "故食諸衆生，名食父母肉。", "又觀一切身，悉是我本體。", "自肉及他肉，其實是一肉。", "如舍前後住，亦名爲我舍。", "當知食肉人，即食自身肉。"]'),
('a2378e6e-8dda-4771-8c57-a13da6bf452d','戒五辛頌','釋遵式','宋','宋诗','song-poetry','','[]','五辛佛所說，障道定無疑。',120,'全唐诗/poet.song.5000.json','["五辛佛所說，障道定無疑。", "梵網招輕垢，楞伽損大慈。", "人天猶尚失，浄土固難期。", "生啖增瞋念，熟食發淫思。", "講經十二部，天仙悉捨離。", "善神不守護，惡鬼得便宜。", "薜荔唼脣吻，魔羅現佛儀。", "福德因消滅，業障更彌滋。", "地獄銅兼鐵，輪迴網復羈。", "無端耽草味，殃禍大堪悲。"]'),
('eb6c3889-33bd-4b15-a81a-86ab2b1abac2','改祭修齋决疑頌 第一疑：有鬼無鬼，能禍能福耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','鬼神隨處有，諂誑世間人。',24,'全唐诗/poet.song.5000.json','["鬼神隨處有，諂誑世間人。", "祭鬼都無福，空增殺業因。"]'),
('193a0a1b-c2a2-47b6-82a3-e5b52a64128d','改祭修齋决疑頌 第二疑：現見世人病患，祭祀獲安，何言無福耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','正信天龍護，邪神豈奈何。',24,'全唐诗/poet.song.5000.json','["正信天龍護，邪神豈奈何。", "但知常念佛，災怪自消磨。"]'),
('621fa665-cfc1-4cd0-a6a5-52d240bcd97f','改祭修齋决疑頌 第三疑：家眷死後祭祀，得食不得食耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','人死隨前業，升沉六道殊。',24,'全唐诗/poet.song.5000.json','["人死隨前業，升沉六道殊。", "如何純祭祀，須道世人愚。"]'),
('c5dc1e88-72be-4950-9723-bb9ac81b1cf8','改祭修齋决疑頌 圓丘方澤，上下神明，國之常典。云何勸令斷祭，奈太傷國風乎？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','殺牛慚禴祭，黍稷本非馨。',24,'全唐诗/poet.song.5000.json','["殺牛慚禴祭，黍稷本非馨。", "齋誦真明德，何勞執禮經。"]'),
('b41a2d0c-2e0a-4829-a5dc-9e12d1acd29c','改祭修齋决疑頌 第五疑：祭祀之家，及彼師巫，得何罪報耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','殺他還自殺，影響逐形聲。',24,'全唐诗/poet.song.5000.json','["殺他還自殺，影響逐形聲。", "鬼飽都無福，空招墮火坑。"]'),
('a2e3421d-7c67-45a5-ad7f-7299c7dc7e6e','改祭修齋决疑頌 第六疑：今若改祭，自古已來，還有報驗耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','迴邪生正信，臭草出栴檀。',24,'全唐诗/poet.song.5000.json','["迴邪生正信，臭草出栴檀。", "逢難須堅固，安居志好攀。"]'),
('6df38dd7-5c2c-4099-bcff-ddd745881fa3','改祭修齋决疑頌 第七疑：改祭之後，忽遇災禍，既已捨神，求誰救護耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','專持菩薩號，八部護君身。',24,'全唐诗/poet.song.5000.json','["專持菩薩號，八部護君身。", "急難隨聲應，唯除不信人。"]'),
('ea90b877-3276-43bc-9c94-22c44502c6d4','改祭修齋决疑頌 第八疑：自來殺生祭祀，所有罪業作何功德而得消滅耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','法寶真良藥，衆生自不嘗。',24,'全唐诗/poet.song.5000.json','["法寶真良藥，衆生自不嘗。", "書持并供養，世世上天堂。"]'),
('a5c6ba74-37ea-47a0-9fc7-328127213af1','改祭修齋决疑頌 第九疑：凡修齋福，并讀誦經典，當迴向家宅何等神明，凡有幾位耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','作福常迴施，天龍善鬼神。',24,'全唐诗/poet.song.5000.json','["作福常迴施，天龍善鬼神。", "威光常覆護，使汝免災迍。"]'),
('687d27df-2a9e-4460-ac25-577dcf2d111d','改祭修齋决疑頌 第十疑：既不許祭祀，或家眷死亡墮在鬼趣，云何施其飲食耶？頌曰：','釋遵式','宋','宋诗','song-poetry','','[]','鬼道常饑渴，當生憐愍心。',24,'全唐诗/poet.song.5000.json','["鬼道常饑渴，當生憐愍心。", "能蠲口中食，佛賛福田深。"]'),
('68bd812e-7677-4a1b-8097-29d1656b6141','地獄界偈','釋遵式','宋','宋诗','song-poetry','','[]','三界無別法，一切唯心造。',72,'全唐诗/poet.song.5000.json','["三界無別法，一切唯心造。", "是故於日夜，當自勤觀心。", "心欲起諸惡，速滅如救然。", "心欲起諸善，愛護如珍寶。", "行惡雖少頃，未來受苦長。", "爲善向菩提，永證常樂果。"]'),
('168da845-4cea-4a25-a2ed-3fdef6996291','上王丞相十界心圖頌','釋遵式','宋','宋诗','song-poetry','','[]','無象無名杳莫尋，强將名象測幽深。',64,'全唐诗/poet.song.5000.json','["無象無名杳莫尋，强將名象測幽深。", "憑斯會解還相背，捨此他求轉自沉。", "鷲嶺殷勤親付囑，龍門愷悌好知音。", "仍聞挂在高堂上，誤殺來人錯認心。"]'),
('21d79b3a-387a-457c-b6ad-4400686e37ae','大悲觀音栴檀像','釋遵式','宋','宋诗','song-poetry','','[]','南無十方三世佛，南無本師大牟尼。',384,'全唐诗/poet.song.5000.json','["南無十方三世佛，南無本師大牟尼。", "南無西方安樂剎，阿彌陀佛十力尊。", "南無過去無數劫，彼世世燈觀世音。", "諸佛慧眼第一凈，以不二相觀三界。", "如實見我歸命禮，成就大願護衆生。", "南無一切法寶海，無邊無盡解脫門。", "南無總持功德藏，三世十方諸佛印。", "消除三障無諸惡，五眼具足成菩提。", "未來際劫誓修行，普使衆生獲無畏。", "南無文殊普賢尊，一切智行圓滿海。", "金剛藏及金剛手，得大勢等諸大士。", "聲聞辟支賢聖衆，願以慈眼普瞻視。", "我今南無讚三寶，爲欲深遊大悲海。", "南無大悲救厄者，昔曾值佛觀世音。", "入彼如來所入門，故佛授與同名號。", "從聞解脫六塵縛，如聲度垣不能礙。", "由斯徧入微塵國，普現微塵自在身。", "一一身宣總持句，施與衆生無畏法。", "是故娑婆世界中，皆號爲施無畏者。", "我昔經中值密言，能除三障名消伏。", "佛稱功德難思議，故我常持不敢忘。", "誓向當來大劫海，徧將此句救諸苦。", "爲求大士加持力，故造栴檀持呪形。", "爍迦羅首金色容，具足七數端嚴相。"]'),
('1bf591cf-2dee-4ab7-a78a-2d1d269badb8','依修多羅立往生正信偈','釋遵式','宋','宋诗','song-poetry','','[]','稽首西方安樂剎，彌陀世主大慈尊。',384,'全唐诗/poet.song.5000.json','["稽首西方安樂剎，彌陀世主大慈尊。", "我依種種修多羅，成就往生决定信。", "住大乘者清凈心，十念念彼無量壽。", "臨終夢佛定往生，大寶積經如是說。", "五逆地獄衆火現，值善知識發猛心。", "十念稱佛即往生，十六觀經如是說。", "若有歡喜信樂心，下至十念即往生。", "若不爾者不成佛，四十八願如是說。", "諸有聞名生至心，一念迴向即往生。", "唯除五逆謗正法，無量壽經如是說。", "臨終不能觀及念，但作生意知有佛。", "此人氣絕即往生，大法鼓經如是說。", "一日一夜懸繒蓋，專念往生心不斷。", "卧中夢佛即往生，無量壽經如是說。", "晝夜一日稱佛名，殷勤精進不斷絕。", "展轉相勸同往生，大悲經中如是說。", "一日二日若七日，執持名號心不亂。", "佛現其前即往生，阿彌陀經如是說。", "若人聞彼阿彌陀，一日二日若過等。", "繫念現前即往生，般舟經中如是說。", "十日十夜六時中，五體禮佛念不斷。", "現見彼佛即往生，鼓音王經如是說。", "十日十夜持齋戒，懸繒幡蓋然香燈。", "繫念不斷得往生，無量壽經如是說。"]'),
('ffcb1022-e29a-4556-a742-b17a96aae58f','釋大方廣佛華嚴經賢首菩薩讚佛偈  其一','釋遵式','宋','宋诗','song-poetry','','[]','又放光明名見佛，此光覺悟將終者。',32,'全唐诗/poet.song.5000.json','["又放光明名見佛，此光覺悟將終者。", "令隨悟念見如來，命終得生其凈土。"]'),
('5cd2ee26-81f1-416a-9c96-ed1e7d1f505f','釋大方廣佛華嚴經賢首菩薩讚佛偈  其二','釋遵式','宋','宋诗','song-poetry','','[]','見有臨終勸念佛，及示尊像令瞻敬。',32,'全唐诗/poet.song.5000.json','["見有臨終勸念佛，及示尊像令瞻敬。", "俾於佛所深歸仰，是故得成此光明。"]'),
('29453c2f-a300-44cf-860e-d7a9957de05c','十六觀經頌','釋遵式','宋','宋诗','song-poetry','','[]','韋提重禮請能仁，願說西方凈報因。',32,'全唐诗/poet.song.5000.json','["韋提重禮請能仁，願說西方凈報因。", "十六觀兼三凈業，修之即得往生身。"]'),
('20222416-7cf2-45bc-bbd8-acdf30d849db','十六觀經頌 日觀第一','釋遵式','宋','宋诗','song-poetry','','[]','正坐面西想日輪，見日欲沒如懸鼓。',32,'全唐诗/poet.song.5000.json','["正坐面西想日輪，見日欲沒如懸鼓。", "見已閉目開目間，皆令明了心堅住。"]'),
('7f18c418-0a7a-4611-b677-fd6225a3b35f','十六觀經頌 水觀第二','釋遵式','宋','宋诗','song-poetry','','[]','次作水想見西方，一切皆爲凈土水。',32,'全唐诗/poet.song.5000.json','["次作水想見西方，一切皆爲凈土水。", "既見水已想成冰，皎然映徹琉璃地。"]'),
('328df7a2-5ee7-4784-8530-4bf9c5f35418','十六觀經頌 地觀第三','釋遵式','宋','宋诗','song-poetry','','[]','琉璃寶地正觀時，諦了分明極樂國。',32,'全唐诗/poet.song.5000.json','["琉璃寶地正觀時，諦了分明極樂國。", "八種清風鼓樂音，苦空無我無常曲。"]'),
('160c6c0b-f4df-46c1-9803-7616d246a123','十六觀經頌 樹觀第四','釋遵式','宋','宋诗','song-poetry','','[]','四觀寶樹七重行，寶葉華敷妙宮殿。',32,'全唐诗/poet.song.5000.json','["四觀寶樹七重行，寶葉華敷妙宮殿。", "寶幢幡蓋影重重，十方佛國於中現。"]'),
('7866b44f-024b-4474-9fc2-413c4c599aa0','十六觀經頌 池觀第五','釋遵式','宋','宋诗','song-poetry','','[]','五想凈土七寶池，池中水有八功德。',32,'全唐诗/poet.song.5000.json','["五想凈土七寶池，池中水有八功德。", "宣流念佛法僧名，妙寶蓮華千萬億。"]'),
('01ee3819-967f-431e-ab68-242ed09e92fa','十六觀經頌 總觀第六','釋遵式','宋','宋诗','song-poetry','','[]','衆寶國土寶樓閣，寶樹更兼池間錯。',32,'全唐诗/poet.song.5000.json','["衆寶國土寶樓閣，寶樹更兼池間錯。", "此箇總觀若成時，名爲粗見彼極樂。"]'),
('dc4a682a-7645-42b8-85bb-d06d9553a8e4','十六觀經頌 華座觀第七','釋遵式','宋','宋诗','song-poetry','','[]','七想蓮華妙臺座，廣大彌陀願力成。',32,'全唐诗/poet.song.5000.json','["七想蓮華妙臺座，廣大彌陀願力成。", "作此想時心不亂，定當極樂國中生。"]'),
('e105ecf5-291b-4c33-a460-f9c296fc4643','十六觀經頌 佛菩薩像觀第八','釋遵式','宋','宋诗','song-poetry','','[]','諸佛如來法界身，徧入衆生一切想。',32,'全唐诗/poet.song.5000.json','["諸佛如來法界身，徧入衆生一切想。", "智者當觀此想心，是心即佛菩薩像。"]'),
('c1676012-c09c-4b75-bc07-fdbe2a9c4a36','十六觀經頌 無量壽佛身觀第九','釋遵式','宋','宋诗','song-poetry','','[]','無量壽佛金色身，光明普照羣生類。',32,'全唐诗/poet.song.5000.json','["無量壽佛金色身，光明普照羣生類。", "勤修智者繫心觀，諸佛現前同授記。"]'),
('fbb7312e-9c75-4ad3-9583-2a88837c4412','十六觀經頌 觀音觀第十','釋遵式','宋','宋诗','song-poetry','','[]','觀音菩薩紫金身，眉間毫相七寶色。',32,'全唐诗/poet.song.5000.json','["觀音菩薩紫金身，眉間毫相七寶色。", "流出光明滿十方，光中化佛無數億。"]'),
('4786b7db-e0e2-447f-a009-fa59e23e5540','十六觀經頌 勢至觀第十一','釋遵式','宋','宋诗','song-poetry','','[]','次觀勢至菩薩身，量等觀音無有異。',32,'全唐诗/poet.song.5000.json','["次觀勢至菩薩身，量等觀音無有異。", "但於肉髻寶缾中，盛衆光明現佛事。"]'),
('a46ebdd6-25c8-498b-8624-71efa5a316ce','十六觀經頌 普往生觀第十二','釋遵式','宋','宋诗','song-poetry','','[]','端想身生極樂界，蓮華合閉身居內。',32,'全唐诗/poet.song.5000.json','["端想身生極樂界，蓮華合閉身居內。", "華開見佛滿虛空，水鳥樹林宣法偈。"]'),
('a37640c1-1bc4-4e8a-a658-96342a1e1a85','十六觀經頌 雜往生觀第十三','釋遵式','宋','宋诗','song-poetry','','[]','重想彌陀二菩薩，神通變現事如前。',32,'全唐诗/poet.song.5000.json','["重想彌陀二菩薩，神通變現事如前。", "雜沓觀成無量福，定生安養奉金僊。"]'),
('9ab30be4-4a69-47ae-887b-1cf92f33f764','十六觀經頌 上品上生觀第十四','釋遵式','宋','宋诗','song-poetry','','[]','慈心不殺持衆戒，讀誦大乘方等經。',32,'全唐诗/poet.song.5000.json','["慈心不殺持衆戒，讀誦大乘方等經。", "修行六念迴向願，臨終化佛悉來迎。"]'),
('d2a71b76-a1c5-4a29-bf12-872654fa4904','十六觀經頌 上品中生','釋遵式','宋','宋诗','song-poetry','','[]','不必受持方等經，解第一義明因果。',32,'全唐诗/poet.song.5000.json','["不必受持方等經，解第一義明因果。", "紫金臺現命終時，自見身於臺上坐。"]'),
('3f8524ac-7336-4ad4-b7a2-9810f0bb4006','十六觀經頌 上品下生','釋遵式','宋','宋诗','song-poetry','','[]','深信因果奉大乘，但發無上菩提意。',32,'全唐诗/poet.song.5000.json','["深信因果奉大乘，但發無上菩提意。", "以此功德迴願生，生已當住歡喜地。"]'),
('404148cb-932f-4bd1-b6de-34a37d88fc15','十六觀經頌 中品上生觀第十五','釋遵式','宋','宋诗','song-poetry','','[]','受持五戒八戒齋，修行諸戒迴向願。',32,'全唐诗/poet.song.5000.json','["受持五戒八戒齋，修行諸戒迴向願。", "命終生彼聞法音，應時即得阿羅漢。"]'),
('531c4e68-067d-4a4c-94a7-1d35ff35203b','十六觀經頌 中品中生','釋遵式','宋','宋诗','song-poetry','','[]','若人至心一日夜，持戒持齋無破缺。',32,'全唐诗/poet.song.5000.json','["若人至心一日夜，持戒持齋無破缺。", "以此功德迴願生，七日華敷成記莂。"]'),
('53e3879f-15e2-4c6e-b1b7-a03ad48880ed','十六觀經頌 中品下生','釋遵式','宋','宋诗','song-poetry','','[]','孝養父母行仁義，臨終復遇善知識。',32,'全唐诗/poet.song.5000.json','["孝養父母行仁義，臨終復遇善知識。", "廣說彌陀大願因，屈伸臂頃生彼國。"]'),
('55f7734f-7531-4f81-a030-479030f8e988','十六觀經頌 下品上生觀第十六','釋遵式','宋','宋诗','song-poetry','','[]','若人雖不謗尊經，造衆惡業無慚愧。',32,'全唐诗/poet.song.5000.json','["若人雖不謗尊經，造衆惡業無慚愧。", "臨終遇勸念彌陀，生彼十劫得初地。"]'),
('4359e024-f973-4d46-bc35-7796ac555ae2','十六觀經頌 下品中生','釋遵式','宋','宋诗','song-poetry','','[]','若有衆生犯衆戒，盜取僧祇三寶物。',32,'全唐诗/poet.song.5000.json','["若有衆生犯衆戒，盜取僧祇三寶物。", "臨終遇勸念彌陀，一念頃間生彼國。"]'),
('5f610a32-fa4b-4c8c-84b0-30799405868d','十六觀經頌 下品下生','釋遵式','宋','宋诗','song-poetry','','[]','有作五逆十惡業，應墮地獄受諸苦。',32,'全唐诗/poet.song.5000.json','["有作五逆十惡業，應墮地獄受諸苦。", "臨終遇勸念彌陀，决定超生於彼土。"]'),
('85239586-49ed-4151-a0d5-70bf44ec621f','念佛三昧詩  其一','釋遵式','宋','宋诗','song-poetry','','[]','萬感外形骸，儼然虛堂寂。',48,'全唐诗/poet.song.5000.json','["萬感外形骸，儼然虛堂寂。", "明毫冠羣彩，幽神資始績。", "妙象非夙預，俗覽豈良覿。", "析之會入微，清玩心無懌。"]'),
('a50d387b-4b7f-408e-b875-9bb61e33a21a','念佛三昧詩  其二','釋遵式','宋','宋诗','song-poetry','','[]','金肌昧真見，八音愚正聞。',48,'全唐诗/poet.song.5000.json','["金肌昧真見，八音愚正聞。", "玄空了無託，至涉寧有勳。", "森羅會都寂，長空銷積氛。", "良哉此達觀，局士安與云。"]'),
('75dbca7b-3d53-44ed-85b2-2dec96b21b3b','念佛三昧詩  其三','釋遵式','宋','宋诗','song-poetry','','[]','融抱迴曲照，熙如鑑中象。',48,'全唐诗/poet.song.5000.json','["融抱迴曲照，熙如鑑中象。", "諦覽無遺心，虛求非滯想。", "追夢忘始終，通幽宛如往。", "藉此會神姿，逍遥期西賞。"]'),
('005209cf-8042-49c2-836d-828e9e8e198d','念佛三昧詩  其四','釋遵式','宋','宋诗','song-poetry','','[]','鑑極玄想孤，動靜如爲區。',48,'全唐诗/poet.song.5000.json','["鑑極玄想孤，動靜如爲區。", "大象詎形儀，大方誰廉隅。", "正賞不隠括，妙踐無迴迂。", "心澄徧知海，粲粲黄金軀。"]'),
('9cd64c53-44dd-46e3-be43-f368f3f2a1d5','爲檀越寫彌陀經正信偈發願文','釋遵式','宋','宋诗','song-poetry','','[]','稽首十方佛，彌陀聖中尊。',282,'全唐诗/poet.song.5000.json','["稽首十方佛，彌陀聖中尊。", "方等修多羅，一切法寶藏。", "觀音及勢至，大地菩薩僧。", "我以誠信心，刻板并印造。", "阿彌陀經卷，及以正信偈。", "旋造各一萬，施四衆受持。", "偈以發信心，經以資讀誦。", "若有每日中，至少誦三卷。", "年誦千八十，十年萬八百。", "況復多誦者，及歷多年數。", "如是積功德，自然生佛前。", "我此萬卷經，隨所流布處。", "極少得一人，誦持生凈土。", "我願承此力，决定生彼國。", "況復於多人，人亡經復在。", "展轉相傳授，是名無盡燈。", "燈燈相照耀，破生死長夜。", "顯出佛菩提，究竟悉同生。", "常寂光凈土，持此清凈福。", "迴向奉君親，我國聖帝王。", "及聖后聖位，仁壽各萬年。", "覆育羣氓類，我父母眷屬。", "怨親非怨親，咸承勝善根，同生安養國。"]'),
('4bc788b5-64ea-4e95-b180-a392a22811b7','遊天台觀','釋遵式','宋','宋诗','song-poetry','','[]','古觀春山下，尋幽似有期。',48,'全唐诗/poet.song.5000.json','["古觀春山下，尋幽似有期。", "瀑清冥坐久，峰好獨歸遲。", "客嘯巢禽識，仙蹤藥叟知。", "我來無別趣，禪性盡相宜。"]'),
('f4e6be88-ef71-4346-9cb8-14c3ac1fd570','寄題丹丘梵才上人山居','釋遵式','宋','宋诗','song-poetry','','[]','禪家真隠處，翠谷倚城隍。',48,'全唐诗/poet.song.5000.json','["禪家真隠處，翠谷倚城隍。", "海近雲歸早，山孤鳥去長。", "石當泉脈潤，風度柏枝香。", "此地容吾否，中霄去意狂。"]'),
('7c2799d6-6872-43ec-a777-608e718880da','寄丹丘鴻上人不出寺','釋遵式','宋','宋诗','song-poetry','','[]','小固山前一道人，不言生死不言真。',64,'全唐诗/poet.song.5000.json','["小固山前一道人，不言生死不言真。", "茅堂靜有朝端客，草履爛無門外塵。", "銀漏滴殘猶在定，石花開盡始知春。", "相思未得相尋去，空恨江頭多病身。"]'),
('d33b0d3e-9971-4773-bb53-fe3d0653a37c','酬伉上人','釋遵式','宋','宋诗','song-poetry','','[]','鳥外清閒極，誰能更似君。',48,'全唐诗/poet.song.5000.json','["鳥外清閒極，誰能更似君。", "山光晴後見，瀑響夜深聞。", "拾句書幽石，收茶踏亂雲。", "江頭待無事，終學棄人羣。"]'),
('f4d4b637-df99-41aa-9fa0-abaea9ff3f9e','贈智倫弟','釋遵式','宋','宋诗','song-poetry','','[]','溪竹擁疏簾，溪雲冷不厭。',48,'全唐诗/poet.song.5000.json','["溪竹擁疏簾，溪雲冷不厭。", "千巖唯虎伴，一講許詩兼。", "煮茗敲冰柱，看經就雪簷。", "有時開靜戶，寒日下峰尖。"]'),
('e27e4c87-9071-4502-8b20-dd22fa370f26','隋觀法師塔','釋遵式','宋','宋诗','song-poetry','','[]','五六百年內，金軀亦化塵。',48,'全唐诗/poet.song.5000.json','["五六百年內，金軀亦化塵。", "方知新塚上，盡是古人身。", "白髮爭名急，青山送骨頻。", "除師靈塔外，一一好沾巾。"]'),
('9c68b2ea-56b1-4e72-9673-640cf18f5148','送苗推官','釋遵式','宋','宋诗','song-poetry','','[]','官滿載琴書，乘春入上都。',48,'全唐诗/poet.song.5000.json','["官滿載琴書，乘春入上都。", "煙波離遠岸，桃李發中途。", "俸薄尊常淺，詩清道太孤。", "登朝無恨晚，未有白髭鬚。"]'),
('d2c7311c-e2f3-4583-bbd6-a7195c5afc99','隠者','釋遵式','宋','宋诗','song-poetry','','[]','一徑千峰裏，何人更往還。',48,'全唐诗/poet.song.5000.json','["一徑千峰裏，何人更往還。", "無爲無事者，白首白雲閒。", "釀酒擔寒瀑，尋猿過別山。", "豈知名利客，鞭馬向秦關。"]'),
('414856e0-4ff4-41a4-962c-2bbf2ac38541','寄劉處士','釋遵式','宋','宋诗','song-poetry','','[]','度月阻相尋，應爲苦雨吟。',48,'全唐诗/poet.song.5000.json','["度月阻相尋，應爲苦雨吟。", "井渾茶味失，地潤屐痕深。", "鳥背長湖色，門閒古樹陰。", "想君慵更甚，華髮晝方簪。"]'),
('33eb6b5d-b89a-4444-be00-7142bfa0c834','寄悟和尚','釋遵式','宋','宋诗','song-poetry','','[]','無累無機祇任緣，一齋長掩古松邊。',64,'全唐诗/poet.song.5000.json','["無累無機祇任緣，一齋長掩古松邊。", "寒垂白髮過深雪，不下青林知幾年。", "木葉當薪燒更暖，薑苗爲屨著難穿。", "竟何人問東林社，時引清流灌碧蓮。"]'),
('b5a20e16-1db6-4488-a844-367ea7e85d24','酬蘇屯田西湖韻','釋遵式','宋','宋诗','song-poetry','','["\u897f\u6e56"]','雨餘殘景照漁家，漁子鳴榔徹郡衙。',32,'全唐诗/poet.song.5000.json','["雨餘殘景照漁家，漁子鳴榔徹郡衙。", "今夜相呼好垂釣，晚來新雨漲蒹葭。"]'),
('25d61ba5-6d7c-4b24-8592-27d1edb7b0e9','五峰合澗詩 飛來峰','釋遵式','宋','宋诗','song-poetry','','[]','乾坤持中樞，動運非物圖。',72,'全唐诗/poet.song.5000.json','["乾坤持中樞，動運非物圖。", "欝欝彼靈鷲，飄飄如飛鳬。", "層空累怪石，古木生其膚。", "仁虎終安棲，白猿時號呼。", "錢源注鮫室，謝月揚天衢。", "曩喆多遺塵，清風來四隅。"]'),
('fd779651-70c0-4d78-8d21-c8eedcd045eb','五峰合澗詩 蓮華峰','釋遵式','宋','宋诗','song-poetry','','["\u534e\u5c71"]','青瑛麗芙蕖，造化工且奇。',72,'全唐诗/poet.song.5000.json','["青瑛麗芙蕖，造化工且奇。", "輝彩向星河，結根在天池。", "臨飈無馨香，禦雨不離披。", "朝靄發翠華，暮雲生碧姿。", "鼎湖幾榮落，華嶽何盛衰。", "獨爾謝羣芳，自將天地期。"]'),
('4ea8d403-a729-41c0-ad95-a76f91b886e2','五峰合澗詩 稽留峰','釋遵式','宋','宋诗','song-poetry','','[]','武林神仙宅，代有隠者遊。',72,'全唐诗/poet.song.5000.json','["武林神仙宅，代有隠者遊。", "谷靜雲性閑，源長水涵幽。", "吾居餘十年，自足忘百憂。", "豈嚼不死草，夙陪無生儔。", "道慚情未損，身與世爲讎。", "安得會昔人，竹枝歌中秋。"]'),
('b14189da-6709-4397-86fe-d2134480559f','五峰合澗詩 月桂峰','釋遵式','宋','宋诗','song-poetry','','[]','嫦娥戲仙桂，擲子落人寰。',72,'全唐诗/poet.song.5000.json','["嫦娥戲仙桂，擲子落人寰。", "秀穎發矯林，芳馨騰遠山。", "兔邊甘百上，鳥外誰一攀。", "月裏催人老，雲根伴余閑。", "餘霞照海甸，高翠暖湖關。", "康樂不在哉，猿來空庭間。"]'),
('f2f04ccc-50f0-4551-baae-dcf2c1d61fb6','五峰合澗詩 合澗','釋遵式','宋','宋诗','song-poetry','','[]','靈峰天竺寺，水向南北流。',72,'全唐诗/poet.song.5000.json','["靈峰天竺寺，水向南北流。", "源遠無竭時，石渠平且修。", "潭潔照臺館，岸滋蔚松楸。", "晚霽起長虹，夜寒吟潛虬。", "余居山水中，炎夏長如秋。", "飛梁會一瀉，清響出林邱。"]'),
('5dd097cb-b575-4a74-8cab-50e5fb13691a','五峰合澗詩 白猿峰','釋遵式','宋','宋诗','song-poetry','','[]','人死猿亦亡，碧峰空崔嵬。',72,'全唐诗/poet.song.5000.json','["人死猿亦亡，碧峰空崔嵬。", "六龍馭圓景，巨壑流紅埃。", "今亦看誠古，後還思悲哀。", "茲山俯南澗，水潔影如頹。", "春篠生嫩筠，秋蘭變枯荄。", "方新林下寺，吟此心悠哉。"]'),
('5b34d494-1d3c-4f4f-bb7f-6371f9312b6e','句  其一','釋遵式','宋','宋诗','song-poetry','','[]','真空是選場，大覺爲官位。',12,'全唐诗/poet.song.5000.json','["真空是選場，大覺爲官位。"]'),
('a428c8e3-9ea9-45c7-b434-5ac974722e12','句  其二','釋遵式','宋','宋诗','song-poetry','','[]','翔空迹自絕，不在青青山。',12,'全唐诗/poet.song.5000.json','["翔空迹自絕，不在青青山。"]'),
('b59fe43c-a5c0-4ee3-86b9-59a392b0f1b6','句  其三','釋遵式','宋','宋诗','song-poetry','','[]','梅有和羹實，龍無爲雨心。',12,'全唐诗/poet.song.5000.json','["梅有和羹實，龍無爲雨心。"]'),
('abf219d2-d3f0-4f7f-af21-cc7cee50d299','句  其四','釋遵式','宋','宋诗','song-poetry','','[]','天上無雙月，人間只一僧。',12,'全唐诗/poet.song.5000.json','["天上無雙月，人間只一僧。"]'),
('01798c89-dac9-49f4-9897-34e75a9bad7f','遊龍瑞觀','楊侃','宋','宋诗','song-poetry','','[]','泛舟秋水一湖平，入觀松風數里清。',160,'全唐诗/poet.song.5000.json','["泛舟秋水一湖平，入觀松風數里清。", "丹井有泉仙跡在，玉書藏穴禹功成。", "步虛夜月千峰靜，投簡春霖萬壑盈。", "述記賀知章手筆，題詩元相國聲名。", "結廬野客前谿住，採朮幽人絕頂行。", "杉檜影侵山殿冷，星辰光逼醮壇明。", "降仙臺畔看雲過，射的潭邊聽鶴鳴。", "樵客多聞逢異事，洞天都不遠重城。", "林閒窗戶塵難到，衣上煙嵐暮自生。", "不待照湖天子賜，欲將長往換浮榮。"]'),
('5052c5db-5906-4b1f-b245-94c36d15e80e','遊梅山寺','楊侃','宋','宋诗','song-poetry','','[]','出郭塵路斷，登舟鷲嶺通。',72,'全唐诗/poet.song.5000.json','["出郭塵路斷，登舟鷲嶺通。", "樓臺花嶼上，鐘梵水天中。", "石磴班春蘚，松門韻晚風。", "蓴絲惹輕檝，雲錦散遥空。", "竹逕連茶塢，山亭對藥叢。", "却輸湖畔叟，朝夕訪支公。"]'),
('eaf71bdf-5355-410d-ac99-0657c91a3e0d','送梵才上人歸天台','楊侃','宋','宋诗','song-poetry','','[]','忽憶幽棲地，千峰秀海濆。',48,'全唐诗/poet.song.5000.json','["忽憶幽棲地，千峰秀海濆。", "歸心挂飛瀑，高迹指浮雲。", "塵世宜深遯，詩名畏遠聞。", "猶嗟石橋畔，凡聖路岐分。"]'),
('63f26166-a9f7-4094-b600-4b5d716d4db4','送陳堯叟','楊侃','宋','宋诗','song-poetry','','[]','馬困炎天蠻嶺路，棹衝秋霧瘴江流。',32,'全唐诗/poet.song.5000.json','["馬困炎天蠻嶺路，棹衝秋霧瘴江流。", "辛勤爲國親求病，百越中無不治州。"]'),
('4b1a9806-a5d8-4759-a9a3-a23bcdd244e7','寄呂許公','梅詢','宋','宋诗','song-poetry','','[]','十五年前忝一麾，公餘嘗得預言詩。',64,'全唐诗/poet.song.5000.json','["十五年前忝一麾，公餘嘗得預言詩。", "玉階步武爲霖早，雲路風波得志遲。", "浴鳳池深春蕩蕩，觀魚臺古草離離。", "重來故老休相問，請揭紗籠看舊碑。"]'),
('d06ed004-e3a4-449f-9ac3-eab58ad3fff4','虎丘','梅詢','宋','宋诗','song-poetry','','[]','鳳池初下陟孱顔，虎寺重遊啟舊關。',64,'全唐诗/poet.song.5000.json','["鳳池初下陟孱顔，虎寺重遊啟舊關。", "金鉞傳呼投釣渚，寶天輝映讀書山。", "卧龍昔日曾三顧，遼鶴千年始一還。", "應爲蒼生須再起，草堂蘿幄詎容閑。"]'),
('5d0cb8c4-518a-4023-b0ba-f244449bbc2d','華亭道中','梅詢','宋','宋诗','song-poetry','','[]','晴雲唳鶴幾千里，隔水野梅三四株。',32,'全唐诗/poet.song.5000.json','["晴雲唳鶴幾千里，隔水野梅三四株。", "欲問陸機當日宅，而今何處不荒蕪。"]'),
('6568665c-e6d5-4515-b0c9-6a0bcd5eb98f','吳江太湖笠澤虹橋','梅詢','宋','宋诗','song-poetry','','["\u592a\u6e56"]','岸傍高士陸龜蒙，羌雁曾徵戀釣筒。',32,'全唐诗/poet.song.5000.json','["岸傍高士陸龜蒙，羌雁曾徵戀釣筒。", "船戶平居兩山下，圖經分載幾州中。"]'),
('30a80b6c-2578-4c95-9849-cc84c93ad5ad','桃源','梅詢','宋','宋诗','song-poetry','','[]','武陵風景都然改，谷口桃花鎮長在。',32,'全唐诗/poet.song.5000.json','["武陵風景都然改，谷口桃花鎮長在。", "自從改賜鼎州名，轉覺桃源仙氣靈。"]'),
('852e2100-f3af-433a-b9d6-685635bbc110','送蒙寺丞赴郡','梅詢','宋','宋诗','song-poetry','','[]','郢國當時唱，猶傳白雪真。',24,'全唐诗/poet.song.5000.json','["郢國當時唱，猶傳白雪真。", "問今非昔日，和者幾何人。"]'),
('ff64d2e8-65c2-465d-b534-39f08998ee9e','送楊可及第還鄉','梅詢','宋','宋诗','song-poetry','','[]','君恩兼喜拜維桑，路入家山道更光。',64,'全唐诗/poet.song.5000.json','["君恩兼喜拜維桑，路入家山道更光。", "春色殿前初脫白，秋風隴上見焚黄。", "偏留名紙呼先輩，喜著藍袍到故鄉。", "科第孝思俱已遂，却經劍棧莫凄凉。"]'),
('2e999d2e-9c37-4a08-a1b9-0e0ba0acd75c','吳王墓','梅詢','宋','宋诗','song-poetry','','[]','昔見虎眈眈，今爲佛子巖。',48,'全唐诗/poet.song.5000.json','["昔見虎眈眈，今爲佛子巖。", "雲寒不出寺，劍浄求離潭。", "幽步蘿隨徑，高禪雪閉庵。", "吳都十萬戶，烟瓦亙東南。"]'),
('0a412cf0-799b-4ad2-b71d-a03c39ca1f0d','武林山十詠 飛來峰','梅詢','宋','宋诗','song-poetry','','[]','竺慧指此峰，飛來自靈鷲。',48,'全唐诗/poet.song.5000.json','["竺慧指此峰，飛來自靈鷲。", "猿鳥曾未知，烟嵐尚依舊。", "興亡謾千古，天地豈關紐。", "祇恐舟壑移，他年却西走。"]'),
('cdc62d77-38c8-4f84-b9cd-060b17b0b351','武林山十詠 蓮花峰','梅詢','宋','宋诗','song-poetry','','[]','巨石如芙蕖，天然匪雕飾。',48,'全唐诗/poet.song.5000.json','["巨石如芙蕖，天然匪雕飾。", "盤礴峰頂邊，嬋娟秋江側。", "涉川試誰探，作礪當自惜。", "坐與榮落同，正心未嘗易。"]'),
('c7200402-cced-4f15-ab77-21823f71d206','武林山十詠 呼猿洞','梅詢','宋','宋诗','song-poetry','','[]','古澗飛白猿，寂歷不知處。',48,'全唐诗/poet.song.5000.json','["古澗飛白猿，寂歷不知處。", "風激石上泉，僧疑月中樹。", "微茫認松雪，髣髴橫樵路。", "寫望增爾思，蒼蒼奈烟霧。"]'),
('fa0ddd17-4a21-4ba1-82cb-d84150e0e1b6','武林山十詠 龍泓洞','梅詢','宋','宋诗','song-poetry','','[]','矯矯淵下龍，潛神在靈府。',36,'全唐诗/poet.song.5000.json','["矯矯淵下龍，潛神在靈府。", "雲卧雖有時，泥沙可長處。", "陰崖寒氣腥，峭壁烟痕古。"]'),
('83344153-b96f-449c-aecd-4d780a705596','武林山十詠 煉丹井','梅詢','宋','宋诗','song-poetry','','[]','仙翁道未成，棲神在巖石。',48,'全唐诗/poet.song.5000.json','["仙翁道未成，棲神在巖石。", "酌彼山下泉，窮年煉金液。", "洞陰春始綠，苔甃秋涵碧。", "緬慕不可期，憑欄望鳬舄。"]'),
('60cce2d3-a18a-4d7b-9831-5472d22d36a1','武林山十詠 冷泉亭','梅詢','宋','宋诗','song-poetry','','[]','古竇鳴幽泉，蒼崖結虛宇。',48,'全唐诗/poet.song.5000.json','["古竇鳴幽泉，蒼崖結虛宇。", "六月期客遊，披襟苦徂暑。", "開窗弄清淺，吹鬢疑風雨。", "不見白使君，烟蘿爲誰語。"]'),
('5b6e0ebd-25ca-4d20-8e15-bd2164a44a35','武林山十詠 靈隠寺','梅詢','宋','宋诗','song-poetry','','[]','千峰凌紫烟，中有梵宮闕。',48,'全唐诗/poet.song.5000.json','["千峰凌紫烟，中有梵宮闕。", "靈眄極幽棲，塵心自超越。", "松篁發春靄，桂實墜秋月。", "爭得謝世人，茲焉老華髮。"]'),
('8484bcd3-5611-4adc-85e4-83b498b817d8','武林山十詠 水臺盤','梅詢','宋','宋诗','song-poetry','','[]','鶴髮山中人，疏泉鑿幽石。',48,'全唐诗/poet.song.5000.json','["鶴髮山中人，疏泉鑿幽石。", "如憑青玉案，分遞白雲液。", "泠泠濺雕俎，瑟瑟穿吟席。", "醉坐三伏中，煩襟自消釋。"]'),
('f1697ac7-4375-4789-8ae9-c0c671533d8c','武林山十詠 翻經臺','梅詢','宋','宋诗','song-poetry','','[]','靈運曾此臺，冥心住幽寂。',48,'全唐诗/poet.song.5000.json','["靈運曾此臺，冥心住幽寂。", "重繹葉上書，深藏林中跡。", "遺文傳竹素，野蔓侵苔壁。", "登覽殊未休，蒼山日將夕。"]'),
('01137e9e-9561-4fa6-a4e6-37ab661e629c','武林山十詠 高峰塔','梅詢','宋','宋诗','song-poetry','','[]','高塔列遠岑，亭亭幾百載。',48,'全唐诗/poet.song.5000.json','["高塔列遠岑，亭亭幾百載。", "鈴聲答夜風，輪影落滄海。", "閑雲伴危級，曙日平烟彩。", "欲下生暮愁，千山閉輕靄。"]'),
('1e7fe5db-86c7-4544-b79b-5d1ae0c54c7c','陰陵','梅詢','宋','宋诗','song-poetry','','[]','龍虎相驅逐，干戈事戰爭。',60,'全唐诗/poet.song.5000.json','["龍虎相驅逐，干戈事戰爭。", "千重漢圍合，一夜楚歌聲。", "凄凉七十戰，散漫八千兵。", "失道欺田父，窮途遇灌嬰。", "天亡終不悟，覽古亦傷情。"]'),
('401411f8-0535-425b-a086-eafcb044d26f','疊嶂樓','梅詢','宋','宋诗','song-poetry','','[]','謝公城上謝公樓，百尺闌干挂斗牛。',64,'全唐诗/poet.song.5000.json','["謝公城上謝公樓，百尺闌干挂斗牛。", "碧瓦萬家烟樹密，蒼崖一檻瀑泉流。", "波光灧灧前溪滿，剎影亭亭古寺幽。", "此地近除新太守，綠窗明月爲君留。"]'),
('7ef82d2d-1886-423f-945d-24465b6cf35e','遊齊山寺','梅詢','宋','宋诗','song-poetry','','[]','鳳剎岧嶢挂斷霓，鳬雲渚洳暗窗扉。',64,'全唐诗/poet.song.5000.json','["鳳剎岧嶢挂斷霓，鳬雲渚洳暗窗扉。", "江風曉定釣人出，山月夜高禪客歸。", "牆外蔓藤移過密，院中杉子落來稀。", "老僧獨坐蒲團穩，自枉晴簷補衲衣。"]'),
('9ea4c22d-c2e4-4e82-a9ac-ec741c1b6484','濠州四望亭閒眺','梅詢','宋','宋诗','song-poetry','','[]','南北舟行互擲梭，長淮混混接天河。',64,'全唐诗/poet.song.5000.json','["南北舟行互擲梭，長淮混混接天河。", "石梁景絕虹垂渚，桐柏春深雪作波。", "四望空明無俗翳，數聲欵乃有漁歌。", "誰言此地殊幽僻，自我今來風味多。"]'),
('6d3d43b5-8b14-41b1-8553-4314d03ae7d6','真廟挽辭','梅詢','宋','宋诗','song-poetry','','[]','愁烟暗鼎湖，龍馭入清都。',48,'全唐诗/poet.song.5000.json','["愁烟暗鼎湖，龍馭入清都。", "陟降紅雲陛，陪歆赤帝雲。", "亮陰真聖嗣，遺詔盡嘉謨。", "尚見孤臣泣，蒙知直殿廬。"]'),
('2364e14c-b839-4418-a176-e1af7a0d1872','江樓晚眺','梅詢','宋','宋诗','song-poetry','','[]','潮落蚌耕洲，霞天雨盡收。',48,'全唐诗/poet.song.5000.json','["潮落蚌耕洲，霞天雨盡收。", "月來山寺候，雲駐海間秋。", "野鶩馴舟遶，紅魚逐餌遊。", "欣然乘此興，呼酒醉高樓。"]'),
('7578139d-e3cf-4a0d-a903-9cd0ce9b187f','題竹山寺','梅詢','宋','宋诗','song-poetry','','[]','亂山幽藹隔招提，祇許相邀入剡迷。',32,'全唐诗/poet.song.5000.json','["亂山幽藹隔招提，祇許相邀入剡迷。", "山樹風泉爲誰響，春城一夜到鳴雞。"]'),
('683c4666-72d4-4b79-93e9-db49f919127a','吳興道中','梅詢','宋','宋诗','song-poetry','','[]','野闊多桑柘，湖平溉沃田。',48,'全唐诗/poet.song.5000.json','["野闊多桑柘，湖平溉沃田。", "採蓮花樣女，載酒葉兒船。", "黄犢青山下，垂楊古道邊。", "行行頻北望，戀闕意懸懸。"]'),
('04570ff9-7cab-4e45-9aef-8680161492df','送夏子喬招討西夏','梅詢','宋','宋诗','song-poetry','','[]','丹墀曾獨繹絲綸，御札親題第一人。',64,'全唐诗/poet.song.5000.json','["丹墀曾獨繹絲綸，御札親題第一人。", "鶑喜上遷張筆力，馬諳西討仗威靈。", "亞夫金鼓從天降，韓信旌旗背水陳。", "耆致爾功還奏闕，圖形仍許上麒麟。"]'),
('71fae860-8177-47df-a690-b0b1645a2c58','詩一首','梅詢','宋','宋诗','song-poetry','','[]','楚之襄王問宋玉，玉時對以郢中歌，歌爲白雪陽春曲。',52,'全唐诗/poet.song.5000.json','["楚之襄王問宋玉，玉時對以郢中歌，歌爲白雪陽春曲。", "始唱千人和，再唱百人逐。", "至此和者纔數人，乃知高調難隨俗。"]'),
('f768d299-9035-429a-b5b0-b3856bd9c4b2','句  其一','梅詢','宋','宋诗','song-poetry','','[]','先帝遺弓劍，排雲上紫清。',24,'全唐诗/poet.song.5000.json','["先帝遺弓劍，排雲上紫清。", "同時受顧託，今日見昇平。"]'),
