('66338306-de34-4430-a238-1e8d226f6954','句  其三','李拱','宋','宋诗','song-poetry','','[]','雨後有人耕綠野，月明無犬吠花村。',16,'全唐诗/poet.song.5000.json','["雨後有人耕綠野，月明無犬吠花村。"]'),
('e15b63a6-41b2-4917-a8f3-5305e91a291c','入天章道中','葉參','宋','宋诗','song-poetry','','[]','帝俞荒址創毗耶，茂嶺烟篁占一涯。',64,'全唐诗/poet.song.5000.json','["帝俞荒址創毗耶，茂嶺烟篁占一涯。", "僧入定中觀水月，客來空際辯天花。", "宸章飛動凌奎彩，瀑溜清凉漲井華。", "不省永和年景趣，飫聞虛座演三車。"]'),
('c7a71cc3-a421-4f21-b4c1-2bbfcb8509a8','晚春遊金明抵暮入宜秋門閽兵捧門牌請官位因書一闋','張士遜','宋','宋诗','song-poetry','','[]','閑遊靈沼送春回，關吏何須苦見猜。',32,'全唐诗/poet.song.5000.json','["閑遊靈沼送春回，關吏何須苦見猜。", "八十衰翁無品秩，昔曾三到鳳池來。"]'),
('d6f6ba08-2837-4bd6-bd31-ca558bd541f9','題西庵寺','張士遜','宋','宋诗','song-poetry','','[]','西庵深入西山裏，算得當年少客遊。',64,'全唐诗/poet.song.5000.json','["西庵深入西山裏，算得當年少客遊。", "密密石叢盤小徑，涓涓雲竇瀉寒流。", "松皆有節誰青蓋，僧盡無心也白頭。", "欲刷粉牌書姓字，調卑官冗不堪留。"]'),
('bb463cde-79d5-49f8-a33a-97cc242235fa','題寶蓋巖寺','張士遜','宋','宋诗','song-poetry','','[]','身爲冠冕留，心是雲泉客。',48,'全唐诗/poet.song.5000.json','["身爲冠冕留，心是雲泉客。", "每到雲泉中，便擬忘歸跡。", "況茲寶蓋巖，天造清凉宅。", "稅車官道邊，誰知願言適。"]'),
('b290ee82-8793-4357-bb63-b1fcddd2bcc6','題建寧縣洛陽村寺','張士遜','宋','宋诗','song-poetry','','[]','金谷花時醉幾場，舊游無日不思量。',32,'全唐诗/poet.song.5000.json','["金谷花時醉幾場，舊游無日不思量。", "誰知萬水千山裏，枉被人言過洛陽。"]'),
('2a46b511-fbf0-4a60-b19a-b9f5a9bb6ee3','送高學士知越','張士遜','宋','宋诗','song-poetry','','[]','著撰煩鴻筆，均勞利建侯。',48,'全唐诗/poet.song.5000.json','["著撰煩鴻筆，均勞利建侯。", "僧隨天際棹，郡冠浙東州。", "山影四明接，溪聲萬壑流。", "謝家風月在，公外稱冥搜。"]'),
('0a834b1d-adba-4ad8-aeb5-7f54159a8005','憶越州  其一','張士遜','宋','宋诗','song-poetry','','[]','稽山巖壑深復高，思之誰妙丹青毫。',32,'全唐诗/poet.song.5000.json','["稽山巖壑深復高，思之誰妙丹青毫。", "霜縑若得一千幅，伻圖何必乘蘭舠。"]'),
('230c8212-38e9-42e2-8f36-5e031cfb5e8e','憶越州  其二','張士遜','宋','宋诗','song-poetry','','[]','平湖八百里多奇，君曾縱賞無餘遺。',32,'全唐诗/poet.song.5000.json','["平湖八百里多奇，君曾縱賞無餘遺。", "不知風月誰爲主，夷猶未必如當時。"]'),
('ad3bd15a-fb24-4b2d-89cf-3d518b61a0f5','寄陳文惠','張士遜','宋','宋诗','song-poetry','','[]','赭案當年並命時，蒹葭衰颯倚瓊枝。',32,'全唐诗/poet.song.5000.json','["赭案當年並命時，蒹葭衰颯倚瓊枝。", "皇恩乞與桑榆老，鴻自高冥鳳在池。"]'),
('cab8ee01-28a6-436a-be9f-e7ff523b9d99','答陳文惠','張士遜','宋','宋诗','song-poetry','','[]','八十光陰有二年，烟蘿門戶喜開關。',32,'全唐诗/poet.song.5000.json','["八十光陰有二年，烟蘿門戶喜開關。", "近來無奈山內相，頻寄書來許綴班。"]'),
('990a9eb4-a477-491b-9f49-a156d5daba35','知邵武縣禱雨大有感應任滿作詩紀其事','張士遜','宋','宋诗','song-poetry','','[]','乞靈曾爇一爐烟，言下霶沱救旱田。',32,'全唐诗/poet.song.5000.json','["乞靈曾爇一爐烟，言下霶沱救旱田。", "今日解龜留數字，要教來者更恭虔。"]'),
('2eedab62-d64c-462d-afb0-e00cdfb1f279','送僧歸護國寺','張士遜','宋','宋诗','song-poetry','','[]','一言已了忘筌誼，諸祖休傳壞色衣。',64,'全唐诗/poet.song.5000.json','["一言已了忘筌誼，諸祖休傳壞色衣。", "隻履遠過葱嶺去，片雲高傍石橋歸。", "海宮有請盃慵度，塵劫無涯錫倦飛。", "元帥香燈持百載，又從樞府發清輝。"]'),
('4305970b-2c4e-42ec-91ad-8b16b564709f','雍熙中植桐于蕭寺壬辰登科後告老來寺留題','張士遜','宋','宋诗','song-poetry','','[]','桐枝手植有桐孫，二紀重來愧此身。',64,'全唐诗/poet.song.5000.json','["桐枝手植有桐孫，二紀重來愧此身。", "三匹衣魚聯貴仕，十洲軒冕接清塵。", "耕桑雖喜多新隴，耆艾堪嗟少故人。", "蕭寺前題粉壁在，又書丁巳對壬辰。"]'),
('6479768c-1a0c-4d2b-8e39-ecf9f02b5844','雲峰寺','張士遜','宋','宋诗','song-poetry','','[]','百越迴轅度翠微，全家還憩白雲扉。',32,'全唐诗/poet.song.5000.json','["百越迴轅度翠微，全家還憩白雲扉。", "白雲知我帝鄉去，旋拂征鞍也要歸。"]'),
('b750b535-8e79-4a20-a07d-a79aa962ce73','錫杖泉','張士遜','宋','宋诗','song-poetry','','[]','靈蹤遺幾載，卓錫在高岑。',48,'全唐诗/poet.song.5000.json','["靈蹤遺幾載，卓錫在高岑。", "妙法歸何地，清泉流至今。", "苔花生細細，雲葉映沈沈。", "桂魄皎清夜，分明六祖心。"]'),
('d0d3a184-89b5-4a5f-ad5a-c631cd02c253','送柴大諫赴闕','張士遜','宋','宋诗','song-poetry','','[]','一萬餘家留戀意，二三十里管絃聲。',32,'全唐诗/poet.song.5000.json','["一萬餘家留戀意，二三十里管絃聲。", "惠加潼水流難盡，鞭指金門望轉清。"]'),
('79371fff-9063-44a5-9f8d-fc17cd0c8a5e','寄唐山人','張士遜','宋','宋诗','song-poetry','','[]','梓潼江口涪江上，深僻還如樗杜村。',32,'全唐诗/poet.song.5000.json','["梓潼江口涪江上，深僻還如樗杜村。", "獨坐翠光噴釣艇，萬家寒影落吟軒。"]'),
('390e6306-f24b-43c3-bfe7-a9243cb124d5','官舍書事二首  其一','張士遜','宋','宋诗','song-poetry','','[]','一載涪江上，轉添山野情。',24,'全唐诗/poet.song.5000.json','["一載涪江上，轉添山野情。", "手携僧共出，筆放吏歸耕。"]'),
('b84d298d-2480-4c3b-9715-c81d217faf57','官舍書事二首  其二','張士遜','宋','宋诗','song-poetry','','[]','官舍如僧舍，翛然萬慮清。',24,'全唐诗/poet.song.5000.json','["官舍如僧舍，翛然萬慮清。", "等閑無客到，容易有苔生。"]'),
('4bd9cf3f-ac0b-4734-a0ce-fff234881ba4','峽山寺','張士遜','宋','宋诗','song-poetry','','[]','峽寺一停橈，新秋暑乍消。',48,'全唐诗/poet.song.5000.json','["峽寺一停橈，新秋暑乍消。", "幽懷徒易釋，肥遁固難招。", "翠擬千峰活，紅分數葉凋。", "優遊虛歲月，何以報清朝。"]'),
('b42f28a9-a460-41b6-b9db-84685060d754','麻姑山','張士遜','宋','宋诗','song-poetry','','[]','結友尋真重駐留，行行渾似近蓬邱。',64,'全唐诗/poet.song.5000.json','["結友尋真重駐留，行行渾似近蓬邱。", "人擎綠玉簡齊立，水带碧桃花亂流。", "松蓋幾層須自老，芝英三秀又誰收。", "坐中忽見紅雲起，疑是仙姑訪舊遊。"]'),
('d62053a5-eb29-4193-bb25-f2d9916eb87b','句  其一','張士遜','宋','宋诗','song-poetry','','[]','曾此焚香動聖容。',8,'全唐诗/poet.song.5000.json','["曾此焚香動聖容。"]'),
('17db1666-348a-4ef2-998e-2c6d0e780dc7','句  其二','張士遜','宋','宋诗','song-poetry','','[]','李成謝世范寬死，唯有長安許道寧。',16,'全唐诗/poet.song.5000.json','["李成謝世范寬死，唯有長安許道寧。"]'),
('bf4967a3-02ab-429d-895c-19aa55af659c','句  其三','張士遜','宋','宋诗','song-poetry','','[]','白浪分吳國，青山隔楚天。',12,'全唐诗/poet.song.5000.json','["白浪分吳國，青山隔楚天。"]'),
('719f9664-1956-4dbf-9ad4-5dcb41ec3fdd','句  其四','張士遜','宋','宋诗','song-poetry','','[]','蘚壁留詩志何大，可憐太華老圖南。',16,'全唐诗/poet.song.5000.json','["蘚壁留詩志何大，可憐太華老圖南。"]'),
('6a2f55de-9978-4b9e-89a5-dfbe2da3ff62','句  其五','張士遜','宋','宋诗','song-poetry','','[]','人家飛鳥外，官舍翠屏中。',12,'全唐诗/poet.song.5000.json','["人家飛鳥外，官舍翠屏中。"]'),
('d0880f4a-1c28-43cd-8c70-811e32f5b381','題義門胡氏華林書院','陳象輿','宋','宋诗','song-poetry','','[]','孝弟揚芳累世傳，書齋雲鎖碧峰前。',96,'全唐诗/poet.song.5000.json','["孝弟揚芳累世傳，書齋雲鎖碧峰前。", "軒窗翠滴松筠接，砌檻清涵水石連。", "旌表華門誠積善，褒崇合族慤敦賢。", "義高管鄭徽猷遠，名重曾顔德行全。", "弟姪登科當景運，公卿記美會佳篇。", "華林勝概終尋訪，舊約依依已數年。"]'),
('12c804ca-df37-43ae-9c22-68af666ea06a','寄館中諸公','楊允元','宋','宋诗','song-poetry','','[]','聞說宮花滿鬢紅，上林絲管侍重瞳。',32,'全唐诗/poet.song.5000.json','["聞說宮花滿鬢紅，上林絲管侍重瞳。", "蓬萊咫尺無由到，始信仙凡迥不同。"]'),
('1d209d34-f654-42eb-a80c-d3a7444ceda1','留題金精山','黎仲吉','宋','宋诗','song-poetry','','[]','昔人鸞鳳色沖天，吳芮遺祠在洞前。',64,'全唐诗/poet.song.5000.json','["昔人鸞鳳色沖天，吳芮遺祠在洞前。", "氣勢徒知凌宇宙，干戈無力問神仙。", "謾輕龜玉傳王業，空得松杉接洞烟。", "一等辛勤鑿巖穴，禹門千古事仍傳。"]'),
('feff2495-a0e7-44ac-b363-d6801d4e2e83','詩一首','張定千','宋','宋诗','song-poetry','','[]','況說龍沙最邊陲，關河阻隔遠明時。',128,'全唐诗/poet.song.5000.json','["況說龍沙最邊陲，關河阻隔遠明時。", "蕃戎把隘當路坐，何日申奏聖人知。", "今遇司空來宣問，枯林滋潤再生枝。", "四面六蕃多圍繞，伏恐尋常失朝儀。", "若不遠仗天威力，只怕河隍陷戎夷。", "請須司空奏論事，封冊加官莫改移。", "比至今秋新恩澤，山林草木總光輝。", "塞上艱莘無說處，一心目斷望龍墀。"]'),
('aeb9da9e-e789-41b7-846c-7da25e1aaa7a','海棠','凌景陽','宋','宋诗','song-poetry','','[]','名園封植幾經春，露濕煙梢畫不真。',32,'全唐诗/poet.song.5000.json','["名園封植幾經春，露濕煙梢畫不真。", "多謝許昌傳雅什，蜀都曾未識詩人。"]'),
('7677f3e5-aa65-4fb2-bc02-c3d6d6d0be77','燕口洞','田霖','宋','宋诗','song-poetry','','[]','燕口龍泓氣象清，錢真此處有遺靈。',64,'全唐诗/poet.song.5000.json','["燕口龍泓氣象清，錢真此處有遺靈。", "仙兄去後師猶在，女弟回時戶已扃。", "雲片尚如披白練，泉聲長似誦黄庭。", "碧桃花發菖蒲紫，留與人間作畫屏。"]'),
('275bccee-3af0-4f0c-b447-11f7c7df1d8e','烏目山五題 興福寺','李堪','宋','宋诗','song-poetry','','[]','雲門十里長，殿塔明朝陽。',48,'全唐诗/poet.song.5000.json','["雲門十里長，殿塔明朝陽。", "半夜風雨至，滿山松桂香。", "清猿嘯遠壑，好鳥鳴虛廊。", "塵土斯可濯，胡爲語滄浪。"]'),
('665fa189-7d62-449a-96a7-dce7157742c5','烏目山五題 延福院','李堪','宋','宋诗','song-poetry','','[]','蘭桂遶禪關，半春香滿山。',48,'全唐诗/poet.song.5000.json','["蘭桂遶禪關，半春香滿山。", "風移金磬遠，雲伴玉龍閑。", "樹暗猿吟外，花開僧定間。", "塵心自然洗，流水日潺潺。"]'),
('722ede0d-6b2e-43c2-8a01-2c1ec3e5446c','烏目山五題 浄居院','李堪','宋','宋诗','song-poetry','','[]','入門松桂深，清氣生人心。',48,'全唐诗/poet.song.5000.json','["入門松桂深，清氣生人心。", "霞影迷窗綺，花光照地金。", "微風起層閣，初月升高林。", "終夜魂自健，滿堂鐘磬音。"]'),
('30dd81df-a0a6-43c7-a537-d7ac1c1bb9a0','烏目山五題 永慶寺','李堪','宋','宋诗','song-poetry','','[]','巖扉開早凉，谷鳥紛遠翔。',48,'全唐诗/poet.song.5000.json','["巖扉開早凉，谷鳥紛遠翔。", "花氣溼幽徑，磬聲清上方。", "雲生松澗底，泉落蘚池傍。", "我有遺榮意，移時坐石牀。"]'),
('bdcbbe55-22a9-492d-a782-80dad14a95b3','烏目山五題 龍院','李堪','宋','宋诗','song-poetry','','[]','林下金仙地，苔門揜夕陽。',48,'全唐诗/poet.song.5000.json','["林下金仙地，苔門揜夕陽。", "花飛殿塔頂，地照雲霞光。", "松老鶴仍在，洞閑龍已翔。", "中宵動清衆，清磬發虛堂。"]'),
('2e83b468-bc97-47c7-b5fc-0fe2bec4a8d1','慧聚寺','李堪','宋','宋诗','song-poetry','','[]','古寺有遠名，欲游先夢生。',48,'全唐诗/poet.song.5000.json','["古寺有遠名，欲游先夢生。", "飛猿澗底嘯，靈鳥雲間鳴。", "影密樓臺衆，香繁草樹榮。", "何年照佛火，燦燦長光明。"]'),
('a3c126a8-bf90-4b70-a209-59a2277c3d72','宿慧聚寺','李堪','宋','宋诗','song-poetry','','[]','石林高月生，蘚閣踈磬鳴。',48,'全唐诗/poet.song.5000.json','["石林高月生，蘚閣踈磬鳴。", "宿鳥夢難就，定僧魂更清。", "香風動花影，巖瀑飛玉聲。", "遥夜坐來短，但餘天外情。"]'),
('a0361790-da06-485b-acc5-3feee5b8e390','仙樓道院','李堪','宋','宋诗','song-poetry','','[]','尋源探雲霞，中有金仙家。',96,'全唐诗/poet.song.5000.json','["尋源探雲霞，中有金仙家。", "綺疏晃飛翬，雕欄燦朱華。", "珍禽棲不去，靈液流無涯。", "晴旭起風篁，空香送天花。", "春雷會社鼓，寒煙聚海茶。", "奇峰媚如削，芳樹一何嘉。", "且將翠閣齊，絕與紅塵賒。", "終然謝朝紱，此地營丹砂。"]'),
('27845f43-8262-4c67-8945-e3012f85584d','極樂寺','李堪','宋','宋诗','song-poetry','','[]','空門出白雲，梵宇依蒼岫。',144,'全唐诗/poet.song.5000.json','["空門出白雲，梵宇依蒼岫。", "天色湛瑶光，春花結野秀。", "簷間綺羅被，池底星珠漏。", "香沉烟篆餘，文兼雨碑舊。", "恬智靜可養，寂寞誰復扣。", "逍遥隠葉猿，盤薄穿花溜。", "團團草露晞，瑟瑟空香逗。", "層臺太虛半，雙壑瀑泉透。", "苔空綠錢死，松老清陰瘦。", "獨鶴倏飛騫，深蘿苦紛構。", "歸涔待沃洲，芥子觀靈鷲。", "凈土人不來，塵寰廓然晝。"]'),
('09708241-42eb-4fff-98fe-769fba38bb0b','玉田八景 翠屏朝雨','李堪','宋','宋诗','song-poetry','','[]','翠屏山下雨霏霏，雲掩岡巒草樹微。',32,'全唐诗/poet.song.5000.json','["翠屏山下雨霏霏，雲掩岡巒草樹微。", "一段丹青誰解寫，畫家惟有米元暉。"]'),
('d0904171-af3b-4869-bb17-acf0bea932b6','玉田八景 西山晴雪','李堪','宋','宋诗','song-poetry','','[]','西山岌岌倚層霄，爽氣恒多瘴氣消。',32,'全唐诗/poet.song.5000.json','["西山岌岌倚層霄，爽氣恒多瘴氣消。", "誰道閩中無雨雪，年年絕頂見璚瑶。"]'),
('8c777e60-a07c-4f35-828a-e3def27af66a','玉田八景 玉灘夜月','李堪','宋','宋诗','song-poetry','','[]','鳴玉灘頭片月生，波光掩映釣舟橫。',32,'全唐诗/poet.song.5000.json','["鳴玉灘頭片月生，波光掩映釣舟橫。", "何人隔岸吹長笛，一曲凉州恰二更。"]'),
('32b57b4e-1601-4e7f-95ae-f572263c50f7','玉田八景 華頂秋容','李堪','宋','宋诗','song-poetry','','[]','何處栖真遠世紛，五華高頂絕人氛。',32,'全唐诗/poet.song.5000.json','["何處栖真遠世紛，五華高頂絕人氛。", "仙翁自有餐霞法，謾使人間望彩雲。"]'),
('f54f145b-183a-4484-9ca9-20945a9cf5f0','玉田八景 仙嶺樵歌','李堪','宋','宋诗','song-poetry','','[]','金仙洞頭樵子多，負薪出山行且歌。',32,'全唐诗/poet.song.5000.json','["金仙洞頭樵子多，負薪出山行且歌。", "仙家棋局無心看，只恐歸時爛斧柯。"]'),
('c87ab9b6-a427-445d-bb32-11424ef23e2e','玉田八景 文筆夕照','李堪','宋','宋诗','song-poetry','','[]','玉邑東南第一峰，銛錐穎脫亂山中。',32,'全唐诗/poet.song.5000.json','["玉邑東南第一峰，銛錐穎脫亂山中。", "夕陽影裏分明見，五色文章耀筆鋒。"]'),
('1d1e18ac-7223-4695-9fbc-6984162e548e','玉田八景 藍洞歸雲','李堪','宋','宋诗','song-poetry','','[]','洞門不閉日空虛，雲去雲來何定居。',32,'全唐诗/poet.song.5000.json','["洞門不閉日空虛，雲去雲來何定居。", "看到虛中生白處，恰如混沌未分初。"]'),
('5b9a3f08-0b6e-4e3d-b76b-5dc91bd19672','玉田八景 劍溪漁唱','李堪','宋','宋诗','song-poetry','','[]','水過雲津勢漸平，雙溪匯作劍溪清。',32,'全唐诗/poet.song.5000.json','["水過雲津勢漸平，雙溪匯作劍溪清。", "漁舟往來無人見，隔竹時聞欵乃聲。"]'),
('b1f6f033-60a0-4225-a8cc-7be2b280641d','舞雩臺','李堪','宋','宋诗','song-poetry','','[]','舞雩臺上春風起，魯國先生講始開。',32,'全唐诗/poet.song.5000.json','["舞雩臺上春風起，魯國先生講始開。", "欲解陶潛印歸去，心思吾道重徘徊。"]'),
('ef6fc882-0cf5-453a-826b-8770a9ddd5e8','句  其一','李堪','宋','宋诗','song-poetry','','[]','桐鄉留語葬，銘路在生悲。',12,'全唐诗/poet.song.5000.json','["桐鄉留語葬，銘路在生悲。"]'),
('61fc3968-3e7e-4383-901e-f7b7a432d588','句  其二','李堪','宋','宋诗','song-poetry','','[]','海月隨帆落，溪花繞驛流。',12,'全唐诗/poet.song.5000.json','["海月隨帆落，溪花繞驛流。"]'),
('cc808c87-e178-44c3-a27a-46912fcbee26','句  其三','李堪','宋','宋诗','song-poetry','','[]','雷風有約春虯起，霜露無情紫蕙枯。',16,'全唐诗/poet.song.5000.json','["雷風有約春虯起，霜露無情紫蕙枯。"]'),
('f8734830-cac6-45c2-afbb-22c5c831c86e','句  其四','李堪','宋','宋诗','song-poetry','','[]','雨密絲桐潤，潮平釣石沈。',12,'全唐诗/poet.song.5000.json','["雨密絲桐潤，潮平釣石沈。"]'),
('245d4f73-8f50-409d-9e41-a27d00d68f8a','句  其五','李堪','宋','宋诗','song-poetry','','[]','海月隨帆落，溪花遶驛流。',12,'全唐诗/poet.song.5000.json','["海月隨帆落，溪花遶驛流。"]'),
('25ddf65d-9941-4a9d-8faf-6a77d4be3945','贈淳于公歸養','朱台符','宋','宋诗','song-poetry','','[]','通籍懸車不待年，綵衣歸去奉晨昏。',64,'全唐诗/poet.song.5000.json','["通籍懸車不待年，綵衣歸去奉晨昏。", "倚門且慰慈親望，戀闕空銜聖主恩。", "天上芝泥新誥敕，海邊蕪沒舊田園。", "會須引退追高躅，宦路悠悠豈足論。"]'),
('ab976f95-23d2-43de-9838-711ff46124ec','詠華林書院','朱台符','宋','宋诗','song-poetry','','[]','白雲深處舊生涯，東指名都百里賒。',64,'全唐诗/poet.song.5000.json','["白雲深處舊生涯，東指名都百里賒。", "萬卷詩書惟曲檻，四方賓客到儒家。", "峰巒卓立多奇石，草木叢芳半異花。", "勝概無由一尋訪，只憑幽夢繞煙霞。"]'),
('e40b697a-3fc4-475e-9ae3-c6328b2b8b65','南朝','李宗諤','宋','宋诗','song-poetry','','[]','仙華玉壽夜沉沉，三閣齊雲複道深。',64,'全唐诗/poet.song.5000.json','["仙華玉壽夜沉沉，三閣齊雲複道深。", "平昔金鋪空廢苑，于今瓊樹有遺音。", "珠簾映寢方成夢，麝壁飄香未稱心。", "惆悵雷塘都幾日，吟魂醉魄已相尋。"]'),
('4062475c-41bd-4109-8c9d-c0df440e9ee7','代意','李宗諤','宋','宋诗','song-poetry','','[]','霧鸞曉影忽參差，雲雨陽臺役夢思。',64,'全唐诗/poet.song.5000.json','["霧鸞曉影忽參差，雲雨陽臺役夢思。", "自是膠絃無續日，不同珪月有圓時。", "洞房斗帳承新愛，河漢星橋隔後期。", "綺榭凝塵斷消息，抒情空擬四愁詩。"]'),
('c9328794-93ac-4e09-bb24-eda8db31d176','漢武','李宗諤','宋','宋诗','song-poetry','','[]','建章宮闕鬰岧嶢，露掌脩莖倚泬寥。',64,'全唐诗/poet.song.5000.json','["建章宮闕鬰岧嶢，露掌脩莖倚泬寥。", "平樂館中觀角觝，單于臺上懾天驕。", "蓬萊望氣滄波闊，太一祈年紫府遥。", "西母不來東朔去，茂陵松柏冷蕭蕭。"]'),
('6faf4629-2c65-4915-9b18-d580cf8c4592','館中新蟬','李宗諤','宋','宋诗','song-poetry','','[]','雨過新聲出苑牆，烟輕餘韻度回塘。',64,'全唐诗/poet.song.5000.json','["雨過新聲出苑牆，烟輕餘韻度回塘。", "短亭疏柳臨官道，平野西風更夕陽。", "八斗陳思饒賦詠，二毛潘岳易悲凉。", "感時偏動騷人思，不問天涯與帝鄉。"]'),
('66145f06-760a-407d-8fa7-9a6f0c597f97','勸石集賢飲','李宗諤','宋','宋诗','song-poetry','','[]','都門祖軷綺筵張，舉白無由訴羽觴。',64,'全唐诗/poet.song.5000.json','["都門祖軷綺筵張，舉白無由訴羽觴。", "石室紬書勤亦至，金貂換酒醉何妨。", "甕間吏部寧須問，席上車公不可忘。", "應念朝來猶眊矂，解酲誰用蔗爲漿。"]'),
('a363b395-8a1e-41e4-bc8e-9a7cac974ac6','燈夕寄獻內翰虢略公','李宗諤','宋','宋诗','song-poetry','','[]','東城南陌盡遊人，陌上香車起暗塵。',64,'全唐诗/poet.song.5000.json','["東城南陌盡遊人，陌上香車起暗塵。", "歷歷星榆光奪晝，煌煌火樹豔爭春。", "章溝五鼓催行樂，衛尉千廬罷徼巡。", "應念鼇山方併宿，紫泥封後獨頻伸。"]'),
('fa0f37e9-4530-420a-9c4e-832d8b03f7b7','清風十韻','李宗諤','宋','宋诗','song-poetry','','[]','閒館方迴暑，商飈乍應金。',120,'全唐诗/poet.song.5000.json','["閒館方迴暑，商飈乍應金。", "天高初起籟，松澹更宜琴。", "汾棹傳歌遠，班詩託興深。", "東陽仁自布，西顥氣還侵。", "太液翻晴旭，靈和亂翠陰。", "舟輕飛燕袂，臺逈楚王襟。", "阮嘯經時盡，齊蟬度日吟。", "愁生孤戍角，響續暮城砧。", "空靜銷雲鏤，庭虛轉蕙心。", "賢哉吉甫頌，千載有遺音。"]'),
('43f687ec-9903-423c-9979-5e548b2c8469','絕句','李宗諤','宋','宋诗','song-poetry','','[]','戴了宮花賦了詩，不容重睹赭黄衣。',32,'全唐诗/poet.song.5000.json','["戴了宮花賦了詩，不容重睹赭黄衣。", "無聊獨出金門去，恰似當年下第歸。"]'),
('22d042d5-e2a3-4064-ba74-4b0622f17ebd','送僧歸天寧萬年禪院','李宗諤','宋','宋诗','song-poetry','','[]','師住天台寺，天台水石幽。',96,'全唐诗/poet.song.5000.json','["師住天台寺，天台水石幽。", "眼前皆勝境，門下盡名流。", "法號君恩賜，精藍國力修。", "渡杯來鳳闕，振錫謁珠旒。", "內殿從容對，神都委曲游。", "高僧類雲鶴，歸思在林丘。", "御札全編得，宸毫幾處收。", "遥思到時節，煙樹赤城秋。"]'),
('835f74ce-2cf6-4608-a8a0-273669b47ec2','送何水部蒙出牧袁州','李宗諤','宋','宋诗','song-poetry','','[]','三省郎曹素髮垂，兩朝頻賜五時衣。',64,'全唐诗/poet.song.5000.json','["三省郎曹素髮垂，兩朝頻賜五時衣。", "一麾又守江城去，千騎方從澤國歸。", "釃酒河梁秋草闊，卸舟湖岸暝烟微。", "宜陽郡客多才子，誰伴山公醉夕暉。"]'),
('d74de122-d7bf-4ec3-884d-1e38d46cce63','詩送士龍腹兄','李宗諤','宋','宋诗','song-poetry','','[]','銅魚四明守，竹馬十年兄。',48,'全唐诗/poet.song.5000.json','["銅魚四明守，竹馬十年兄。", "摻袂河梁別，鳴橈澤國行。", "登樓知日近，傍海見潮生。", "郡政應多暇，新詩幾首成。"]'),
('f7ce6bc0-2dce-48cb-81b1-1d346242a552','詠華林書院','李宗諤','宋','宋诗','song-poetry','','[]','華林有胡氏，孝義共知名。',120,'全唐诗/poet.song.5000.json','["華林有胡氏，孝義共知名。", "宅對千峰秀，家傳雙桂榮。", "書樓藏六籍，講席聚諸生。", "官序新春拜，門閭往歲旌。", "兒孫多力學，兄弟亦躬耕。", "一院松篁影，滿山猿鶴聲。", "傍溪挑蕨煮，就樹采茶烹。", "客戀琴樽樂，僧依水石清。", "官途空擾擾，塵世自營營。", "他日林泉約，何當遂此情。"]'),
('688ae49b-6e67-42db-a9c7-f87d535dc6e5','句  其一','李宗諤','宋','宋诗','song-poetry','','[]','一溪曉綠浮鸂鶒，萬樹春紅叫杜鵑。',16,'全唐诗/poet.song.5000.json','["一溪曉綠浮鸂鶒，萬樹春紅叫杜鵑。"]'),
('4ab98db7-cb3c-4c88-b801-5dfd60ac6c98','句  其二','李宗諤','宋','宋诗','song-poetry','','[]','金鑾後記人爭寫，玉署新碑帝自書。',16,'全唐诗/poet.song.5000.json','["金鑾後記人爭寫，玉署新碑帝自書。"]'),
('9ee2a79c-6a53-42be-b4c6-9aeacb2abfea','句  其三','李宗諤','宋','宋诗','song-poetry','','[]','上饒多勝景，樽酒不應空。',12,'全唐诗/poet.song.5000.json','["上饒多勝景，樽酒不應空。"]'),
('52656083-bf1a-4696-b248-a0fe98ce7c97','句  其四','李宗諤','宋','宋诗','song-poetry','','[]','門外溪山荆渚路，馬前梅杏漢江春。',16,'全唐诗/poet.song.5000.json','["門外溪山荆渚路，馬前梅杏漢江春。"]'),
('f9b4cba5-3efe-4722-a88b-9c53902bbe69','觀德堂','李垂','宋','宋诗','song-poetry','','[]','園池氣象明，池沼春波平。',72,'全唐诗/poet.song.5000.json','["園池氣象明，池沼春波平。", "東匯有朝勢，北源無滯聲。", "臨流好鼓瑟，待月堪浮觥。", "濯足思餘綠，洗心思雲清。", "篆溝合遠派，布竇垂高城。", "我願化飛雨，使君將勸耕。"]'),
('65f54a44-3603-4634-be2b-b1e08ec3f0e1','句','釋法周','宋','宋诗','song-poetry','','[]','地因培客土，凡草有時生。',12,'全唐诗/poet.song.5000.json','["地因培客土，凡草有時生。"]'),
('c7029e31-e787-4e95-9f6f-5e368883ece8','送僧歸護國寺','魯宗道','宋','宋诗','song-poetry','','[]','倏來倏去本無心，舊國王家念正深。',64,'全唐诗/poet.song.5000.json','["倏來倏去本無心，舊國王家念正深。", "猶喜大緣逢景運，不辭千里答嘉音。", "人間話道經三伏，島外棲禪指二林。", "留別皇都有新偈，苦將泡幻喻升沈。"]'),
('02cb8142-e5b4-485c-a0a9-2dcdcc3d4a9a','題湯泉院壁','魯宗道','宋','宋诗','song-poetry','','[]','黄山勝地煙霞明，朱砂泉暖肌膚醒。',64,'全唐诗/poet.song.5000.json','["黄山勝地煙霞明，朱砂泉暖肌膚醒。", "鳥聲不斷山不壞，今人古人徒營營。", "暫來誰更辭磽确，抖擻塵纓聊澣濯。", "靈泉去病功績深，無人復創爲高閣。"]'),
('624fa9c5-697f-454e-89f4-0757ba0c634f','洗藥源','魯宗道','宋','宋诗','song-poetry','','[]','採得千年藥，臨流凈洗藏。',24,'全唐诗/poet.song.5000.json','["採得千年藥，臨流凈洗藏。", "至今源裏水，猶带舊時香。"]'),
('c8381efe-893e-43d6-997a-16ec608e4c7b','登黄山','魯宗道','宋','宋诗','song-poetry','','[]','三十六峰凝翠靄，數千餘仞鎖嵐煙。',32,'全唐诗/poet.song.5000.json','["三十六峰凝翠靄，數千餘仞鎖嵐煙。", "軒皇去後無消息，白鹿青牛何處眠。"]'),
('24097649-238b-4ec3-bbba-985fe80b8e63','蓮花源','魯宗道','宋','宋诗','song-poetry','','[]','花開十丈照峰頭，露褪紅衣爛不收。',32,'全唐诗/poet.song.5000.json','["花開十丈照峰頭，露褪紅衣爛不收。", "太乙真人多逸興，穩眠一葉泛中流。"]'),
('156ab702-0de1-4e8d-9080-79c0c95aaceb','代意','丁謂','宋','宋诗','song-poetry','','[]','玦带珊瑚珮解瓊，楚雲無定好傷情。',64,'全唐诗/poet.song.5000.json','["玦带珊瑚珮解瓊，楚雲無定好傷情。", "臨邛已誤通瑟意，金谷難尋辯玉聲。", "微警單棲盤露重，密含幽思畹蘭平。", "明珠百琲將何當，悵望輕軀病欲成。"]'),
('fc32a81f-2164-494f-b6b6-4a08db8fb2dc','荷花','丁謂','宋','宋诗','song-poetry','','[]','相倚秋風立，蘭言似有無。',72,'全唐诗/poet.song.5000.json','["相倚秋風立，蘭言似有無。", "未饒霜女俊，不愛月娥孤。", "力弱烟被素，心危露泣珠。", "剪裁隨楚思，幽怨寄吳歈。", "半坼香囊解，微傾醉弁扶。", "涉江如可採，百琲答輕軀。"]'),
('fc740575-f917-4d4f-9e90-adbfd0815df1','再賦','丁謂','宋','宋诗','song-poetry','','[]','彼美秋江上，塵埃耻託根。',72,'全唐诗/poet.song.5000.json','["彼美秋江上，塵埃耻託根。", "笑傾行雨國，香返夢蘭魂。", "蛺蝶無媒妁，鴛鴦見子孫。", "徧窺思兩槳，深鎖憶重門。", "怯徇風波性，慚留月露痕。", "枉將金試步，千古怨東昏。"]'),
('790e88e4-002b-478d-b1bb-da04aca020e8','又贈一絕','丁謂','宋','宋诗','song-poetry','','[]','夢散高唐夜正遥，楚天何處不無憀。',32,'全唐诗/poet.song.5000.json','["夢散高唐夜正遥，楚天何處不無憀。", "秋風似會荆王意，露渚烟汀養細腰。"]'),
('0c087eb5-e855-4d7e-b432-1cb3fac28452','梨','丁謂','宋','宋诗','song-poetry','','[]','摇摇繁實弄秋光，曾伴青椑薦武皇。',64,'全唐诗/poet.song.5000.json','["摇摇繁實弄秋光，曾伴青椑薦武皇。", "玄圃雲腴滋紺質，上林風馭獵清香。", "尋芳尚憶瓊爲樹，蠲渴因知玉有漿。", "多少好枝誰最見，冒霜頰丹倚隣牆。"]'),
('e9afa6cd-f13b-470d-a373-f032e866a2ce','戲答白稹','丁謂','宋','宋诗','song-poetry','','[]','欺天行當吾何有，立地機關子太乖。',32,'全唐诗/poet.song.5000.json','["欺天行當吾何有，立地機關子太乖。", "五百青蚨兩家闕，白洪崖打赤洪崖。"]'),
('57b27854-fb0c-4721-bc8e-1e5841cf1e22','陰獄','丁謂','宋','宋诗','song-poetry','','[]','黑水溪旁聊駐馬，奈何岸上試回頭。',32,'全唐诗/poet.song.5000.json','["黑水溪旁聊駐馬，奈何岸上試回頭。", "高崖昏處是陰獄，須信人生到此休。"]'),
('54eabe6e-28e6-4aee-9792-648b147555a8','贈方江二君  其一','丁謂','宋','宋诗','song-poetry','','[]','偶向嚴堂弔子陵，布衣携手遠相迎。',32,'全唐诗/poet.song.5000.json','["偶向嚴堂弔子陵，布衣携手遠相迎。", "乍親冠蓋談諧少，久住林泉骨自清。"]'),
('daf66970-2d68-4705-8aa1-abe50672b465','贈方江二君  其二','丁謂','宋','宋诗','song-poetry','','[]','正好辛勤緣齒少，最難遭遇是時平。',32,'全唐诗/poet.song.5000.json','["正好辛勤緣齒少，最難遭遇是時平。", "李頻鄉黨玄英裔，皆合工詩取盛名。"]'),
('3aa37d82-fd67-4e0d-8f80-ed87f79f38db','次韻和進真宗七言四韻','丁謂','宋','宋诗','song-poetry','','[]','白麻初降紫宸中，簪組相驚帝澤豐。',64,'全唐诗/poet.song.5000.json','["白麻初降紫宸中，簪組相驚帝澤豐。", "驟陟將壇知運偶，久塵台席愧材庸。", "桑榆便覺人間別，旌戟猶疑夢裏逢。", "已是都城聳榮觀，更頒天唱耀戎容。"]'),
('b05001a2-27ac-467a-9a58-cd2b0805cbeb','又五言十韻','丁謂','宋','宋诗','song-poetry','','[]','叨竊逢嘉會，孤單荷曲成。',120,'全唐诗/poet.song.5000.json','["叨竊逢嘉會，孤單荷曲成。", "高車陪上宰，密座厠羣英。", "步武清華地，優游侍從榮。", "勤劬期薄效，忠謹誓明誠。", "方畏官箴失，俄驚寵命行。", "冒恩心易感，戀聖意難平。", "未副宵衣念，寧安晝錦情。", "摇摇千里棹，眷眷九重城。", "茜旆輝登路，瓊章耀去程。", "子牟牽望處，金闕玉爲京。"]'),
('79dd5384-dcea-4bda-bc10-77d836a655b7','虎丘','丁謂','宋','宋诗','song-poetry','','[]','久塵黄閣侍威顔，忽擁高牙出帝關。',64,'全唐诗/poet.song.5000.json','["久塵黄閣侍威顔，忽擁高牙出帝關。", "玉佩乍辭文石陛，錦衣重到虎丘山。", "仙飈時傍潺湲起，珍羽多從杳靄還。", "官大寵深難得暇，林泉懷舊是偷閑。"]'),
('6345c680-a163-4815-b312-5b05a1865fa4','以詩送宣賜進奉紅綃封龍字茶與璉禪師','丁謂','宋','宋诗','song-poetry','','[]','密緘龍焙火前春，翠字紅綃熨眼新。',32,'全唐诗/poet.song.5000.json','["密緘龍焙火前春，翠字紅綃熨眼新。", "品味至高誰合得，雙林樹下上乘人。"]'),
('7ab495ae-8302-4974-93a2-6159f0e164ad','山居','丁謂','宋','宋诗','song-poetry','','[]','峒口清香徹海濱，四時芬馥四時春。',64,'全唐诗/poet.song.5000.json','["峒口清香徹海濱，四時芬馥四時春。", "山多綠桂憐同氣，谷有幽蘭讓後塵。", "草解忘憂憂底事，花能含笑笑何人。", "爭如彼美欽天壙，長薦芳香奉百神。"]'),
('4b38b2d2-4650-42b4-98fa-b4b84c1523d8','北苑焙新茶','丁謂','宋','宋诗','song-poetry','','[]','北苑龍茶者，甘鮮的是珍。',192,'全唐诗/poet.song.5000.json','["北苑龍茶者，甘鮮的是珍。", "四方惟數此，萬物更無新。", "纔吐微茫綠，初沾少許春。", "散尋縈樹遍，急採上山頻。", "宿葉寒猶在，芳芽冷未伸。", "茅茨溪口焙，籃籠雨中民。", "長疾勾萌併，開齊分兩均。", "带烟蒸雀舌，和露疊龍鱗。", "作貢勝諸道，先嘗祇一人。", "緘封瞻闕下，郵傳渡江濱。", "特旨留丹禁，殊恩賜近臣。", "啜爲靈藥助，用與上罇親。", "頭進英華盡，初烹氣味醇。", "細香勝却麝，淺色過於筠。", "顧渚慚投木，宜都愧積薪。", "年年號供御，天産壯甌閩。"]'),
('6a4356b5-e128-49e6-a4bd-5f3311b6ba58','送張無夢歸天台山','丁謂','宋','宋诗','song-poetry','','[]','不逐蒲輪至，惟尋蕙帳還。',72,'全唐诗/poet.song.5000.json','["不逐蒲輪至，惟尋蕙帳還。", "冥鴻思物外，遼鶴別人間。", "心與冠纓遠，身將日月閑。", "放歸銜帝澤，賜對仰天顔。", "逸躅淩風馭，高文炳象環。", "瓊臺刻宸藻，千古耀名山。"]'),
('2f3af2ff-a163-4074-aac2-12294ff2a1b9','送僧歸護國寺','丁謂','宋','宋诗','song-poetry','','[]','少室久傳西祖印，京華時不等閑尋。',64,'全唐诗/poet.song.5000.json','["少室久傳西祖印，京華時不等閑尋。", "黄樞慕道飛書密，紫禁知名示寵深。", "一法徧垂春雨潤，羣生皆悟海潮音。", "南歸八桂禪庭在，後夜僧懷立雪心。"]'),
('7cb44580-b5cd-40bb-8457-f4b2c159b3a6','九華山','丁謂','宋','宋诗','song-poetry','','["\u4e5d\u534e\u5c71"]','宿月鷗鳬立淺沙，落花蘆荻露人家。',32,'全唐诗/poet.song.5000.json','["宿月鷗鳬立淺沙，落花蘆荻露人家。", "天寒夜靜長無物，一片清江浸九華。"]'),
('90a663d0-fc69-43a4-89c7-3ca9dc0e527d','江陵','丁謂','宋','宋诗','song-poetry','','[]','渚宮形勝地，從古冠荆湖。',24,'全唐诗/poet.song.5000.json','["渚宮形勝地，從古冠荆湖。", "依劉開幕府，吊屈俯滄浪。"]'),
('e06138a8-ee0d-456f-ab02-19717df7f4b0','廣利','丁謂','宋','宋诗','song-poetry','','[]','出城數里即青山，路入青松白石間。',32,'全唐诗/poet.song.5000.json','["出城數里即青山，路入青松白石間。", "只合步行尋石徑，不宜呵喝入松關。"]'),
('43ba2138-4a57-4013-ad64-557a47de8dff','橘花','丁謂','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','香於梔子細於梅，柳絮梨花過後開。',64,'全唐诗/poet.song.5000.json','["香於梔子細於梅，柳絮梨花過後開。", "搔首預愁經惡雨，傷心初見落蒼苔。", "丹青得到須名手，題詠今疏信不才。", "莫怪主公相看好，舉家新自洞庭來。"]'),
('2cda4283-a5ce-473b-b776-fd43a2d7a73b','江上雨','丁謂','宋','宋诗','song-poetry','','[]','雨驚魚食釣翁歸，手把絲綸下蘚磯。',32,'全唐诗/poet.song.5000.json','["雨驚魚食釣翁歸，手把絲綸下蘚磯。", "家在渡頭衝濕去，碎聲繁點逐蓑衣。"]'),
('bb5a9a05-a85c-4e7d-a64b-148a1021b38e','詠泉州刺桐','丁謂','宋','宋诗','song-poetry','','[]','聞得鄉人說刺桐，葉先花發始年豐。',32,'全唐诗/poet.song.5000.json','["聞得鄉人說刺桐，葉先花發始年豐。", "我今到此憂民切，只愛青青不愛紅。"]'),
('d0f5b8cf-ed88-4329-8a8f-5cfba62361c8','過武陵甘泉寺留題','丁謂','宋','宋诗','song-poetry','','[]','翠影人疏度，波光瑟瑟凝。',48,'全唐诗/poet.song.5000.json','["翠影人疏度，波光瑟瑟凝。", "帝家金掌露，仙署玉壺冰。", "曉井侵星汲，宵厨向月澄。", "豈惟蠲肺渴，灌頂助三乘。"]'),
('91918261-c815-4ad7-b757-1327ed192c84','有感','丁謂','宋','宋诗','song-poetry','','[]','今到崖州事可嗟，夢中常若在京華。',64,'全唐诗/poet.song.5000.json','["今到崖州事可嗟，夢中常若在京華。", "程途何啻一萬里，戶口都無三百家。", "夜聽猿啼孤樹遠，曉看潮上瘴烟斜。", "吏人不見中朝禮，麋鹿時時到縣衙。"]'),
('1b52ac62-2158-4148-8665-c5e6a2b7dfb4','途中盛暑','丁謂','宋','宋诗','song-poetry','','[]','山木無陰驛路長，海風吹熱透蕉裳。',64,'全唐诗/poet.song.5000.json','["山木無陰驛路長，海風吹熱透蕉裳。", "渴思西漢金莖露，困憶南朝石步廊。", "江上竹竿輸散誕，林間冠褐負清凉。", "下程欲選披襟處，滿眼赭桐兼佛桑。"]'),
('7be501b9-9463-42cb-a03e-5876d0812971','游東山','丁謂','宋','宋诗','song-poetry','','[]','數峰回抱隔烟林，一簇招提十里深。',64,'全唐诗/poet.song.5000.json','["數峰回抱隔烟林，一簇招提十里深。", "祇合步行尋石徑，不宜呵喝入松陰。", "遥分畫手援毫意，暗起詩人得句心。", "梅嶺笙歌上高處，孤猿幽鳥減清音。"]'),
('3d58291c-0459-4ebd-b22c-2f9cefe8b34e','清真香歌','丁謂','宋','宋诗','song-poetry','','[]','四兩玄參三兩松，麝香半分蜜和同。',32,'全唐诗/poet.song.5000.json','["四兩玄參三兩松，麝香半分蜜和同。", "丸如彈子金爐爇，還似花心噴曉風。"]'),
('d42ff481-0fbf-4025-b3b5-632ff2935dde','公舍春日','丁謂','宋','宋诗','song-poetry','','[]','綠楊垂線草鋪茵，觸處烟光舉眼新。',64,'全唐诗/poet.song.5000.json','["綠楊垂線草鋪茵，觸處烟光舉眼新。", "一品也須妨白髮，千金莫惜買青春。", "鶑聲圓滑堪清耳，花豔鮮明欲照身。", "獨向此時爲俗吏，風流知是不如人。"]'),
('b6a4d74a-9518-4670-bcf8-9b1e81b87aeb','煎茶','丁謂','宋','宋诗','song-poetry','','[]','開緘試雨前，須汲遠山泉。',96,'全唐诗/poet.song.5000.json','["開緘試雨前，須汲遠山泉。", "自遶風爐立，誰聽石碾眠。", "輕微緣入麝，猛沸却如蟬。", "羅細烹還好，鐺新味更全。", "花隨僧箸破，雲逐客甌圓。", "痛惜藏書篋，堅留待雪天。", "睡醒思滿啜，吟困憶重煎。", "祇此消塵慮，何須作酒仙。"]'),
('34f33761-fb0c-4b4a-aa7a-f745ad1610ff','垂虹亭','丁謂','宋','宋诗','song-poetry','','[]','悠悠風物四時新，苒苒山屏萬古春。',32,'全唐诗/poet.song.5000.json','["悠悠風物四時新，苒苒山屏萬古春。", "多少江山人不看，却來江上看行人。"]'),
('a6cf7e8c-4a30-4b6e-9f80-09c1f7ae508d','山','丁謂','宋','宋诗','song-poetry','','[]','嫩雲零落樹參差，忽見千峰豁所思。',32,'全唐诗/poet.song.5000.json','["嫩雲零落樹參差，忽見千峰豁所思。", "酷愛似看名手畫，難題却憶古人詩。"]'),
('d5e6d913-6ae5-46fc-98cf-990b19e12ab7','遊卧龍山','丁謂','宋','宋诗','song-poetry','','[]','日長春老職司閒，縱轡因尋負郭山。',64,'全唐诗/poet.song.5000.json','["日長春老職司閒，縱轡因尋負郭山。", "花氣半飄青靄外，泉聲多在白雲間。", "香燈肅肅嚴僧事，鐘梵蕭蕭爽客顔。", "坐有詩人樽有酒，擬拋城市宿禪關。"]'),
('e45c5d9a-ead7-4b1e-bb40-c21cc99c41cb','桂林資聖寺','丁謂','宋','宋诗','song-poetry','','[]','八桂提封接九疑，寶坊遊覽負心期。',64,'全唐诗/poet.song.5000.json','["八桂提封接九疑，寶坊遊覽負心期。", "栴檀未睹生天像，琬琰空傳置寺碑。", "白玉毫光應照我，黄金色相竟留誰。", "靈川他日香雲裏，莫道凡夫見佛遲。"]'),
('805204c4-7ce3-4b04-8a71-340ca9a16e94','癸酉仲夏自□道□華嚴山主正師上人□□相遇今忽至止且云□□□□□□携酒□□□□□□□□□□□□□□','丁謂','宋','宋诗','song-poetry','','[]','壞衲相過羽服迎，可憐□靜□營營。',64,'全唐诗/poet.song.5000.json','["壞衲相過羽服迎，可憐□靜□營營。", "我思江上忘身計，師出山中乞寺名。", "振錫迴還心未住，布金圓□意方平。", "零陵泉石三湘最，莫踏□□□□□。"]'),
('c27db332-121e-4659-8703-8f82f9edcd74','冠','丁謂','宋','宋诗','song-poetry','','[]','盛禮尊元服，嘉名重進賢。',48,'全唐诗/poet.song.5000.json','["盛禮尊元服，嘉名重進賢。", "窮奢譏鵔鵲，極品貴貂蟬。", "就列峨章甫，瞻顔仰邃延。", "誰知遠遊制，寵錫自高天。"]'),
('1aa7355b-ea33-465b-a0af-767b704f9f1c','笏','丁謂','宋','宋诗','song-poetry','','[]','詘直明懷讓，球魚示有章。',48,'全唐诗/poet.song.5000.json','["詘直明懷讓，球魚示有章。", "對敭資指畫，受命助心藏。", "慎重傳三世，榮華置滿牀。", "賢哉段太尉，爲國擊豺狼。"]'),
('e22281c0-c431-48d9-9363-bba6463c0a54','珮','丁謂','宋','宋诗','song-poetry','','[]','山玄水蒼重，進揖退揚清。',48,'全唐诗/poet.song.5000.json','["山玄水蒼重，進揖退揚清。", "靜有如圭德，行無變玉聲。", "韋弦非中度，蘭蕙欠鏘鳴。", "幾憶陪朝會，交相間九成。"]'),
('8796b106-9f5b-4247-a2c5-a2f70fe8f864','玉佩','丁謂','宋','宋诗','song-poetry','','[]','至寶不自獻，韜藏亦英華。',24,'全唐诗/poet.song.5000.json','["至寶不自獻，韜藏亦英華。", "餘香被草木，秀擢幽巖花。"]'),
('f87a944a-b5ec-4d3f-8627-919630a82e31','金','丁謂','宋','宋诗','song-poetry','','[]','莫羨雙南美，休貪九牧珍。',48,'全唐诗/poet.song.5000.json','["莫羨雙南美，休貪九牧珍。", "入懷寧讓粟，攫市不防人。", "越冶模良弼，燕臺禮上賓。", "徒誇滿堂富，永勝一經貧。"]'),
('3924fe45-0f84-4c02-97d3-86e00ff31b39','玉','丁謂','宋','宋诗','song-poetry','','[]','誰負連城美，須思韞櫝藏。',48,'全唐诗/poet.song.5000.json','["誰負連城美，須思韞櫝藏。", "輝山知稟異，被褐喻韜光。", "呂釣時終至，虞求禍是防。", "寧爲田父棄，莫作楚人傷。"]'),
('8e1f630a-f2ef-4aeb-b252-5459b4352486','珠','丁謂','宋','宋诗','song-poetry','','[]','寶氣媚長潯，明光法大陰。',48,'全唐诗/poet.song.5000.json','["寶氣媚長潯，明光法大陰。", "探龍殊九品，剖蚌盡千金。", "漢女飛昇跡，鮫人感泣心。", "任輕從彈雀，魚目莫相侵。"]'),
('f4641b93-d1f3-4237-adc3-1457e4680c1d','酒','丁謂','宋','宋诗','song-poetry','','[]','淥蟻含柔旨，清醇泛烈芳。',48,'全唐诗/poet.song.5000.json','["淥蟻含柔旨，清醇泛烈芳。", "帝樽甘露醴，天宴碧霞漿。", "千釀富難敵，萬錢酬亦當。", "宜遵三爵禮，莫羨百壺章。"]'),
('c9e212db-2f24-4a96-aebc-a5d01eb1a3df','茶','丁謂','宋','宋诗','song-poetry','','[]','真上堪修貢，甘泉代飲醇。',48,'全唐诗/poet.song.5000.json','["真上堪修貢，甘泉代飲醇。", "劉崑求愈疾，陸納用延賓。", "顧渚傳芳久，灉湖擅價新。", "唐賢經譜內，未識建溪春。"]'),
('53c8c8f7-f868-41c5-b3bc-681d8cafb522','松','丁謂','宋','宋诗','song-poetry','','[]','君子憐無改，詩人賦有喬。',48,'全唐诗/poet.song.5000.json','["君子憐無改，詩人賦有喬。", "輕舟隨檜楫，深澗映山苗。", "偃蓋秦官遠，凌霜夏社遥。", "鶴棲知得地，柏悅見干霄。"]'),
('070e8f94-5ef6-410d-b4c1-05e27883871e','桂','丁謂','宋','宋诗','song-poetry','','[]','青紫間朱丹，三湘五嶺間。',48,'全唐诗/poet.song.5000.json','["青紫間朱丹，三湘五嶺間。", "充庖資爽口，泛酒助𨠑□。", "種色思圓月，叢生憶小山。", "郄枝曾入手，招隠更聊攀。"]'),
('4231fc50-eefb-47ad-bcd4-8b4fb07c8056','桐','丁謂','宋','宋诗','song-poetry','','[]','託質朝陽地，含芳改火時。',48,'全唐诗/poet.song.5000.json','["託質朝陽地，含芳改火時。", "錫圭裁細葉，栖鳳養深枝。", "雙樹憐銀井，孤生稱檿絲。", "龍門高百尺，梓漆讓華滋。"]'),
('abed1bd6-c8c5-47fb-8b04-69a12508e753','柳  其一','丁謂','宋','宋诗','song-poetry','','[]','楊柳鬰氤氳，金堤總翠氛。',48,'全唐诗/poet.song.5000.json','["楊柳鬰氤氳，金堤總翠氛。", "庭前花類雪，樓際葉如雲。", "列宿分龍影，芳池寫鳳文。", "短簫何以奏，攀折爲思君。"]'),
('1907d485-6c60-4a0b-ba3a-d943c44899ff','柳  其二','丁謂','宋','宋诗','song-poetry','','[]','客舍青青亂，名園鬰鬰斜。',48,'全唐诗/poet.song.5000.json','["客舍青青亂，名園鬰鬰斜。", "舊栽彭澤署，新植武昌家。", "翠幄隋堤密，金絲蜀道賒。", "狂夫少樊圃，有菀興無涯。"]'),
('8abdb373-b096-4fb7-a81e-393dce798589','蘭','丁謂','宋','宋诗','song-poetry','','[]','彼羨南陔子，其誰粉署郎。',48,'全唐诗/poet.song.5000.json','["彼羨南陔子，其誰粉署郎。", "渥丹承露彩，紺綠泛風光。", "屢結騷人佩，時飄鄭國香。", "何須尋九畹，十步即芬芳。"]'),
('e44c117d-10fe-4147-a83d-8b4cf447755d','菊','丁謂','宋','宋诗','song-poetry','','[]','陶令重時芳，鍾繇帝賫霶。',48,'全唐诗/poet.song.5000.json','["陶令重時芳，鍾繇帝賫霶。", "清香宜桂酒，冷艷壓萸房。", "羽客長生助，騷人夕落傷。", "郊原多似是，甘苦冀情詳。"]'),
('1a77286e-f970-44e4-b3f2-5d18433846c1','桃','丁謂','宋','宋诗','song-poetry','','[]','未展蓁蓁葉，先開灼灼華。',48,'全唐诗/poet.song.5000.json','["未展蓁蓁葉，先開灼灼華。", "武陵迷境域，御宿接煙霞。", "投我疇爲報，偷兒孰是家。", "春風南北起，別有洛陽花。"]'),
('fd80ad4c-3040-4e18-ac9f-bca2520e3ffb','李','丁謂','宋','宋诗','song-poetry','','[]','桃徑共無言，整冠防未然。',48,'全唐诗/poet.song.5000.json','["桃徑共無言，整冠防未然。", "折枝如薺苦，沉水若朱研。", "東苑瓊芳細，南居玉質堅。", "高穹指爲姓，合冠百嘉先。"]'),
('cbc96cba-830a-4672-be27-4659e280aa7e','梅','丁謂','宋','宋诗','song-poetry','','[]','瓊葉宮闈飾，瑶華樂府詞。',48,'全唐诗/poet.song.5000.json','["瓊葉宮闈飾，瑶華樂府詞。", "和羹資倚相，止渴濟全師。", "七實連三實，南枝對北枝。", "同心將紫蔕，長恐失芳時。"]'),
('55191ff3-cd20-4093-8d75-cd65629dcf96','梨','丁謂','宋','宋诗','song-poetry','','[]','真定如拳大，靈關爽口清。',48,'全唐诗/poet.song.5000.json','["真定如拳大，靈關爽口清。", "甘香朱蜜冷，脆破玉霜鳴。", "工苑司官屬，交枝播頌聲。", "誰知洛陽樹，海內佔先名。"]'),
('f88d8a43-08f1-4cf7-ad6f-f176a66930c1','蓮','丁謂','宋','宋诗','song-poetry','','[]','魚戲煙莖細，龜巢粉蕊新。',48,'全唐诗/poet.song.5000.json','["魚戲煙莖細，龜巢粉蕊新。", "縫裳憐遠客，開幕想嘉賓。", "千葉松風畔，雙花柳渚瀕。", "翠芳天宴得，誰假涉江人。"]'),
('dabe1fde-d383-4ef6-939b-8962c9fee46a','棗','丁謂','宋','宋诗','song-poetry','','[]','好植蓬萊樹，無凝枳棘姿。',48,'全唐诗/poet.song.5000.json','["好植蓬萊樹，無凝枳棘姿。", "鷄心藏密葉，羊角出高枝。", "外炳丹朱彩，中含石蜜滋。", "何當如尹令，見食玉文時。"]'),
('8a6d1463-0e04-470c-b182-fbbbfb41d110','橘','丁謂','宋','宋诗','song-poetry','','[]','綠枳憐同氣，黄橙共我鄉。',48,'全唐诗/poet.song.5000.json','["綠枳憐同氣，黄橙共我鄉。", "厥包堪任土，其實可憐霜。", "天宴交枝異，君門並蔕祥。", "湘人無菲陋，曾用薦陶唐。"]'),
('0302ff3a-2525-4bc9-81fd-83a2c8c31a05','瓜','丁謂','宋','宋诗','song-poetry','','[]','綿瓞憐同蔕，鋤耰莫誤芸。',48,'全唐诗/poet.song.5000.json','["綿瓞憐同蔕，鋤耰莫誤芸。", "浮泉滋紺質，巾綌透清芬。", "積石三年熟，瑶池五色文。", "靜思空洞美，寧問邵平君。"]'),
('85bba339-30b6-4484-930a-fbf0d5f53623','草','丁謂','宋','宋诗','song-poetry','','[]','葭茁迎春早，山芮得地高。',48,'全唐诗/poet.song.5000.json','["葭茁迎春早，山芮得地高。", "堪書同細带，入詠似青袍。", "弱力綿綿葛，微香蓼蓼莪。", "王孫何處在，楚思徧江皋。"]'),
('da94670a-0213-4043-81ad-5f8303cf3600','琴','丁謂','宋','宋诗','song-poetry','','[]','材妙嶧陽枝，絃調野繭絲。',48,'全唐诗/poet.song.5000.json','["材妙嶧陽枝，絃調野繭絲。", "清音飛雉操，雅曲白駒詩。", "屬意山水際，寄聲鸞鳳時。", "南薰如在御，忠義必傾思。"]'),
('f2cf37dc-0743-478e-b0d8-765e86a93a24','瑟','丁謂','宋','宋诗','song-poetry','','[]','軒后更張妙，羲和舊制存。',48,'全唐诗/poet.song.5000.json','["軒后更張妙，羲和舊制存。", "絙絃參廟樂，疏越薦犧樽。", "趙女宣孤憤，湘靈寫斷魂。", "仲由無雅吹，何必鼓丘門。"]'),
('379e6ea7-0ccc-4f93-b9a9-66978212fbbe','簫','丁謂','宋','宋诗','song-poetry','','[]','莊籟知天理，虞韶見帝心。',48,'全唐诗/poet.song.5000.json','["莊籟知天理，虞韶見帝心。", "輕清楊柳曲，和樂鳳凰音。", "翼展編筠密，中虛鏤玉深。", "吳門休鼓腹，仙侶好追尋。"]'),
('dbc92892-391a-40a3-8ed4-d8c080f30e2e','嵩嶽聞笙','丁謂','宋','宋诗','song-poetry','','[]','煙篠裁圓直，霜匏鏤密深。',48,'全唐诗/poet.song.5000.json','["煙篠裁圓直，霜匏鏤密深。", "雅將鏞間奏，清與磬同音。", "隋作工何妙，媧傳制可尋。", "師夔如審曲，知我發生心。"]'),
('2b57e953-0f62-4407-8aef-6b972d398708','笛','丁謂','宋','宋诗','song-poetry','','[]','衡陽裁翠簳，夢澤剪霜柯。',48,'全唐诗/poet.song.5000.json','["衡陽裁翠簳，夢澤剪霜柯。", "妙制非丘仲，知音賞列和。", "賦因懷舊得，曲爲寫情多。", "三弄青溪側，風流奈爾何。"]'),
('ab6fdc7a-9392-4466-b395-6f5a2e9dd5d7','鼓','丁謂','宋','宋诗','song-poetry','','[]','未辨吳宮鷺，誰收駱越銅。',48,'全唐诗/poet.song.5000.json','["未辨吳宮鷺，誰收駱越銅。", "抑揚三今內，和樂五音中。", "美玉隨天仗，靈夔集帝功。", "雷門休冒布，方叔笑愚聾。"]'),
('e3d14441-2b06-4080-80e6-6158663a5a0a','棋','丁謂','宋','宋诗','song-poetry','','[]','不假分曹進，非同博塞游。',48,'全唐诗/poet.song.5000.json','["不假分曹進，非同博塞游。", "謝安方料敵，祖納正忘憂。", "窺豹仙枰晝，迷風石海秋。", "金門誰國手，一局賭宣州。"]'),
('f7947c05-6e23-45d4-bc5c-124a267c5a65','紙','丁謂','宋','宋诗','song-poetry','','[]','妙製剡溪人，多名錦水春。',48,'全唐诗/poet.song.5000.json','["妙製剡溪人，多名錦水春。", "卷疑方絮重，開覺露桃新。", "左氏三都貴，張芝徑寸珍。", "謝公如就乞，九萬一纖塵。"]'),
('8238bcbb-80eb-4d23-a617-0435330aafdc','筆','丁謂','宋','宋诗','song-poetry','','[]','霜距金犀利，煙毫枳棘銛。',48,'全唐诗/poet.song.5000.json','["霜距金犀利，煙毫枳棘銛。", "綠沉裁鏤管，翠羽飾雕奩。", "几格朱黄雜，臺牀竹素兼。", "古今資日用，錯綜盡洪纖。"]'),
('b550f718-1f1a-4fe2-a351-ab0ef7187860','船','丁謂','宋','宋诗','song-poetry','','[]','積羽貽深戒，爲梁藉衆材。',48,'全唐诗/poet.song.5000.json','["積羽貽深戒，爲梁藉衆材。", "採菱浮苑囿，鳴鶴泛池臺。", "雲映孤篷去，潮隨兩槳回。", "南風鸜鵒艗，知是故人來。"]'),
('e7e5ab3a-0df0-4069-b882-290e25656184','車','丁謂','宋','宋诗','song-poetry','','[]','任重材惟美，多工制不僭。',48,'全唐诗/poet.song.5000.json','["任重材惟美，多工制不僭。", "七香參鶴駕，五色間鸞軒。", "沙路茱萸輞，香風翡翠轅。", "莫矜流水妙，須畏叔孫言。"]'),
('e5624b58-f008-4940-b63d-8f316ebb663e','弓','丁謂','宋','宋诗','song-poetry','','[]','天道弛張中，爲箕學有宗。',48,'全唐诗/poet.song.5000.json','["天道弛張中，爲箕學有宗。", "六材皆妙物，三制盡良工。", "招我見詩意，遺人觀禮容。", "弨兮辭且美，帝賚示疇庸。"]'),
('0d6db83e-3d72-4764-a737-d2c1f62b68ac','射','丁謂','宋','宋诗','song-poetry','','[]','五善貴和容，榮觀萃澤宮。',48,'全唐诗/poet.song.5000.json','["五善貴和容，榮觀萃澤宮。", "循聲知得禮，上列見多功。", "盡志三正內，矜能一發中。", "無輕秉籌者，百中出羣公。"]'),
('51b2b955-809f-421e-9eef-e29ce8c637ac','劍','丁謂','宋','宋诗','song-poetry','','[]','漢室千金重，耶溪百鍊精。',48,'全唐诗/poet.song.5000.json','["漢室千金重，耶溪百鍊精。", "干星彰利器，出水示神兵。", "斬佞朱雲志，留亡季札情。", "何須麾晉鄭，自有倚天名。"]'),
('76a998ac-92e4-4caf-ab80-fb5ada2ba4b5','刀','丁謂','宋','宋诗','song-poetry','','[]','庖刀多餘地，鉛銛信可嗟。',48,'全唐诗/poet.song.5000.json','["庖刀多餘地，鉛銛信可嗟。", "割雞譏邑政，買犢勵田家。", "鞞䩬窮華妙，龍熊辨等差。", "學操言可復，呂贈意無涯。"]'),
('21308704-3e40-461d-a8c4-c8df4880a0c1','印','丁謂','宋','宋诗','song-poetry','','[]','示信流千古，頒榮徧萬方。',48,'全唐诗/poet.song.5000.json','["示信流千古，頒榮徧萬方。", "帝緘金縷細，天印玉文長。", "雀馬嚴君政，龜蛇辨國章。", "何當携棗篆，回首謝銀黄。"]'),
('c88e59f7-ddec-43e5-bce4-96c78a19a8b8','詠簾','丁謂','宋','宋诗','song-poetry','','[]','南楚佳名舊，西都妙製稀。',48,'全唐诗/poet.song.5000.json','["南楚佳名舊，西都妙製稀。", "風輕摇美璧，香細透明機。", "翠羽翻羅幄，龍文壓錦帷。", "蘭宮將桂殿，日用覺光輝。"]'),
('04e95957-28d9-4d43-bc14-391be468d4bd','詠席','丁謂','宋','宋诗','song-poetry','','[]','著位時專絕，鋪筵罄恪恭。',48,'全唐诗/poet.song.5000.json','["著位時專絕，鋪筵罄恪恭。", "魯堂曾子避，漢殿戴憑重。", "黼繡矜華靡，莞茅助禮容。", "軒皇膺帝錫，瑶彩映昂顒。"]'),
('dd80ccf8-8c36-4920-9273-a062c75407de','鼎','丁謂','宋','宋诗','song-poetry','','[]','妙盡三才象，精皆九貢金。',48,'全唐诗/poet.song.5000.json','["妙盡三才象，精皆九貢金。", "克商遷洛邑，興漢出汾陰。", "郜賂慙非道，秦求愧醜心。", "觀銘知考甫，傴僂戒何深。"]'),
('6cecb7f0-f947-4d6f-8947-90eeb01cb356','鏡','丁謂','宋','宋诗','song-poetry','','[]','外寫龍鸞質，中含日月輝。',48,'全唐诗/poet.song.5000.json','["外寫龍鸞質，中含日月輝。", "帝家金錯重，人世玉榮稀。", "掩匣隋珠秘，開奩趙璧歸。", "不須矜百鍊，軒鑑洞幽微。"]'),
('b7193796-c846-45ae-aa11-659520cf7147','扇','丁謂','宋','宋诗','song-poetry','','[]','雲母功無比，蒲葵用有餘。',48,'全唐诗/poet.song.5000.json','["雲母功無比，蒲葵用有餘。", "九華曹植賦，六角右軍書。", "皎皎蟾輪薄，蕭蕭雉尾疏。", "曾窺五明伏，鶴羽映鸞車。"]'),
('ff5a9a14-e538-450c-a740-d8265af77a39','燭','丁謂','宋','宋诗','song-poetry','','[]','影抱銅芝直，光摇鑄鳳圓。',48,'全唐诗/poet.song.5000.json','["影抱銅芝直，光摇鑄鳳圓。", "叢花生木蓼，凝蜜墮金蓮。", "積貨徒供爨，當官竟不燃。", "曾窺司烜氏，明燧奉高天。"]'),
('268a60cd-3bba-406c-aa77-cf5bbfb0fa87','地','丁謂','宋','宋诗','song-poetry','','[]','著象本沉潛，成形莫我厭。',48,'全唐诗/poet.song.5000.json','["著象本沉潛，成形莫我厭。", "秉陰彰至信，厚載示流謙。", "右轉羣生遂，東頃萬壑兼。", "寰區今底定，不用八龍占。"]'),
('74e6dd3e-bb5c-4031-9187-04d2445f0129','橋','丁謂','宋','宋诗','song-poetry','','[]','鞭石滔滔遠，填烏歲歲新。',48,'全唐诗/poet.song.5000.json','["鞭石滔滔遠，填烏歲歲新。", "七星橫巨浸，半月映長津。", "永固騫崩勢，終無揭厲因。", "時逢題柱客，不見脫輈人。"]'),
('9758364d-56f3-468a-b540-86193be30587','山','丁謂','宋','宋诗','song-poetry','','[]','不起纖塵讓，寧辭一簣勞。',48,'全唐诗/poet.song.5000.json','["不起纖塵讓，寧辭一簣勞。", "始從拳石大，終致極天高。", "蓮頂觀歸馬，蓬壺見負鼇。", "器車呈上瑞，繩檢秘崇褒。"]'),
('5634d73d-e326-4476-991a-3edf4304da81','江','丁謂','宋','宋诗','song-poetry','','[]','楚望爲南紀，岷源始濫觴。',48,'全唐诗/poet.song.5000.json','["楚望爲南紀，岷源始濫觴。", "雙流沿蜀道，九派出潯陽。", "桃葉行歌遠，芙蓉摘採長。", "衝風休破浪，靜練正交光。"]'),
('db021d7e-36e1-41e5-b1b5-c08edeb684f3','河','丁謂','宋','宋诗','song-poetry','','[]','擘華鑿龍傾，長源接杳冥。',48,'全唐诗/poet.song.5000.json','["擘華鑿龍傾，長源接杳冥。", "潤應逾九里，清必契千齡。", "箭浪奔霆電，滎光焰日星。", "聖皇圖奧事，真祖有祥經。"]'),
('0af2e36d-b75a-4e83-9d53-da2393af7653','海','丁謂','宋','宋诗','song-poetry','','[]','積潤容零露，無涯任酌蠡。',48,'全唐诗/poet.song.5000.json','["積潤容零露，無涯任酌蠡。", "浮空長浴日，表聖不揚波。", "江漢源流衆，蕃夷島嶼多。", "客槎如可泛，咫尺是星河。"]'),
('be02d4bb-0138-42b6-a0d3-ac52e28dfac8','竹','丁謂','宋','宋诗','song-poetry','','[]','自保猗猗綠，誰憐冉冉根。',48,'全唐诗/poet.song.5000.json','["自保猗猗綠，誰憐冉冉根。", "紫花含鳳實，繡籜抱龍孫。", "掃月仙壇靜，摇風雪霧昏。", "彤竿思化杖，紺葉想開樽。"]'),
('ce95b40c-f6de-4815-a664-b4016427f346','鳳','丁謂','宋','宋诗','song-poetry','','[]','舞穴標祥異，巢阿表盛明。',48,'全唐诗/poet.song.5000.json','["舞穴標祥異，巢阿表盛明。", "靈音諧律本，綵羽應陽精。", "去必翔千仞，來皆叶九成。", "上林堪飲啄，竹密醴泉清。"]'),
('30601aad-30eb-49f5-9000-9699ac14aaf9','鶴','丁謂','宋','宋诗','song-poetry','','[]','警露青冥外，沖天食息間。',48,'全唐诗/poet.song.5000.json','["警露青冥外，沖天食息間。", "金衣游太液，玉羽下緱山。", "松見千年偃，丹知九轉還。", "雲心在蓬閬，枝粒不相關。"]'),
('ea01d066-5a6b-40d6-8144-873ac18be50f','鶑','丁謂','宋','宋诗','song-poetry','','[]','刷羽幽棲地，啼春上苑間。',48,'全唐诗/poet.song.5000.json','["刷羽幽棲地，啼春上苑間。", "金衣何睍睆，簧舌苦綿蠻。", "百囀情無及，遷喬迥莫攀。", "可憐求友意，出谷便關關。"]'),
('b3667751-4005-4d18-bb8b-c9e8db17e739','燕','丁謂','宋','宋诗','song-poetry','','[]','受署司分氏，開祥簡狄心。',48,'全唐诗/poet.song.5000.json','["受署司分氏，開祥簡狄心。", "風簾雖易偶，巢幕亦難任。", "兩兩差池羽，翩翩下上音。", "曲江何感憤，託意動微吟。"]'),
('37f0dfed-1d98-411a-9e35-5769417c841e','雀','丁謂','宋','宋诗','song-poetry','','[]','飲啄遶藩籬，無聲乏羽儀。',48,'全唐诗/poet.song.5000.json','["飲啄遶藩籬，無聲乏羽儀。", "銜環誠可念，穿屋奈終卑。", "鴻鵠非予忖，鸞皇不汝欺。", "莫輕蟬飲露，挾彈鎮相隨。"]'),
('cf8603ac-b1da-45c6-8f4b-0b1d87474d5b','烏','丁謂','宋','宋诗','song-poetry','','[]','仁里徊翔久，層巢返哺頻。',48,'全唐诗/poet.song.5000.json','["仁里徊翔久，層巢返哺頻。", "九雛依百峙，三足託重輪。", "聲爲空營樂，心因止屋馴。", "夜啼休度曲，丹白瑞無倫。"]'),
('7e0bc8ff-3f70-4220-a4ba-13746561de48','鵲','丁謂','宋','宋诗','song-poetry','','[]','匣照光芒裏，熏爐想像間。',48,'全唐诗/poet.song.5000.json','["匣照光芒裏，熏爐想像間。", "營巢登大歲，採粟上仙山。", "玉璞驚心起，星河盡力還。", "上林無限樹，枯枿莫登攀。"]'),
('98544079-64ab-4a85-94e6-1ee7199f8726','鷹','丁謂','宋','宋诗','song-poetry','','[]','心極鵬摶遠，形將鶚立孤。',48,'全唐诗/poet.song.5000.json','["心極鵬摶遠，形將鶚立孤。", "尚慙同隼擊，寧肯截鴛雛。", "六翮風雷疾，雙骹枳棘枯。", "大蒐如展禮，聊用助三驅。"]'),
('2816fe32-d9b9-4ded-b082-42e77664acba','雁','丁謂','宋','宋诗','song-poetry','','[]','避繳非無意，隨陽自有期。',48,'全唐诗/poet.song.5000.json','["避繳非無意，隨陽自有期。", "飛霜聯伯仲，叫月應壎箎。", "小雅宣王什，登歌武帝辭。", "青冥時矯翼，燕雀爾焉知。"]'),
('02398e67-927d-4ab2-a55d-adf07e7cb86b','雉','丁謂','宋','宋诗','song-poetry','','[]','雉操揚琴奏，名翬拂扇塵。',48,'全唐诗/poet.song.5000.json','["雉操揚琴奏，名翬拂扇塵。", "其文伊洛地，厥貢越裳人。", "幾爲郎官集，還因今邑馴。", "山梁時飲啄，媒翳莫朝親。"]'),
('23efc215-b187-447f-864b-c64bd95e5fcc','雞','丁謂','宋','宋诗','song-poetry','','[]','戒旦知霄漏，棲塒識晚陽。',48,'全唐诗/poet.song.5000.json','["戒旦知霄漏，棲塒識晚陽。", "花冠誠可愛，芥羽亦難防。", "祝祝時求友，咬咬獨擅場。", "自當陳玉質，寧止化陳倉。"]'),
('b76360d3-4bd3-4bea-8f63-eecf8bbef1bb','麟','丁謂','宋','宋诗','song-poetry','','[]','魯史標嘉瑞，周詩頌太平。',48,'全唐诗/poet.song.5000.json','["魯史標嘉瑞，周詩頌太平。", "屢遊靈畤地，數立紀年名。", "矩步規行跡，含仁抱義情。", "盛時期在囿，五緯想儲精。"]'),
('ca99c485-65d8-414e-9c8e-e2f7880df1b3','熊','丁謂','宋','宋诗','song-poetry','','[]','高山多蟄獸，爾族載聲詩。',48,'全唐诗/poet.song.5000.json','["高山多蟄獸，爾族載聲詩。", "趙夢膺天命，周畋得帝師。", "當前忠至矣，碎掌果於斯。", "好俟東胡獻，神靈錫祐時。"]'),
('80ee0740-5312-491f-b679-3422bca1ff7f','虎','丁謂','宋','宋诗','song-poetry','','[]','雄文彰炳變，麟史載於菟。',48,'全唐诗/poet.song.5000.json','["雄文彰炳變，麟史載於菟。", "莫負編鬚勇，須懷履尾虞。", "恥將豺共棄，忍與兕爲徒。", "嘯谷非威怒，風從懾萬夫。"]'),
('918d885f-076a-45c1-8f53-aca0dfbf58f9','狼','丁謂','宋','宋诗','song-poetry','','[]','出必彰明盛，來當表慶隆。',48,'全唐诗/poet.song.5000.json','["出必彰明盛，來當表慶隆。", "野心知楚子，疐尾見周公。", "仲德牽衣惠，烏孫飼乳功。", "金行鍾粹白，冬獻莫雷同。"]'),
('a7201af8-f58d-4072-a267-c29ba1f6ecad','豹','丁謂','宋','宋诗','song-poetry','','[]','炳蔚西方美，羣居即谷陰。',48,'全唐诗/poet.song.5000.json','["炳蔚西方美，羣居即谷陰。", "人文窮燮妙，將略取名深。", "飾用千金直，韜藏七日心。", "會當窺落落，莫向管中尋。"]'),
('f2ce737c-5f19-4651-88fa-2d06bb6c92c9','象','丁謂','宋','宋诗','song-poetry','','[]','教戰誠無敵，充庭實可嘉。',48,'全唐诗/poet.song.5000.json','["教戰誠無敵，充庭實可嘉。", "指蹤知拜處，服習認葩花。", "遠視慙剛鬣，深藏惜素牙。", "十牛雖此夭，可奈可巴蛇。"]'),
('0204bfff-c627-4b7f-8fd1-25783a66c971','犀','丁謂','宋','宋诗','song-poetry','','[]','食野甘榆棘，乘流接海鯨。',48,'全唐诗/poet.song.5000.json','["食野甘榆棘，乘流接海鯨。", "駭雞稱國寶，辟水得天名。", "巴浦千年跡，黄支萬里程。", "至循來禁籞，六擾莫心驚。"]'),
('d50456ea-1cb5-453a-a5c4-9918002d8ce4','猿','丁謂','宋','宋诗','song-poetry','','[]','行不傷田畝，饑無壞果林。',48,'全唐诗/poet.song.5000.json','["行不傷田畝，饑無壞果林。", "渡雲連臂飲，宿月擁條吟。", "愈疾知調氣，消憂學定心。", "沐猴多損物，遠矣莫相侵。"]'),
('c3338aae-6803-4831-82b1-76819974fb2c','鹿','丁謂','宋','宋诗','song-poetry','','[]','賦命斯千載，登仙託五雲。',48,'全唐诗/poet.song.5000.json','["賦命斯千載，登仙託五雲。", "發祥呈玉質，標異冠星文。", "食薦時鳴野，遊林或命羣。", "白環何日至，真祖有前聞。"]'),
('508cc884-0784-4e9b-8bba-576f7cb8647e','兔','丁謂','宋','宋诗','song-poetry','','[]','三窟同蜫蟄，平岡若電驅。',48,'全唐诗/poet.song.5000.json','["三窟同蜫蟄，平岡若電驅。", "爰爰依枳棘，肅肅避罝罦。", "已得思烹犬，其亡尚守株。", "何當華桂畔，宿月翫雲衢。"]'),
('565fe529-5557-4b30-b78b-a7b75c73819a','狐','丁謂','宋','宋诗','song-poetry','','[]','安問謝張綱，依憑恃堞長。',48,'全唐诗/poet.song.5000.json','["安問謝張綱，依憑恃堞長。", "獲三當戰狩，用一勝千羊。", "冰渡憂濡尾，風嗥樂在梁。", "莫言無粹白，九尾薦佳祥。"]'),
('779c10f8-7be3-4c6b-9a37-73162b0a7e22','牛','丁謂','宋','宋诗','song-poetry','','[]','服箱譏睆彼，其耳動來思。',48,'全唐诗/poet.song.5000.json','["服箱譏睆彼，其耳動來思。", "不負葭芻惠，終成稼穡資。", "瑩蹄知愛矣，騂角肯忘之。", "好放桃林野，銷兵是此時。"]'),
('7c11013c-3d10-4d8a-aa04-b4037dab9c3f','馬','丁謂','宋','宋诗','song-poetry','','[]','蹀躞追風足，權奇汗血軀。',48,'全唐诗/poet.song.5000.json','["蹀躞追風足，權奇汗血軀。", "沙丘逢駿骨，澣海得名駒。", "天驥千金直，龍媒萬里途。", "王良如在銜，下駟敢前驅。"]'),
('04dbcf15-d4c3-47d8-bc00-f3861bce8301','羊','丁謂','宋','宋诗','song-poetry','','[]','千足比侯封，矜矜莫可窮。',48,'全唐诗/poet.song.5000.json','["千足比侯封，矜矜莫可窮。", "觸藩難進退，荷箠易西東。", "鄭伯牽降辱，初平叱化功。", "律和當薦瑞，願牧上林中。"]'),
('1f81bfcb-992c-44a6-a5d6-60dd88bd330a','龍','丁謂','宋','宋诗','song-poetry','','[]','不操千金寶，思觀九色虯。',48,'全唐诗/poet.song.5000.json','["不操千金寶，思觀九色虯。", "負圖鍾上聖，銜燭照窮幽。", "但仰飛天大，寧聞戰野憂。", "沃焦須霈澤，莫道我無求。"]'),
('b37d97d6-ef6b-49e0-9870-57de77b714eb','魚  其一','丁謂','宋','宋诗','song-poetry','','[]','戲葉復依蒲，登龍是去途。',48,'全唐诗/poet.song.5000.json','["戲葉復依蒲，登龍是去途。", "何煩垂翡翠，未肯畏鵜鶘。", "已負吞舟大，終無涸轍虞。", "濠梁寧足樂，相忘在江湖。"]'),
('bd761371-305c-4b4f-8a52-7128726911d5','魚  其二','丁謂','宋','宋诗','song-poetry','','[]','江湖各相忘，魚蝦同一波，樂哉樂哉。',34,'全唐诗/poet.song.5000.json','["江湖各相忘，魚蝦同一波，樂哉樂哉。", "莫貪釣上餌，去□鼎中羹，戎哉戎哉。"]'),
('93bb1cd9-e0c4-47fd-af0c-435cde962219','龜','丁謂','宋','宋诗','song-poetry','','[]','居蔡推神物，巢蓮表聖君。',48,'全唐诗/poet.song.5000.json','["居蔡推神物，巢蓮表聖君。", "膺期千歲色，垂世九疇文。", "惠向銜珠辨，靈從顧印分。", "自諳宮沼樂，錫貢任江濱。"]'),
('3a4ecb7d-24ec-4b24-b74c-5eef356a36da','蛇','丁謂','宋','宋诗','song-poetry','','[]','起蟄良時在，鳴風異稟存。',48,'全唐诗/poet.song.5000.json','["起蟄良時在，鳴風異稟存。", "大能吞巨象，長可遶崑崙。", "出笥彰嘉慶，銜珠報厚恩。", "由來稟龍質，靈化出山門。"]'),
('7c6a87bc-e579-49e2-9acf-752c4a73d83e','螢','丁謂','宋','宋诗','song-poetry','','[]','蘭畹炎飈息，莎階霽景凉。',48,'全唐诗/poet.song.5000.json','["蘭畹炎飈息，莎階霽景凉。", "宵征循屋漏，晝伏避陽光。", "具體微雨顯，餘輝有若亡。", "惟憐資學者，熠燿滿紗囊。"]'),
('ed90bab4-095c-4430-9ebb-8db30f67632b','蝶','丁謂','宋','宋诗','song-poetry','','[]','熠耀非吾族，蠨蛸莫我知。',48,'全唐诗/poet.song.5000.json','["熠耀非吾族，蠨蛸莫我知。", "韓憑飛處妬，莊叟夢時疑。", "瓊玉含芳細，絲篁度曲遲。", "自當同羽化，蟬范任冠緌。"]'),
('ea93fd95-32ba-4e4e-8e1b-008225b5f64e','蟬','丁謂','宋','宋诗','song-poetry','','[]','齊女幽憂後，幽時興詠中。',48,'全唐诗/poet.song.5000.json','["齊女幽憂後，幽時興詠中。", "曉寒初飲露，夕燥正含風。", "翼若裁綃薄，心如鼓橐空。", "貂冠如見用，清白勵王公。"]'),
('ceb472ec-7da4-48e7-8036-f5bbd18fd3b0','樓','丁謂','宋','宋诗','song-poetry','','[]','幾集元規會，曾留子建題。',48,'全唐诗/poet.song.5000.json','["幾集元規會，曾留子建題。", "東南當日出，西北與雲齊。", "帝里五百尺，仙家十二梯。", "吹簫多感激，丹鳳竟相携。"]'),
('7478141a-9d76-40f7-bcd6-4a2136dfa2bb','臺','丁謂','宋','宋诗','song-poetry','','[]','不效燕昭置，終貽子罕羞。',48,'全唐诗/poet.song.5000.json','["不效燕昭置，終貽子罕羞。", "吳都矜四達，楚國炫三休。", "好卜登春樂，無增累卵憂。", "玄都有瓊構，何日從真遊。"]'),
('0aa17390-ba61-4814-aeac-b246067a60b1','窗','丁謂','宋','宋诗','song-poetry','','[]','玉女潛窺久，偷兒竊覘頻。',48,'全唐诗/poet.song.5000.json','["玉女潛窺久，偷兒竊覘頻。", "綺疏環禁掖，青瑣近嚴宸。", "靜聽翰音異，遥觀列岫新。", "好開虛白室，雲母若冰輪。"]'),
('c12961e1-6864-483f-9229-c591deba8ddb','書','丁謂','宋','宋诗','song-poetry','','[]','始向龜圖妙，爰從鳥跡成。',48,'全唐诗/poet.song.5000.json','["始向龜圖妙，爰從鳥跡成。", "偃波如制妙，例薤更難精。", "蔡表崩雲重，曹章綴露輕。", "憶曾思刻玉，瓊簡鏤金英。"]'),
('c4846e70-27b5-4032-9da4-dc7ae1d5034a','句  其一','丁謂','宋','宋诗','song-poetry','','[]','鷹鶻騰雙眼，龍蛇繞四肢。',12,'全唐诗/poet.song.5000.json','["鷹鶻騰雙眼，龍蛇繞四肢。"]'),
('7afee660-8401-4c70-9e4f-61754a8c4f38','句  其二','丁謂','宋','宋诗','song-poetry','','[]','背裝花屈膝，白打大廉斯。',24,'全唐诗/poet.song.5000.json','["背裝花屈膝，白打大廉斯。", "進前行兩步，蹺後立多時。"]'),
('c36f989e-8268-438c-ac74-a063590445a0','句  其三','丁謂','宋','宋诗','song-poetry','','[]','珊瑚新筆架，雲母舊屏風。',12,'全唐诗/poet.song.5000.json','["珊瑚新筆架，雲母舊屏風。"]'),
('f79fbc35-f12c-4138-bfdc-cc78d60d77d1','句  其四','丁謂','宋','宋诗','song-poetry','','[]','梅花過嶺路，桃葉渡江船。',12,'全唐诗/poet.song.5000.json','["梅花過嶺路，桃葉渡江船。"]'),
('3de03e32-dd16-470f-a0d8-b8473e09cf8d','句  其五','丁謂','宋','宋诗','song-poetry','','[]','泣珠泉客通關市，種玉仙翁寄版圖。',16,'全唐诗/poet.song.5000.json','["泣珠泉客通關市，種玉仙翁寄版圖。"]'),
('224fedd6-4f07-404d-9343-ab0f6875002a','句  其六','丁謂','宋','宋诗','song-poetry','','[]','楚子夢雲鈴閣密，郢人歌雪射堂開。',16,'全唐诗/poet.song.5000.json','["楚子夢雲鈴閣密，郢人歌雪射堂開。"]'),
('38698f69-a57a-4abc-b88d-83454de0df0e','句  其七','丁謂','宋','宋诗','song-poetry','','[]','九萬里鵬重出海，一千年鶴再歸巢。',16,'全唐诗/poet.song.5000.json','["九萬里鵬重出海，一千年鶴再歸巢。"]'),
('9fb154a8-f260-454c-a347-c2470012625b','句  其八','丁謂','宋','宋诗','song-poetry','','[]','千金家累非良寶，一品高官是强名。',16,'全唐诗/poet.song.5000.json','["千金家累非良寶，一品高官是强名。"]'),
('21b7fdbc-db9d-4af6-8bba-f5bf9efe327e','句  其九','丁謂','宋','宋诗','song-poetry','','[]','內翰拜時髭擊地。',8,'全唐诗/poet.song.5000.json','["內翰拜時髭擊地。"]'),
('0e41c560-b775-4aca-ae01-da4b7be51346','句  其一○','丁謂','宋','宋诗','song-poetry','','[]','吾皇寬大容尸素，乞與江城不計年。',16,'全唐诗/poet.song.5000.json','["吾皇寬大容尸素，乞與江城不計年。"]'),
('367ed232-3724-4a33-b8c0-1636b312893f','句  其一一','丁謂','宋','宋诗','song-poetry','','[]','物華如陣筆如鋒，沈謝曹劉是七雄。',16,'全唐诗/poet.song.5000.json','["物華如陣筆如鋒，沈謝曹劉是七雄。"]'),
('036b20d7-e507-4f83-8e1d-87f7b80a8f88','句  其一二','丁謂','宋','宋诗','song-poetry','','[]','鶑驚鳳輦穿花去，魚畏龍顔上釣遲。',16,'全唐诗/poet.song.5000.json','["鶑驚鳳輦穿花去，魚畏龍顔上釣遲。"]'),
('22b04694-b289-4f2f-aa41-ebac982a3dc5','句  其一三','丁謂','宋','宋诗','song-poetry','','[]','戴歸雙綵勝，就賜五辛盤。',12,'全唐诗/poet.song.5000.json','["戴歸雙綵勝，就賜五辛盤。"]'),
