('1d479d3b-9c66-4609-b266-2e4df145b6f2','句  其三二','丁謂','宋','宋诗','song-poetry','','[]','吹開吹落任東風。',8,'全唐诗/poet.song.5000.json','["吹開吹落任東風。"]'),
('31e5b1a9-8d47-4933-bd53-8e720aa4f667','句  其三三','丁謂','宋','宋诗','song-poetry','','[]','清香誰許比荼蘼。',8,'全唐诗/poet.song.5000.json','["清香誰許比荼蘼。"]'),
('c4227b29-00ec-4828-9458-2596227544dc','句  其三四','丁謂','宋','宋诗','song-poetry','','[]','水邊遥見久停橈。',8,'全唐诗/poet.song.5000.json','["水邊遥見久停橈。"]'),
('877c249c-5ef0-4709-acaa-37bd2aa22f7e','憶越州  其一','薛奎','宋','宋诗','song-poetry','','[]','照湖方干吟格高，搜清研奇含爛毫。',32,'全唐诗/poet.song.5000.json','["照湖方干吟格高，搜清研奇含爛毫。", "天中無雲水中月，虛明晶曜忘迴舠。"]'),
('735fbd87-aa87-4085-9dc8-bb1755b3442e','憶越州  其二','薛奎','宋','宋诗','song-poetry','','[]','千巖萬壑爭清奇，天地靈秀應無遺。',32,'全唐诗/poet.song.5000.json','["千巖萬壑爭清奇，天地靈秀應無遺。", "吟舟恐在碧霄上，湖心澄波涵月時。"]'),
('8fff985b-e65e-45c0-bf3a-66700a0964c0','寄金繩院正因大師','薛奎','宋','宋诗','song-poetry','','[]','僧中憶藝本超羣，釋氏蒙求見討論。',64,'全唐诗/poet.song.5000.json','["僧中憶藝本超羣，釋氏蒙求見討論。", "儒行合爲文暢侶，詩名雅作貫休孫。", "心燈久已傳宗意，命服仍嘗錫帝恩。", "宴坐栴檀消篆字，眼前闤闠任囂喧。"]'),
('86559fbc-a417-464a-aa5a-e65dfbdfda06','句  其一','薛奎','宋','宋诗','song-poetry','','[]','囊書空自負，早晚達明君。',12,'全唐诗/poet.song.5000.json','["囊書空自負，早晚達明君。"]'),
('6ed002c6-f90c-40aa-9671-d188304509eb','句  其二','薛奎','宋','宋诗','song-poetry','','[]','千林如有喜，一氣自無私。',12,'全唐诗/poet.song.5000.json','["千林如有喜，一氣自無私。"]'),
('d7ab4b06-4be5-4929-8066-0011be7697ed','仙遊亭詩贈丁晉公','劉遁','宋','宋诗','song-poetry','','[]','屢在仙遊亭上醉，仙遊洞裏杳無人。',32,'全唐诗/poet.song.5000.json','["屢在仙遊亭上醉，仙遊洞裏杳無人。", "他時鳴鶴歸滄海，同看蓬萊島上春。"]'),
('807e2d1e-28cf-4188-b546-2903786b96a8','遊峽山飛來寺','高紳','宋','宋诗','song-poetry','','[]','古寺清江上，維舟夕照前。',48,'全唐诗/poet.song.5000.json','["古寺清江上，維舟夕照前。", "山根盤到海，塔影直侵天。", "蘿月空禪石，霜鐘落客船。", "秋風懶回首，送目入雲煙。"]'),
('413181e0-4d03-45f0-9773-e08b2d62747b','詠華林書院','高紳','宋','宋诗','song-poetry','','[]','元秀峰前累世居，聖朝旌表振門閭。',64,'全唐诗/poet.song.5000.json','["元秀峰前累世居，聖朝旌表振門閭。", "四方來客多登第，一邑爲儒喜讀書。", "詩閣夜聞吟木狖，水亭晴見戲荷魚。", "石嬌華表溪山裏，晚景寒烟盡不如。"]'),
('e206c19a-fbaf-4168-a365-e513cdf5d9d9','句','李南陽','宋','宋诗','song-poetry','','[]','朝馮玉几言猶在，夜啟金縢事已非。',16,'全唐诗/poet.song.5000.json','["朝馮玉几言猶在，夜啟金縢事已非。"]'),
('0276b5b2-5c51-4757-a958-a170f78618f3','存目  其一','李湛','宋','宋诗','song-poetry','','[]','詩題：永慶寺首句：巖扉開早凉。',15,'全唐诗/poet.song.5000.json','["詩題：永慶寺首句：巖扉開早凉。"]'),
('0f57a9a6-968f-4f39-8025-dcf1d9dd505b','存目  其二','李湛','宋','宋诗','song-poetry','','[]','詩題：遊頂破二山凈居院首句：入門松桂深。',20,'全唐诗/poet.song.5000.json','["詩題：遊頂破二山凈居院首句：入門松桂深。"]'),
('f8b8916a-6d9e-4e13-8269-a4b9bfe3973d','存目  其三','李湛','宋','宋诗','song-poetry','','[]','詩題：破山興福寺首句：雲門十里長。',17,'全唐诗/poet.song.5000.json','["詩題：破山興福寺首句：雲門十里長。"]'),
('edea50b7-014e-4488-b541-c6bf0894208e','至道初元六月不雨爲民冒暑乞靈龍湫投辭未竟雲氣已作雷雨繼之','王挺之','宋','宋诗','song-poetry','','[]','欲呼雲雨沃焦田，裊裊籃輿入翠煙。',64,'全唐诗/poet.song.5000.json','["欲呼雲雨沃焦田，裊裊籃輿入翠煙。", "萬仞孤高隨鳥道，一潭澄碧快龍眠。", "浮丘黄帝真成道，漢武秦皇謾學僊。", "但願甘霖慰枯槁，豈知衰朽得神憐。"]'),
('daa7bbe8-8c51-42f4-872e-8b837e039cc6','題黄山二首  其一','王挺之','宋','宋诗','song-poetry','','[]','疊巘障南國，攢峰頂半空。',48,'全唐诗/poet.song.5000.json','["疊巘障南國，攢峰頂半空。", "朝昏長見日，晴晦預知風。", "樹枿千年在，嵐光四面通。", "名山今日睹，奇秀兩無窮。"]'),
('c51f4f2e-70c7-4e31-a5e5-3390e3f93d61','題黄山二首  其二','王挺之','宋','宋诗','song-poetry','','[]','地靈通十洞，山邃宅諸僊。',48,'全唐诗/poet.song.5000.json','["地靈通十洞，山邃宅諸僊。", "怪似龍逢霹，高疑劍倚天。", "巖端鎖丹竈，石罅逗溫泉。", "却憶登樓堞，徒能見巨然。"]'),
('b34d67d9-8a53-48c1-8023-29c7f7205c26','句','李夷庚','宋','宋诗','song-poetry','','[]','生公曾說法，聽石尚孱頑。',28,'全唐诗/poet.song.5000.json','["生公曾說法，聽石尚孱頑。", "雁塔晴觀海，松門夜閉山。", "林喧羣。"]'),
('ed6b3352-1b19-48a9-b53d-ab670d78aba1','句','釋修己','宋','宋诗','song-poetry','','[]','羊腸鳥道無人到，寂寞雲中一箇人。',16,'全唐诗/poet.song.5000.json','["羊腸鳥道無人到，寂寞雲中一箇人。"]'),
('477c37af-fd45-4bff-b3ce-737edfc578f1','賞花釣魚侍宴應制','姚鉉','宋','宋诗','song-poetry','','[]','上苑烟花迥不同，漢皇何必幸回中。',64,'全唐诗/poet.song.5000.json','["上苑烟花迥不同，漢皇何必幸回中。", "花枝冷濺昭陽雨，釣線斜牽太液風。", "綺萼惹衣朱檻近，錦鱗隨手玉波空。", "小臣侍宴驚凡目，知是蓬萊第幾宮。"]'),
('4aa4c983-7275-4a80-9992-d797f309ee54','曹娥廟碑','姚鉉','宋','宋诗','song-poetry','','[]','簫鼓聲中浪渺瀰，古楓陰砌蘚封碑。',32,'全唐诗/poet.song.5000.json','["簫鼓聲中浪渺瀰，古楓陰砌蘚封碑。", "行人到此自恭肅，不似巫山雲雨祠。"]'),
('450313b8-7a10-4566-aaf4-9d5b434502aa','翻經臺','姚鉉','宋','宋诗','song-poetry','','[]','康樂悟玄機，寂寥此棲息。',24,'全唐诗/poet.song.5000.json','["康樂悟玄機，寂寥此棲息。", "經翻貝葉文，臺近蓮華石。"]'),
('44de3b75-0399-47b8-b1f1-804ac857a457','過松江','姚鉉','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','句吳奇勝絕無儔，更見松江八月秋。',64,'全唐诗/poet.song.5000.json','["句吳奇勝絕無儔，更見松江八月秋。", "震澤波光連別派，洞庭山影落中流。", "汀蘆擁雪藏魚市，岸橘風香趁客舟。", "清興不窮聊一望，烟空雲霽倚層樓。"]'),
('b0918ca7-3899-4397-bf29-7ffef4e1622c','冷泉亭','姚鉉','宋','宋诗','song-poetry','','[]','水石一欄桿，僧歸四山靜。',24,'全唐诗/poet.song.5000.json','["水石一欄桿，僧歸四山靜。", "携琴譜澗泉，月浸夜深冷。"]'),
('f924ca6e-8d5a-4611-bff8-b5d4be038a6d','句','姚鉉','宋','宋诗','song-poetry','','[]','疏鐘天竺曉，一鴈海門秋。',12,'全唐诗/poet.song.5000.json','["疏鐘天竺曉，一鴈海門秋。"]'),
('e8c22951-22f3-4acf-ac8b-c47d32ecaeb7','內香藥庫詩贊','宋真宗','宋','宋诗','song-poetry','','[]','每歲沉檀來遠裔，累朝珠玉實皇居。',32,'全唐诗/poet.song.5000.json','["每歲沉檀來遠裔，累朝珠玉實皇居。", "今辰內府初開處，充牣尤宜史筆書。"]'),
('3bf77262-fcaa-4f24-978e-3716cb14b379','賜神童蔡伯禧','宋真宗','宋','宋诗','song-poetry','','[]','七閔山水多才俊，三歲奇童出盛時。',64,'全唐诗/poet.song.5000.json','["七閔山水多才俊，三歲奇童出盛時。", "家世應傳清白訓，嬰兒自得老成資。", "初嘗學步來朝謁，方及能言解誦詩。", "更勵孜孜圖進益，青雲千里有前期。"]'),
('1fc327d9-4d78-4b3c-b4c6-4bc1e8e867fe','賜楊億判秘監','宋真宗','宋','宋诗','song-poetry','','[]','瑣闥往年司制誥，共嘉藻思類相如。',64,'全唐诗/poet.song.5000.json','["瑣闥往年司制誥，共嘉藻思類相如。", "蓬山今日詮墳史，還仰多聞過仲舒。", "報政列城歸覲後，疏恩高閣拜官初。", "諸生濟濟彌瞻望，鉛槧諮詢辨魯魚。"]'),
('e6202e0e-79c4-478d-aa6c-28e742d0194c','批楊億謝表','宋真宗','宋','宋诗','song-poetry','','[]','承明近侍究儒玄，苦學勞心疾已痊。',32,'全唐诗/poet.song.5000.json','["承明近侍究儒玄，苦學勞心疾已痊。", "善保興居調飲食，副予前席待多賢。"]'),
('7e609eb9-91ce-42f9-950c-e27b4977c019','賜道人鄭隠歸山','宋真宗','宋','宋诗','song-poetry','','[]','盡日臨流看水色，有時隠几聽松聲。',32,'全唐诗/poet.song.5000.json','["盡日臨流看水色，有時隠几聽松聲。", "徧遊萬壑成嘉遁，偶出千峰翫治平。"]'),
('0879c492-852d-483b-be41-92811c77980c','賜丁謂','宋真宗','宋','宋诗','song-poetry','','[]','懿辭碩畫播朝中，造膝詢謀禮遇豐。',64,'全唐诗/poet.song.5000.json','["懿辭碩畫播朝中，造膝詢謀禮遇豐。", "文石延登彰順美，高牙前導表疇庸。", "書生仗鉞今尤貴，舊里分符古罕逢。", "晝錦買臣安敢比，黄樞早日接從容。"]'),
('a3408255-9ef5-4b43-9dcc-83eb82454564','又','宋真宗','宋','宋诗','song-poetry','','[]','踐歷功皆著，諮詢務必成。',120,'全唐诗/poet.song.5000.json','["踐歷功皆著，諮詢務必成。", "懿才符曩彥，佳器貫時英。", "俾展經綸業，旋陞輔弼榮。", "嘉亨忻盛遇，盡瘁罄純誠。", "均逸明恩洽，疇勞茂典行。", "白麻三殿曉，紅斾九衢平。", "雖輟凝嚴任，尤增倚注情。", "擁旄辭帝闕，頓轡望都城。", "風景高秋月，煙波幾舍程。", "想卿懷感意，常是夢神京。"]'),
('d05d5db2-0846-420a-9813-51ff9073c877','賜僧義澄','宋真宗','宋','宋诗','song-poetry','','[]','止觀心地法，色相本皆空。',24,'全唐诗/poet.song.5000.json','["止觀心地法，色相本皆空。", "禪慧明宗性，超然萬法中。"]'),
('3b517a31-235c-46f5-bd10-603656dd0b3f','賜知貢舉晁迥','宋真宗','宋','宋诗','song-poetry','','[]','禮闈選士古稱難，都爲陞沉咫尺間。',32,'全唐诗/poet.song.5000.json','["禮闈選士古稱難，都爲陞沉咫尺間。", "較藝清時公道在，掄材應得惠人寰。"]'),
('fdb56707-b188-4669-ba81-52ee20f22b4f','又','宋真宗','宋','宋诗','song-poetry','','[]','盛時選士貢闈開，殿宇聞風獻藝來。',32,'全唐诗/poet.song.5000.json','["盛時選士貢闈開，殿宇聞風獻藝來。", "心似權衡求實效，勿教蓬蓽有遺才。"]'),
('1d8b0957-6795-4ab1-8bc7-b26b3e457e58','賜知貢舉錢惟演','宋真宗','宋','宋诗','song-poetry','','[]','寅奉昌圖紹慶基，選掄多士叶前規。',96,'全唐诗/poet.song.5000.json','["寅奉昌圖紹慶基，選掄多士叶前規。", "鄉閭薦拔期無濫，草澤搜羅詎有遺。", "德舉況逢全盛日，計偕咸造廣場時。", "春官任職當求善，宗伯掄材務得宜。", "侍從名儒當委任，藝文公道辯妍媸。", "佇伸衡鑑裁深念，允協菁莪樂育詩。"]'),
('049795ee-dd14-4ad9-90ee-799c2772d376','又將放榜','宋真宗','宋','宋诗','song-poetry','','[]','四海爲家寶緒隆，旁求文雅振儒風。',96,'全唐诗/poet.song.5000.json','["四海爲家寶緒隆，旁求文雅振儒風。", "命鄉隨計來多士，較藝掄材有澤宮。", "簪紱近臣當顯任，絲綸深旨論丹衷。", "旰宵汲汲予存念，夙夜孜孜爾徇公。", "名實豈惟衡鑑內，賢能皆萃網羅中。", "佇觀翹楚登時用，布政分憂協庶功。"]'),
('e5256b5b-3245-4c40-b398-7d7abd6598e2','賜王欽若除太子太保判杭州十韻','宋真宗','宋','宋诗','song-poetry','','[]','早自外朝登近侍，克符昌運振嘉名。',160,'全唐诗/poet.song.5000.json','["早自外朝登近侍，克符昌運振嘉名。", "一參黄閣推良畫，再陟鴻樞顯至榮。", "該博古今堂獻納，勤勞夙夜每專精。", "石渠撰述多文備，日觀封崇大禮成。", "宰府調元心匪懈，真宮兼職望彌清。", "龍樓進秩恩尤異，熊軾爲藩任不輕。", "二浙奧區期惠化，三吳佳致悅高情。", "重重山水舟中見，處處壺漿陌上迎。", "既肅邇遐安外域，更分宵旰撫黎氓。", "予衷側席方毗倚，佇有甘棠播頌聲。"]'),
('f1eec377-ba1c-4bf3-8f38-625e2d0e2feb','送張無夢歸天台山','宋真宗','宋','宋诗','song-poetry','','[]','混元爲教合醇精，視之無迹聽無聲。',96,'全唐诗/poet.song.5000.json','["混元爲教合醇精，視之無迹聽無聲。", "唯有達人臻此理，逍遥物外事沈冥。", "浮雲舒卷絕常勢，流水方圓靡定形。", "乘興偶然辭澗戶，談真俄爾謁王庭。", "順風已是聞宗旨，枕石還期適性情。", "玉帛簪纓非所重，長歌聊復寵歸程。"]'),
('d5610a03-269f-4259-8ab0-6795efe61b41','賜古藏用','宋真宗','宋','宋诗','song-poetry','','[]','海霞照灼散青烟，歷歷星榆在曉天。',32,'全唐诗/poet.song.5000.json','["海霞照灼散青烟，歷歷星榆在曉天。", "松韻寒烟絕世態，鶴翔高頂應鳴絃。"]'),
('f1959edd-c689-4e63-8c2c-f402d56a11ff','海棠  其一','宋真宗','宋','宋诗','song-poetry','','[]','春律行將半，繁枝忽競芳。',48,'全唐诗/poet.song.5000.json','["春律行將半，繁枝忽競芳。", "霏霏含宿霧，灼灼艷朝陽。", "戲蝶棲輕蕊，遊蜂逐遠香。", "物華留賦詠，非獨務雕章。"]'),
('3327e13b-ccd6-4186-a597-047658c69f84','海棠  其二','宋真宗','宋','宋诗','song-poetry','','[]','翠萼凌晨綻，清香逐處飄。',48,'全唐诗/poet.song.5000.json','["翠萼凌晨綻，清香逐處飄。", "高低臨曲檻，紅白間纖條。", "潤比攢溫玉，繁如簇絳綃。", "盡堪圖畫取，名筆在僧繇。"]'),
('dc933540-6c51-4b51-8106-5b402f018e17','觀龍歌','宋真宗','宋','宋诗','song-poetry','','[]','四靈之長惟虬龍，虬龍變化故難同。',162,'全唐诗/poet.song.5000.json','["四靈之長惟虬龍，虬龍變化故難同。", "三茅福地羣仙宅，靈物潛形在此中。", "池內仙人馴擾得，至今隠現誰能測。", "乘雲蠢動獨標奇，行雨嘉生皆荷力。", "常人競取暫從心，才出山楹兮無處尋。", "中使勤求深有意，欲獻明庭兮陳上瑞。", "初獻一龍朝魏闕，偶挹二龍離洞穴。", "人心龍心若符契，一去一住何神異。", "我睹真龍幸不驚，至誠祝龍龍好聽。", "但祈風雨年年順，庶使倉箱處處盈。"]'),
('2c4b8201-fe62-47db-8f90-1f2009ba907a','佛牙讚','宋真宗','宋','宋诗','song-poetry','','[]','西方大聖號迦文，接物垂慈世所尊。',32,'全唐诗/poet.song.5000.json','["西方大聖號迦文，接物垂慈世所尊。", "常願進修增妙果，庶期饒益在黎元。"]'),
('c9fd1054-a1a7-4e49-a19c-74f17199cbf0','北征回鑾詩','宋真宗','宋','宋诗','song-poetry','','[]','銳旅懷忠節，群胡竄北荒。',36,'全唐诗/poet.song.5000.json','["銳旅懷忠節，群胡竄北荒。", "堅冰銷巨浪，輕吹集隹祥。", "繼好安邊境，和同樂小康。"]'),
('8b8cc626-9121-4e41-8fe0-40c19bb688f1','賜陳堯叟謝病歸濟源','宋真宗','宋','宋诗','song-poetry','','[]','文苑垂清譽，朝端仰盛才。',72,'全唐诗/poet.song.5000.json','["文苑垂清譽，朝端仰盛才。", "嘉猷毗萬路，奇遇列三台。", "勤職興居爽，辭榮奏疏來。", "疇咨登百揆，異數冠中臺。", "巨屏揚旌去，名藩晝錦回。", "君臣相厚意，瞻望兩徘徊。"]'),
('04c5134b-6f95-451c-93db-613cbb6b4ee2','賜詹騤','宋真宗','宋','宋诗','song-poetry','','[]','名閱誇詹氏，新居古五雲。',48,'全唐诗/poet.song.5000.json','["名閱誇詹氏，新居古五雲。", "擢科魁衆士，拔萃喜超羣。", "禮肅人畏敬，臚傳世共聞。", "好將多錦繡，五色耀龍文。"]'),
('0c1e03dd-7607-48e6-92d9-9e5c8581184d','贊胡家','宋真宗','宋','宋诗','song-poetry','','[]','一門三刺史，四代五尚書。',24,'全唐诗/poet.song.5000.json','["一門三刺史，四代五尚書。", "他族未聞有，朕今止見胡。"]'),
('21dafa47-3bfb-42b2-adf0-81240f4ad35a','句  其一','宋真宗','宋','宋诗','song-poetry','','[]','該明聖典通今古，發啟沖年曉典常。',16,'全唐诗/poet.song.5000.json','["該明聖典通今古，發啟沖年曉典常。"]'),
('0935d3de-aacc-4713-b023-283b7c0a0071','句  其二','宋真宗','宋','宋诗','song-poetry','','[]','酣醉皮裘思晦跡，行高終自有人知。',16,'全唐诗/poet.song.5000.json','["酣醉皮裘思晦跡，行高終自有人知。"]'),
('c9ea7027-a069-4278-8618-21a3491392aa','句  其三','宋真宗','宋','宋诗','song-poetry','','[]','臣守但當守公法，馳騖苟進何可取。',16,'全唐诗/poet.song.5000.json','["臣守但當守公法，馳騖苟進何可取。"]'),
('0d27885c-fe44-40f6-ae59-cb33d85a3cdc','題淮陰侯廟','錢昆','宋','宋诗','song-poetry','','[]','築臺拜日恩雖厚，躡足封時慮已深。',32,'全唐诗/poet.song.5000.json','["築臺拜日恩雖厚，躡足封時慮已深。", "隆準早知同鳥喙，將軍應起五湖心。"]'),
('c5cd83c7-4611-434d-8688-d950e41dedc0','宿延慶院','錢昆','宋','宋诗','song-poetry','','[]','水繞門牆竹繞堂，滿窗春綠更山光。',64,'全唐诗/poet.song.5000.json','["水繞門牆竹繞堂，滿窗春綠更山光。", "坐來苔蘚侵衣潤，吟處松花落硯香。", "汀鷺雙雙翻亂石，溪風裊裊弄修篁。", "遊人暫得幽閑趣，時带茶烟下上方。"]'),
('9f05eb12-07a9-494e-8f53-dca566d76ff1','遊鐵岸','錢昆','宋','宋诗','song-poetry','','[]','晴紅烟綠襯虛亭，公退因來得野情。',32,'全唐诗/poet.song.5000.json','["晴紅烟綠襯虛亭，公退因來得野情。", "落日東風懶歸去，擬將薄祿換溪聲。"]'),
('b0a35694-cafc-448f-bcab-eb8318f72eed','夢越州小江','錢易','宋','宋诗','song-poetry','','[]','越布縫單衾，燈青月黄淺。',96,'全唐诗/poet.song.5000.json','["越布縫單衾，燈青月黄淺。", "精魂度江水，適去無近遠。", "濕沙平朔天，宿鳥踏古篆。", "巨潮淹積石，瘦白澀無蘚。", "櫓響期西陵，蒼岑屏曲展。", "夙齡賤登臨，今日生健羨。", "汀洲逢故妾，振袂指吳苑。", "向人呼舊官，血泣慚孤蹇。"]'),
('f0cefce3-e5d4-424f-b3ca-70c0de3e046d','覽越僧詩集有寄','錢易','宋','宋诗','song-poetry','','[]','莫學江淹擬惠休，碧雲才調已難酬。',48,'全唐诗/poet.song.5000.json','["莫學江淹擬惠休，碧雲才調已難酬。", "懷君知有關山夢，開卷如逢水石秋。", "不得歸來作都講，自慚名宦正悠悠。"]'),
('0d0bb5cd-5321-4b30-af18-b57f22d943bc','上巳至玉津園賜宴','錢易','宋','宋诗','song-poetry','','[]','祓禊標春巳，歌時慶魯雩。',72,'全唐诗/poet.song.5000.json','["祓禊標春巳，歌時慶魯雩。", "禁園宣密宴，玉饌賜天厨。", "班序參三殿，衣冠盛兩都。", "雲罍傾上席，寶馬鬧長衢。", "帝澤恩何重，春風節已徂。", "歸來白虎殿，微詠共操觚。"]'),
('b56b0422-08c6-4ecf-a047-ff79c8ed3e6c','初夏病中','錢易','宋','宋诗','song-poetry','','[]','抱病經清暑，空庭掃紫苔。',48,'全唐诗/poet.song.5000.json','["抱病經清暑，空庭掃紫苔。", "花籬妨蝶過，桐井引禽來。", "徒有文園渴，更有漳浦才。", "可憐餘滯骨，無復動心灰。"]'),
('04758a4c-b79e-4cf6-9b3f-1c88468e1e76','和人首夏池上雨中聞笛','錢易','宋','宋诗','song-poetry','','[]','朱華始沈泉，池塘恰雨天。',96,'全唐诗/poet.song.5000.json','["朱華始沈泉，池塘恰雨天。", "鷺頭飄雪暗，荷腹蕩珠圓。", "風遞誰家笛，聲衝幾里烟。", "拂波輕重起，隔樹往來傳。", "瀝瀝雖侵漢，遥遥已雜□。", "天龍吟轉樂，石韻更相連。", "謾讀襄王賦，虛誇子晉仙。", "寧同向散騎，腸斷向漪漣。"]'),
('26542c41-7d36-4009-ab92-0cf825110bcf','七夕作','錢易','宋','宋诗','song-poetry','','[]','天上人間重此宵，新情舊恨兩迢迢。',64,'全唐诗/poet.song.5000.json','["天上人間重此宵，新情舊恨兩迢迢。", "漢宮露密罘罳冷，秦殿燈深羯鼓焦。", "香粉溟濛篩綺席，蛛絲千萬絡煙霄。", "牽牛何事勞烏鵲，不使虹蜺駕作橋。"]'),
('04a2b7e7-f9a6-40f6-b221-53a2651c4ed9','中秋夜守讓南廳玩月','錢易','宋','宋诗','song-poetry','','[]','秋氣元清切，明蟾千里心。',48,'全唐诗/poet.song.5000.json','["秋氣元清切，明蟾千里心。", "金盤上河側，玉水浸樓陰。", "閨怨有消歇，客愁無淺深。", "關山今夜裏，星斗共沉沉。"]'),
('81cf72ee-f669-410c-befc-921a5541c3af','中秋','錢易','宋','宋诗','song-poetry','','[]','天慘嚴霜厚，神清宿雨微。',48,'全唐诗/poet.song.5000.json','["天慘嚴霜厚，神清宿雨微。", "枝空蟬擬脫，巢冷燕謀歸。", "白日蓮塘夢，紅紗水國衣。", "錦書知未了，軋軋弄鳴機。"]'),
('bb8f25cb-743d-4721-be9d-011edc310e25','嵇康小舞詞','錢易','宋','宋诗','song-poetry','','[]','薛九三十侍中郎，蘭香花態生春堂。',128,'全唐诗/poet.song.5000.json','["薛九三十侍中郎，蘭香花態生春堂。", "龍盤王氣變秋霧，淮聲哭月浮秋霜。", "宜城酒煙濕羈腹，與君强舞當時曲。", "玉樹遺辭莫重聽，黄塵染鬢無前綠。", "我聞襄陽白銅鞮，荒情古艷傳幽悲。", "淒凉不抵亡國恨，塵中苦淚飛柔絲。", "洛陽公子擎銀觴，跪奴和曲生輝光。", "茂陵旅夢無春草，彤管含羞裁短章。"]'),
('b169bd2b-80cd-4ae8-b258-ddb1bfef8ced','西遊曲','錢易','宋','宋诗','song-poetry','','[]','花銷秋老白日短，敗紅荒綠迷空館。',96,'全唐诗/poet.song.5000.json','["花銷秋老白日短，敗紅荒綠迷空館。", "擬將清血灑昭陵，幽谷蛇啼半山晚。", "十年辭家勤獻書，王孫不許延公車。", "江頭祖廟祭無血，重門生草寒離離。", "我有黄金三尺劍，姦骨無痕古波艷。", "佩入函關無故人，玉握凋零七星暗。"]'),
('e64bd685-f72a-4a0f-8e9f-5e6538874fb0','溫泉詩','錢易','宋','宋诗','song-poetry','','[]','悲哉天寶時，帝耄政不修。',240,'全唐诗/poet.song.5000.json','["悲哉天寶時，帝耄政不修。", "寵幸尊婦人，陰極陽已柔。", "外戚盛本枝，櫛比封列侯。", "丞相大將軍，備位甚悠悠。", "天下安既久，積漸力不周。", "車服金玉煥，黎庶饑寒愁。", "驪山溫泉宮，晝幸與夜遊。", "一遊百司備，萬費一日休。", "雖能心自快，化作神稷憂。", "國忠恣吞噬，林甫懷姦偷。", "胡雛據太原，鐘鼓無計收。", "黄塵滿長安，慘黷九廟羞。", "唐天未使絕，返正知疾瘳。", "自茲遊賞地，荆棘生荒秋。", "舊物悉已廢，蜘蛛挂重樓。", "覽者咸寒心，一過三迴頭。", "因知帝王業，堅固宣鴻猷。", "豈可信嗜欲，侮弄生瘡疣。", "雕牆峻宇誡，簡牘況有由。", "翻思黍離章，續之應可仇。"]'),
('105458b7-f480-4d96-ad4b-862849940b66','南兵','錢易','宋','宋诗','song-poetry','','[]','曾見南兵苦，征遼事亦如。',48,'全唐诗/poet.song.5000.json','["曾見南兵苦，征遼事亦如。", "金瘡寒長肉，紙甲雨生蛆。", "山小虀霜骨，河枯臛腐魚。", "黎元無處哭，丁戶日相疏。"]'),
('8f079c79-707e-49e9-b2e5-85e5a0b97748','習家池大堤','錢易','宋','宋诗','song-poetry','','[]','清風習池上，落日峴山西。',24,'全唐诗/poet.song.5000.json','["清風習池上，落日峴山西。", "使君來問俗，聽唱白銅鞮。"]'),
('b9f047a8-3ccb-4850-82e4-42519f0a545c','送張無夢歸天台','錢易','宋','宋诗','song-poetry','','[]','暫謁明光拂斗槎，杖蔾歸去赤城霞。',64,'全唐诗/poet.song.5000.json','["暫謁明光拂斗槎，杖蔾歸去赤城霞。", "琳宮重啟仙人室，金闕新辭太帝家。", "祇自運心奔白日，何須擲米作丹砂。", "雲章賜重崆峒遠，還向懸岑鍊五芽。"]'),
('1297c638-7c7c-4286-9f29-cd453b9291bd','送僧歸護國寺','錢易','宋','宋诗','song-poetry','','[]','拂衣台嶺舊林泉，命服蘭芽奪目鮮。',64,'全唐诗/poet.song.5000.json','["拂衣台嶺舊林泉，命服蘭芽奪目鮮。", "一念不居常在定，十分無悶盡安禪。", "霜含庭栢依稀老，月到經窗暗澹圓。", "蠛枕沈迷難話別，半橋衰柳鎖寒烟。"]'),
('6aee7888-a696-4afa-9063-ed31f4fed680','擬張籍上裴晉公','錢易','宋','宋诗','song-poetry','','[]','午橋莊上千竿竹，綠野堂中白日春。',64,'全唐诗/poet.song.5000.json','["午橋莊上千竿竹，綠野堂中白日春。", "富貴極來唯歎老，功名高後轉輕身。", "嚴更未報皇城裏，勝賞時遊洛水濱。", "昨日庭趨三節度，淮西曾是執戈人。"]'),
('0e9d0f0d-c222-4c6e-adac-326c08f52d7b','擬盧仝詩','錢易','宋','宋诗','song-poetry','','[]','門前飛楊花，屋後惡水鳴青蛙。',34,'全唐诗/poet.song.5000.json','["門前飛楊花，屋後惡水鳴青蛙。", "案上兩卷書，堯典與舜典，留與添丁作生涯。"]'),
('bbbf4680-21e6-4fbd-b459-81a2960b87ea','詠華林書院','錢易','宋','宋诗','song-poetry','','[]','旌表華林盛，儒官寄翠微。',48,'全唐诗/poet.song.5000.json','["旌表華林盛，儒官寄翠微。", "科名新伯仲，孝行舊光輝。", "雲影陰書幌，松花濕道衣。", "自慚方試吏，爭得去忘機。"]'),
('c3135109-2878-4a3d-8b91-64627d7b9746','蘆花','錢易','宋','宋诗','song-poetry','','[]','深溪高岸罩秋烟，颯颯江風向暮天。',32,'全唐诗/poet.song.5000.json','["深溪高岸罩秋烟，颯颯江風向暮天。", "凝潔月華臨靜夜，一叢叢蓋釣魚船。"]'),
('e7f9eee7-a222-41ff-868d-3811027d7538','句  其一','錢易','宋','宋诗','song-poetry','','[]','莫歎鬢如雪，且教心似灰。',12,'全唐诗/poet.song.5000.json','["莫歎鬢如雪，且教心似灰。"]'),
('a220655e-2ab2-4df6-8e8c-322a63723454','句  其二','錢易','宋','宋诗','song-poetry','','[]','世上何人號最忙，紫微失去張君房。',16,'全唐诗/poet.song.5000.json','["世上何人號最忙，紫微失去張君房。"]'),
('933773e5-acfb-40a6-9965-c3ae601d2b8c','句  其三','錢易','宋','宋诗','song-poetry','','[]','雙蜂上簾額，獨鵲裊庭柯。',12,'全唐诗/poet.song.5000.json','["雙蜂上簾額，獨鵲裊庭柯。"]'),
('810e1cfb-5f78-4736-bc24-070f7b90b8fa','句  其四','錢易','宋','宋诗','song-poetry','','[]','綠章封事緘初啟，青鳳求凰尾乍開。',16,'全唐诗/poet.song.5000.json','["綠章封事緘初啟，青鳳求凰尾乍開。"]'),
('031cb5af-8772-49fe-9ee8-20225a8b0d56','句  其五','錢易','宋','宋诗','song-poetry','','[]','子美無情甚，都官著意頻。',12,'全唐诗/poet.song.5000.json','["子美無情甚，都官著意頻。"]'),
('739623ba-f8e7-4924-af44-dabe3974d7d2','句  其六','錢易','宋','宋诗','song-poetry','','[]','好開今日太平基，萬里山河歸掌握。',16,'全唐诗/poet.song.5000.json','["好開今日太平基，萬里山河歸掌握。"]'),
('82c3e1ca-fb1f-4305-9db6-90d0c80833a5','湖樓晚望','林逋','宋','宋诗','song-poetry','','[]','湖水混空碧，憑闌凝睇勞。',48,'全唐诗/poet.song.5000.json','["湖水混空碧，憑闌凝睇勞。", "夕寒山翠重，秋凈鳥行高。", "遠意極千里，浮生輕一毫。", "叢林數未遍，杳靄隔漁舠。"]'),
('bf4c0de2-7c07-4bfe-b687-7507eaadf522','秋日西湖閒泛','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水氣并山影，蒼茫已作秋。',48,'全唐诗/poet.song.5000.json','["水氣并山影，蒼茫已作秋。", "林深喜見寺，岸靜惜移舟。", "疏葦先寒折，殘虹带夕收。", "吾廬在何處，歸興起漁謳。"]'),
('0f7fe8c9-154d-473a-b89a-36c8de00090a','上湖閒泛艤舟石函因過下湖小墅','林逋','宋','宋诗','song-poetry','','[]','平皋望不極，雲樹遠依依。',48,'全唐诗/poet.song.5000.json','["平皋望不極，雲樹遠依依。", "及向扁舟泊，還尋下瀨歸。", "青山連石埭，春水入柴扉。", "多謝提壺鳥，留人到落暉。"]'),
('870a0780-649f-40ea-a4e2-17077f812f2c','西湖舟中值雪','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','浩蕩彌空闊，霏霏接水濆。',48,'全唐诗/poet.song.5000.json','["浩蕩彌空闊，霏霏接水濆。", "舟移忽自却，山近未全分。", "凍軫間清泛，溫鑪接薄薰。", "悠然詠招隠，何許嘆離羣。"]'),
('a9f4e8c0-9de4-4bd6-ac7b-b92a8ced2c4d','西村晚泊','林逋','宋','宋诗','song-poetry','','[]','弭棹危橋外，霜村乍夕陰。',48,'全唐诗/poet.song.5000.json','["弭棹危橋外，霜村乍夕陰。", "田園向野水，樵採語空林。", "白鳥歸飛遠，青山重複深。", "那堪遲新月，誰復賞微吟。"]'),
('a073b50f-2343-4119-a69a-61e004fa39df','湖村晚興','林逋','宋','宋诗','song-poetry','','[]','滄洲白鳥飛，山影落晴暉。',48,'全唐诗/poet.song.5000.json','["滄洲白鳥飛，山影落晴暉。", "映竹犬初吠，弄舡人合歸。", "水波隨月動，林翠带烟微。", "寺近疏鐘起，蕭然還掩扉。"]'),
('6c37f390-62fa-4318-a2f5-94f4911e2241','湖山小隠  其一','林逋','宋','宋诗','song-poetry','','[]','猿鳥清絕，林蘿擁翠微。',47,'全唐诗/poet.song.5000.json','["猿鳥清絕，林蘿擁翠微。", "步穿僧徑出，肩搭道衣歸。", "水墅香菰熟，烟崖早笋肥。", "功名無一點，何要更忘機。"]'),
('af2b5bd0-a5d1-4fce-a77e-03331be66073','湖山小隠  其二','林逋','宋','宋诗','song-poetry','','[]','園井夾蕭森，紅芳墮翠陰。',48,'全唐诗/poet.song.5000.json','["園井夾蕭森，紅芳墮翠陰。", "晝岩松鼠靜，春塹竹鷄深。", "歲課非無秫，家藏獨有琴。", "顔原遺事在，千古壯閑心。"]'),
('f4073940-fdd1-482a-b845-6357346c8b5a','湖山小隠  其三','林逋','宋','宋诗','song-poetry','','[]','衡門鄰晚島，環堵背寒崗。',48,'全唐诗/poet.song.5000.json','["衡門鄰晚島，環堵背寒崗。", "片月通蘿徑，幽雲在石床。", "客遊拋鄠杜，漁事擬滄浪。", "管樂非吾尚，昂頭肯自方。"]'),
('abd7fe67-5106-4181-b307-21337ae8413e','小隠自題','林逋','宋','宋诗','song-poetry','','[]','竹樹繞吾廬，清深趣有餘。',48,'全唐诗/poet.song.5000.json','["竹樹繞吾廬，清深趣有餘。", "鶴閒臨水久，蜂懶採花疏。", "酒病妨開卷，春陰入荷鋤。", "嘗憐古圖畫，多半寫樵漁。"]'),
('f3cd1fa8-7675-4055-9216-af7271931a8c','小隠','林逋','宋','宋诗','song-poetry','','[]','門徑獨蕭然，山林屋舍邊。',48,'全唐诗/poet.song.5000.json','["門徑獨蕭然，山林屋舍邊。", "水風清晚釣，花日重春眠。", "苒苒苔衣滑，磷磷石子圓。", "人寰諸洞府，應合署閒仙。"]'),
('8fef5566-d7d3-4d58-8389-fae3ae77d59a','北山晚望','林逋','宋','宋诗','song-poetry','','[]','晚來山北景，圖畫亦應非。',48,'全唐诗/poet.song.5000.json','["晚來山北景，圖畫亦應非。", "村路飄黄葉，人家濕翠微。", "樵當雲外見，僧向水邊歸。", "一曲誰橫笛，蒹葭白鳥飛。"]'),
('564e6e6a-79b4-41d7-828f-c79ef78be7c3','中峰','林逋','宋','宋诗','song-poetry','','[]','中峰一徑分，盤折上幽雲。',48,'全唐诗/poet.song.5000.json','["中峰一徑分，盤折上幽雲。", "夕照前村見，秋濤隔嶺聞。", "長松含古翠，衰藥動微薰。", "自愛蘇門嘯，懷賢思不羣。"]'),
('5edb9fdd-f42d-43d5-8234-f47387258152','小圃春日','林逋','宋','宋诗','song-poetry','','[]','岸幘倚微風，柴籬春色中。',48,'全唐诗/poet.song.5000.json','["岸幘倚微風，柴籬春色中。", "草長團粉蝶，林暖墜青蟲。", "載酒爲誰子，移花獨乃翁。", "於陵偕隠事，清尚未相同。"]'),
('c1689b63-8180-4dfc-92f1-186f60f01d7e','春夕閒詠','林逋','宋','宋诗','song-poetry','','[]','屐齒徧庭深，時爲擁鼻吟。',48,'全唐诗/poet.song.5000.json','["屐齒徧庭深，時爲擁鼻吟。", "微風引竹籟，斜月轉花陰。", "靜賞應難極，孤懷自不禁。", "蒼然小池上，烟露達青岑。"]'),
('1bfecd7c-9b7b-429c-813e-fc3fcb3ee4c7','春日感懷','林逋','宋','宋诗','song-poetry','','[]','衡宇日蕭寂，高舂猶掩扉。',48,'全唐诗/poet.song.5000.json','["衡宇日蕭寂，高舂猶掩扉。", "春風似有舊，社燕亦重歸。", "覽照老已具，開樽人向稀。", "頹然此心曲，持底屬芳菲。"]'),
('d96c3e53-e840-4a10-b6ab-503147256375','郊園避暑','林逋','宋','宋诗','song-poetry','','[]','柴門鮮人事，氛垢頗相忘。',48,'全唐诗/poet.song.5000.json','["柴門鮮人事，氛垢頗相忘。", "愛彼林間靜，復茲池上凉。", "託心時散帙，遲客復携觴。", "況有陶籬趣，歸禽語夕陽。"]'),
('b7f1675c-3c93-41b8-907f-faea5b25431a','園廬秋夕','林逋','宋','宋诗','song-poetry','','[]','蘭杜裛衰香，開扉趣自長。',48,'全唐诗/poet.song.5000.json','["蘭杜裛衰香，開扉趣自長。", "寒烟宿墟落，清月上林塘。", "意想殊爲適，形骸固可忘。", "援琴有餘興，聊復寄吟觴。"]'),
('ae7f6a7a-72c6-47bb-9263-497a8391741a','山村冬暮','林逋','宋','宋诗','song-poetry','','[]','衡茅林麓下，春色已微茫。',48,'全唐诗/poet.song.5000.json','["衡茅林麓下，春色已微茫。", "雪竹低寒翠，風梅落晚香。", "樵期多獨往，茶事不全忙。", "雙鷺有時起，橫飛過野塘。"]'),
('40a60da9-423e-4093-a660-d29bf5810cd5','山中冬日','林逋','宋','宋诗','song-poetry','','[]','殘雪照籬落，空山無俗諠。',48,'全唐诗/poet.song.5000.json','["殘雪照籬落，空山無俗諠。", "雞寒懶下樹，人晏獨開門。", "廢圃春榮動，回塘霧氣昏。", "誰家歲酒熟，輟棹憶西村。"]'),
('abc133e7-c151-43fd-b709-ba03f26640be','旅館寫懷','林逋','宋','宋诗','song-poetry','','[]','垂成歸不得，危坐對滄浪。',48,'全唐诗/poet.song.5000.json','["垂成歸不得，危坐對滄浪。", "病葉驚秋色，殘蟬怕夕陽。", "可堪疏舊計，寧復更剛腸。", "的的孤峰意，深宵一夢狂。"]'),
('61e3fa2b-935f-44a6-ac60-d293b5b360cc','出曹川','林逋','宋','宋诗','song-poetry','','[]','詩懷動歎嗟，馿立帽陰斜。',48,'全唐诗/poet.song.5000.json','["詩懷動歎嗟，馿立帽陰斜。", "雨濼生新鹻，茅叢夾舊槎。", "午烟昏獨店，岡路透誰家。", "幾日江南興，扁舟泊岸沙。"]'),
('2e499724-6ef8-41b6-936e-80a024be6cc3','盱眙山寺','林逋','宋','宋诗','song-poetry','','[]','下傍盱眙縣，山崖露寺門。',48,'全唐诗/poet.song.5000.json','["下傍盱眙縣，山崖露寺門。", "疏鐘過淮口，一徑入雲根。", "竹老生虛籟，池清見古源。", "高僧拂經榻，茶話到黄昏。"]'),
('6fa9dd9f-e2ae-40ae-b530-bcfda5c6c0ed','留題李頡林亭','林逋','宋','宋诗','song-poetry','','[]','兼琴枕鶴經，盡日卧林亭。',48,'全唐诗/poet.song.5000.json','["兼琴枕鶴經，盡日卧林亭。", "啼鳥自相語，幽人誰欲聽。", "半闌花籍白，一徑草盤青。", "何必對樽酒，此中堪獨醒。"]'),
('356efd77-9045-459a-9888-a6146c399beb','翠微亭','林逋','宋','宋诗','song-poetry','','[]','亭在江干寺，清凉更翠微。',48,'全唐诗/poet.song.5000.json','["亭在江干寺，清凉更翠微。", "秋階響松子，雨壁上苔衣。", "絕境長難得，浮生不擬歸。", "旅懷何計是，西崦入斜暉。"]'),
('40bbfa60-3c65-4736-8022-942b3bcc0263','臺城寺水亭','林逋','宋','宋诗','song-poetry','','[]','金井前朝事，林僧問不知。',48,'全唐诗/poet.song.5000.json','["金井前朝事，林僧問不知。", "綠苔欺破閣，白鳥占閒池。", "清楚曾經晉，荒唐直到隋。", "南廊一聲磬，斜照獨凝思。"]'),
('725476ce-2bed-4cb1-bfdf-a81b0866853c','汴岸曉行','林逋','宋','宋诗','song-poetry','','[]','馿僕劍裝輕，尋河早早行。',48,'全唐诗/poet.song.5000.json','["馿僕劍裝輕，尋河早早行。", "孤烟開道店，平野喝農耕。", "老木迴堤暗，初陽出浪明。", "羈遊事無盡，塵土拂吾纓。"]'),
('950b1731-f061-4043-a9f7-385c493f9aaf','淮甸南遊','林逋','宋','宋诗','song-poetry','','[]','幾許摇鞭興，淮天晚景中。',48,'全唐诗/poet.song.5000.json','["幾許摇鞭興，淮天晚景中。", "樹林兼雨黑，草實著霜紅。", "膽氣誰憐俠，衣裝自笑戎。", "寒威敢相掉，獵獵酒旗風。"]'),
('ca1d06b4-d2fe-4bf8-947e-10b48ca12741','聞葉初秀才東歸','林逋','宋','宋诗','song-poetry','','[]','高鴻多北向，極目雨餘天。',48,'全唐诗/poet.song.5000.json','["高鴻多北向，極目雨餘天。", "春滿吳山樹，人登汴水船。", "吟生千里月，醉盡一囊錢。", "肯便懷鄉邑，時清復少年。"]'),
('20f0cef6-d5aa-43f2-bc4e-43abea4587e8','病中謝馮彭年見訪','林逋','宋','宋诗','song-poetry','','[]','老去已多病，況當梅雨時。',48,'全唐诗/poet.song.5000.json','["老去已多病，況當梅雨時。", "山空門自掩，晝永枕頻移。", "晚燕巢猶濕，新篁籜未披。", "若非求仲至，誰復問棲遲。"]'),
('bd342299-c540-4d90-b945-d334b67521a4','冬日衛樞至','林逋','宋','宋诗','song-poetry','','[]','冷話復長吟，俱非俗者心。',48,'全唐诗/poet.song.5000.json','["冷話復長吟，俱非俗者心。", "空齋留並宿，幾度夢相尋。", "鳥亂槐枝折，烟微雪氣侵。", "如何急前去，羸馬萬山深。"]'),
('7acc4f01-3798-4b76-8f20-e733d0ee167a','偶書','林逋','宋','宋诗','song-poetry','','[]','閒看是斯文，無秦擬自焚。',48,'全唐诗/poet.song.5000.json','["閒看是斯文，無秦擬自焚。", "病來兼萬事，休去負深雲。", "直語時多忌，幽腸俗不分。", "如何麋與鹿，猶此傍人羣。"]'),
('504f3503-ac0d-41c2-9a66-87ae1453f1dc','中峰行樂却望北山因而成詠','林逋','宋','宋诗','song-poetry','','[]','拂石玩林壑，曠然空色秋。',48,'全唐诗/poet.song.5000.json','["拂石玩林壑，曠然空色秋。", "歸雲带層巘，疏葦際滄洲。", "固自堪長往，何爲難久留。", "庶將濠上想，聊作剡中遊。"]'),
('2ec35cb7-7e5e-4dc7-8773-3c7af168d446','將歸四明夜坐話別任君','林逋','宋','宋诗','song-poetry','','[]','酒酣相向坐，別泪濕吟衣。',48,'全唐诗/poet.song.5000.json','["酒酣相向坐，別泪濕吟衣。", "半夜月欲落，千山人憶歸。", "亂塵終古在，長瀑倚雲飛。", "明日重携手，前期易得違。"]'),
('6facc741-8aeb-48f3-8aec-5ebfc4ab00ca','和梅聖俞雪中同虛白上人來訪','林逋','宋','宋诗','song-poetry','','[]','湖上玩佳雪，相將惟道林。',48,'全唐诗/poet.song.5000.json','["湖上玩佳雪，相將惟道林。", "早烟村意遠，春漲岸痕深。", "地僻過三徑，人閑試五禽。", "歸橈有餘興，寧復比山陰。"]'),
('97a4732c-c40c-4d9d-a8df-eeaf05ae4872','和黄亢與季父見訪','林逋','宋','宋诗','song-poetry','','[]','積水凝懸館，船寬或結樓。',48,'全唐诗/poet.song.5000.json','["積水凝懸館，船寬或結樓。", "一窗方寄傲，二巷忽同遊。", "怨慕採菱曲，蒼茫拾翠洲。", "微風起蘋末，歸路滿清愁。"]'),
('d78cefbb-fe86-49e2-89a8-afd680be2e5d','和史宮贊','林逋','宋','宋诗','song-poetry','','[]','門對遠岑青，常時亦懶扃。',48,'全唐诗/poet.song.5000.json','["門對遠岑青，常時亦懶扃。", "久貧慚嗜酒，多病負窮經。", "鶴迹秋偏靜，松陰午欲亭。", "蜀莊何足問，惟解事沉冥。"]'),
('063883d3-ece3-4093-b6ed-1306bde252be','和天竺慈雲大師','林逋','宋','宋诗','song-poetry','','[]','林表飛來色，猶憐久卜鄰。',48,'全唐诗/poet.song.5000.json','["林表飛來色，猶憐久卜鄰。", "沿洄一水路，夢想五天人。", "謝絕空園草，沉冥滿几塵。", "暮雲如有得，寧謝寄聲頻。"]'),
('77c5e462-118f-4842-8a00-604fa352c01f','和朱仲方送然社師無爲還歷陽','林逋','宋','宋诗','song-poetry','','[]','歸路過東關，行行一錫間。',48,'全唐诗/poet.song.5000.json','["歸路過東關，行行一錫間。", "破林霜後月，孤寺水邊山。", "頂笠衝殘葉，腰裝歇暮灣。", "香燈舊吟社，清思逐師還。"]'),
('e7a22c4c-e4a3-4bc2-a749-bde497dd5a57','和酬杜從事題壁','林逋','宋','宋诗','song-poetry','','[]','弭蓋入衡宇，相看情獨深。',48,'全唐诗/poet.song.5000.json','["弭蓋入衡宇，相看情獨深。", "蕭疏秋樹色，老大故人心。", "佳話頻移晷，清飆幾拂襟。", "寥然長卿壁，題此比兼金。"]'),
('e51007b4-5da4-40c7-b9f2-9cb55b4c5417','夏日寺居和酬葉次公','林逋','宋','宋诗','song-poetry','','[]','午日猛如焚，清凉愛寺軒。',48,'全唐诗/poet.song.5000.json','["午日猛如焚，清凉愛寺軒。", "鶴毛橫蘚陣，蟻穴入莎根。", "社信題茶角，樓衣笐酒痕。", "中餐不勞問，筍菊凈盤罇。"]'),
('afea3499-d736-4c69-b8d8-29bcfcdd4eff','僧院夏日和酬朱仲方','林逋','宋','宋诗','song-poetry','','[]','一院掩蕭森，晨凉又夕陰。',48,'全唐诗/poet.song.5000.json','["一院掩蕭森，晨凉又夕陰。", "鶴應輸靜立，蟬合伴清吟。", "著壁雲衣重，通簾竹翠深。", "卧屏來看否，天姥雪千尋。"]'),
('83f60bb2-3cb1-4fc5-9ab4-486ffc02c0a2','送長吉上人','林逋','宋','宋诗','song-poetry','','[]','囊集暮雲篇，行行肯廢禪。',48,'全唐诗/poet.song.5000.json','["囊集暮雲篇，行行肯廢禪。", "青山買未暇，朱闕去隨緣。", "茗試幽人井，香焚賈客船。", "淮流遲新月，吟玩想忘眠。"]'),
('925b8184-9397-41b7-9f51-a7ac1608ec9f','懷長吉上人北遊','林逋','宋','宋诗','song-poetry','','[]','青山日已遠，香裓漸多塵。',48,'全唐诗/poet.song.5000.json','["青山日已遠，香裓漸多塵。", "應愛淮流上，聊逢月色新。", "孤禪安逆旅，警句語誰人。", "復有傷離客，中林病過春。"]'),
('e03d2a12-b285-4167-b957-55dd9c4b9332','春日送袁成進士北歸','林逋','宋','宋诗','song-poetry','','[]','春潮上海門，歸雁遠行分。',48,'全唐诗/poet.song.5000.json','["春潮上海門，歸雁遠行分。", "千里倦行客，片帆還送君。", "酒波欺碧草，歌疊裊晴雲。", "來歲東堂桂，聊酬一戰勛。"]'),
('d66df61e-508b-4bd5-89f7-dfcd78fcca1d','送茂才馮彭年赴舉','林逋','宋','宋诗','song-poetry','','[]','相送不覺遠，離亭寒日斜。',48,'全唐诗/poet.song.5000.json','["相送不覺遠，離亭寒日斜。", "川途分野色，僮御想京華。", "背水當公戰，凌雲屬賦家。", "前春得意處，酣燕上林花。"]'),
('318154c4-8f54-4552-8c3e-0423003ec3a9','送史殿省典封州','林逋','宋','宋诗','song-poetry','','[]','馬援疏蠻邑，銅標何可窮。',48,'全唐诗/poet.song.5000.json','["馬援疏蠻邑，銅標何可窮。", "人烟時亦有，海色自如空。", "髭髮梅分白，旌旗瘴減紅。", "惟應蒔藥罷，都在酒醪中。"]'),
('3a916860-30af-4852-8bf2-32d7a2581d60','送王舍人罷兩浙憲赴闕','林逋','宋','宋诗','song-poetry','','[]','上閣還旌節，明廷覲冕旒。',48,'全唐诗/poet.song.5000.json','["上閣還旌節，明廷覲冕旒。", "清溪傾綺席，蠹簡壓歸舟。", "遠俗今無訟，閑田亦有秋。", "公期論爵賞，當拜富民侯。"]'),
('ce7a81e1-bf66-40db-b713-9f34c92c5024','送昱師赴請姑蘇','林逋','宋','宋诗','song-poetry','','["\u592a\u6e56"]','同載闔閭人，衣囊覆氎巾。',48,'全唐诗/poet.song.5000.json','["同載闔閭人，衣囊覆氎巾。", "新烟赤岸暝，融雪太湖春。", "鐘遠移齋候，香遲上定身。", "當知舉如意，寶地雨花頻。"]'),
('63e41a3e-de30-4f41-b738-b750f77d73f0','送皎師歸越','林逋','宋','宋诗','song-poetry','','[]','林間久離索，忽忽望西陵。',48,'全唐诗/poet.song.5000.json','["林間久離索，忽忽望西陵。", "靜戶初聞扣，歸舟又說登。", "野烟含樹色，春浪疊沙稜。", "幸謝雲門路，同尋苦未能。"]'),
('4d99210f-502c-44dd-808c-47acf43b50a4','送越倅楊屯田赴闕','林逋','宋','宋诗','song-poetry','','[]','越中分治罷，山水別來初。',48,'全唐诗/poet.song.5000.json','["越中分治罷，山水別來初。", "詩景多留石，船痕半載書。", "野程江樹遠，公宴郡樓虛。", "看塞嚴徐召，清風滿直廬。"]'),
('63bde417-986b-4b06-82e9-292c9298b67a','送思齊上人之宣城','林逋','宋','宋诗','song-poetry','','[]','林嶺藹春暉，程程入翠微。',48,'全唐诗/poet.song.5000.json','["林嶺藹春暉，程程入翠微。", "泉聲落坐石，花氣上行衣。", "詩正情懷澹，禪高論語稀。", "蕭閑水西寺，駐錫莫忘歸。"]'),
('efd405d7-6dea-4947-8ce1-207643968771','送僧機素還東嘉','林逋','宋','宋诗','song-poetry','','[]','康樂遺蹤地，言歸已有期。',48,'全唐诗/poet.song.5000.json','["康樂遺蹤地，言歸已有期。", "江流富春闊，山沓括蒼危。", "錫潤飛晴靄，羅寒濾曉澌。", "東巖有幽石，應許折松枝。"]'),
('78a8bfff-28fc-4fb7-a535-3b3eccd35fa8','送僧休復之京師','林逋','宋','宋诗','song-poetry','','[]','金錫指歸鴻，田衣獵曉風。',48,'全唐诗/poet.song.5000.json','["金錫指歸鴻，田衣獵曉風。", "春江片席遠，松月一房空。", "新句別離後，舊山魂夢中。", "到京當袖刺，館閣盡名公。"]'),
('4d32beef-9774-4e5b-b7bf-359de4d09e64','送僧之姑蘇','林逋','宋','宋诗','song-poetry','','[]','被請閶門寺，扁舟積水遥。',48,'全唐诗/poet.song.5000.json','["被請閶門寺，扁舟積水遥。", "幾程衝臘雪，一飯泊村橋。", "岑色晴空映，檀烟遠吹飄。", "公臺悉餘鎮，講罷即相招。"]'),
('56c16d6b-cf66-4924-a692-473051d84314','送聞義師謁池陽郡守','林逋','宋','宋诗','song-poetry','','[]','渺渺大江流，沿洄過幾州。',48,'全唐诗/poet.song.5000.json','["渺渺大江流，沿洄過幾州。", "登艫忽此別，振錫未嘗遊。", "九子尋真界，千兵見假侯。", "松枝談妙字，鈴閣想遲留。"]'),
('4245b8f1-9268-44b3-95fe-a600d5aaed01','寄思齊上人','林逋','宋','宋诗','song-poetry','','[]','松下中峰路，懷師日日行。',48,'全唐诗/poet.song.5000.json','["松下中峰路，懷師日日行。", "靜鐘浮野水，深寺隔春城。", "閣掩茶烟晚，廊迴雪溜清。", "當期相就宿，詩外話無生。"]'),
('0bb96c9f-9f5f-4a93-8f82-9af86944af92','寄吳肅秀才','林逋','宋','宋诗','song-poetry','','[]','肄業寄僧房，暑天湖上凉。',48,'全唐诗/poet.song.5000.json','["肄業寄僧房，暑天湖上凉。", "竹風過枕簟，梅雨潤巾箱。", "引步青山影，供吟白鳥行。", "明年重訪舊，身带桂枝香。"]'),
('2aa5b64c-aa44-418e-a4c2-cd88dd6ca53b','寄錢紫微','林逋','宋','宋诗','song-poetry','','[]','晞髮起初晨，中丘謝病身。',48,'全唐诗/poet.song.5000.json','["晞髮起初晨，中丘謝病身。", "空持白雲意，遥贈紫微人。", "畫轂坊門遠，蒼苔掖署春。", "元和舊文體，當許繼清塵。"]'),
('eaee53b6-b51b-457c-91e2-925e262bfec3','寄清曉闍梨','林逋','宋','宋诗','song-poetry','','[]','前時春雪晴，林壑趣彌清。',48,'全唐诗/poet.song.5000.json','["前時春雪晴，林壑趣彌清。", "幾憶山陰講，兼忘谷口耕。", "樹叢歸夕鳥，湖影浸寒城。", "還肯重相訪，柴門掩杜蘅。"]'),
('916d0fb7-72af-47f0-8c60-b0b4677a2922','寄胡介','林逋','宋','宋诗','song-poetry','','[]','憶著胡居士，長看古佛書。',48,'全唐诗/poet.song.5000.json','["憶著胡居士，長看古佛書。", "衡門惟老母，一飯共寒蔬。", "墨迹多圖鶴，山名愛畫廬。", "幾回曾會宿，風雪滿庭除。"]'),
('4a545075-b5dc-48b4-b4f8-20a13e5dea2b','寄孫仲簿公','林逋','宋','宋诗','song-poetry','','[]','低折滄洲簿，無書整兩春。',48,'全唐诗/poet.song.5000.json','["低折滄洲簿，無書整兩春。", "馬從同事借，妻怕罷官貧。", "道僻收閒藥，詩高笑古人。", "仍聞長吏奏，表乞鎖廳頻。"]'),
('6cc5ec48-db2a-43b2-9004-454589852568','寄和昌符','林逋','宋','宋诗','song-poetry','','[]','家近太行居，西歸壓一馿。',48,'全唐诗/poet.song.5000.json','["家近太行居，西歸壓一馿。", "同儕多及第，高論獨知書。", "名迹收藏遍，公卿扣謁疏。", "離愁不可寫，蟬噪夕陽初。"]'),
('8dbe759f-0429-475d-bc3f-ff1faec9f15c','聞越僧靈皎遊天竺山因而有寄','林逋','宋','宋诗','song-poetry','','[]','天竺秋重入，招提隔翠林。',48,'全唐诗/poet.song.5000.json','["天竺秋重入，招提隔翠林。", "幾回聞桂子，無復隔山陰。", "峰曉雲衣破，溪寒石色深。", "捫蘿諸勝概，孤病負同尋。"]'),
('e0fcd897-542b-41b2-8707-99ba896ddaeb','寄曹南任懶夫','林逋','宋','宋诗','song-poetry','','[]','關門却坐忘，一燼隠居香。',48,'全唐诗/poet.song.5000.json','["關門却坐忘，一燼隠居香。", "午瀨懷泉瀑，秋耕負曉岡。", "道深玄草在，貧久褐衣荒。", "料得心交者，微吟爲楚狂。"]'),
('09b9e0fa-6cfe-4004-907b-4b086db5d6a5','途中回寄閭丘秀才','林逋','宋','宋诗','song-poetry','','[]','極目半秋色，此情聊慘悽。',48,'全唐诗/poet.song.5000.json','["極目半秋色，此情聊慘悽。", "行人古道上，落日破村西。", "劍飲無高會，驢遊困解携。", "祇因風與月，吾子有新題。"]'),
('ea2f1c8a-4395-4a54-b0f9-37c1e6df19d7','淮甸城居寄任刺史','林逋','宋','宋诗','song-poetry','','[]','擾擾非吾事，深居斷俗情。',48,'全唐诗/poet.song.5000.json','["擾擾非吾事，深居斷俗情。", "石莎無雨瘦，秋竹共蟬清。", "劍在慵閑拂，詩難憶細評。", "寥然獨搘枕，淮月上山城。"]'),
('b6e94697-fc30-49d2-8e6a-a2b6e9282524','寄輦下傳神法相大師','林逋','宋','宋诗','song-poetry','','[]','禁寺諸供奉，如師藝學稀。',48,'全唐诗/poet.song.5000.json','["禁寺諸供奉，如師藝學稀。", "粉輕昏古本，羅重拆秋衣。", "凈鹻生缾暈，連陰長竹圍。", "算應支遁馬，毛骨苦無肥。"]'),
('6b5ae861-40a7-4cfb-9976-870e75085e8e','寄臨川司理趙時校書','林逋','宋','宋诗','song-poetry','','[]','遠宦風波隔，歸期歲月頻。',48,'全唐诗/poet.song.5000.json','["遠宦風波隔，歸期歲月頻。", "天形孤鳥晚，烟色大江春。", "驛路向山郭，船檣留估人。", "高臺望不極，空使鬢華新。"]'),
('0a8323c1-87db-4f03-92ef-045ffe4c614c','寄祝長官','林逋','宋','宋诗','song-poetry','','[]','懷想與君勞，區區未劇曹。',48,'全唐诗/poet.song.5000.json','["懷想與君勞，區區未劇曹。", "深心頼黄卷，垂老愧青袍。", "臨事終存道，爲詩轉近騷。", "廬江五畝宅，歸去亦蓬蒿。"]'),
('bf2e5e4d-3cf1-466c-b705-039475ee10f4','寄茂才馮彭年','林逋','宋','宋诗','song-poetry','','[]','異代甘泉賦，誰當頌太微。',48,'全唐诗/poet.song.5000.json','["異代甘泉賦，誰當頌太微。", "無如摛藻妙，所惜賞音稀。", "漸遠江關樹，方單客子衣。", "扁舟艤何許，霰雪暮霏霏。"]'),
('26dde30b-9377-4cfc-abdf-af6f5b07350c','射弓次寄彭城四君','林逋','宋','宋诗','song-poetry','','[]','襟掩皂貂斜，晴鼙響水涯。',48,'全唐诗/poet.song.5000.json','["襟掩皂貂斜，晴鼙響水涯。", "箭翎沉白雪，貼暈破微霞。", "氣爲傍觀壯，言因决勝誇。", "細釵金捍彀，更憶五侯家。"]'),
('d10020d0-5819-450d-b62a-4b53a2848c9a','贈金陵明上人','林逋','宋','宋诗','song-poetry','','[]','高社似東林，修行歲月深。',48,'全唐诗/poet.song.5000.json','["高社似東林，修行歲月深。", "講多刪舊抄，齋早喚幽禽。", "上國名流重，諸方學者尋。", "長因對清話，山閣轉松陰。"]'),
('bb455ab7-7596-4683-9df3-10cccd66e1b5','贈崔少微','林逋','宋','宋诗','song-poetry','','[]','賢才負聖朝，終日掩衡茅。',48,'全唐诗/poet.song.5000.json','["賢才負聖朝，終日掩衡茅。", "尚靜師高道，甘貧絕俗交。", "晒碑看壁蠹，蒸朮拾鄰梢。", "却憶楊夫子，勞勞事解嘲。"]'),
('e1bb8c58-97a5-4793-8622-da4cf7f99a1f','贈任懶夫','林逋','宋','宋诗','song-poetry','','[]','未肯求科第，深坊且隠居。',48,'全唐诗/poet.song.5000.json','["未肯求科第，深坊且隠居。", "勝遊携野客，高卧看兵書。", "點藥醫閑馬，分泉灌晚蔬。", "漢廷無得意，誰擬薦相如。"]'),
('18210227-01d5-4089-a4ae-e30d23c6e36c','知縣李太博得替','林逋','宋','宋诗','song-poetry','','[]','惠愛復公清，三年報政成。',48,'全唐诗/poet.song.5000.json','["惠愛復公清，三年報政成。", "絃歌敦雅俗，桃李藹春榮。", "縣治嘗遊刃，朝趨久彯纓。", "相門如有相，他日願持衡。"]'),
('0e4144ae-2ebe-4fbb-8785-2cd41ebff0d4','贈蔣公明','林逋','宋','宋诗','song-poetry','','[]','高亢近誰同，心閑愛子慵。',48,'全唐诗/poet.song.5000.json','["高亢近誰同，心閑愛子慵。", "居深避俗客，睡起聽鄰鐘。", "紙軸敲晴響，茶鐺煮晚濃。", "南齋屢招宿，幽話數諸峰。"]'),
('7af178ea-1c05-43ba-8e25-61143c0284fa','喜馬先輩及第後見訪','林逋','宋','宋诗','song-poetry','','[]','肄業十年初，蕭然此飯蔬。',48,'全唐诗/poet.song.5000.json','["肄業十年初，蕭然此飯蔬。", "何期桂枝客，來訪竹林居。", "香炷看新誥，塵痕拂舊書。", "回軒應睠睠，將與嶺雲疏。"]'),
('739839e3-9cf7-4f85-83a4-e2ec4a7e82ba','贈胡人','林逋','宋','宋诗','song-poetry','','[]','妻兒終擬棄，舊識盡名賢。',48,'全唐诗/poet.song.5000.json','["妻兒終擬棄，舊識盡名賢。", "高節嫌趨世，常流笑學仙。", "金方燒易得，星度算來玄。", "祇說尋山去，相期已數年。"]'),
('4731c333-d0a4-45c5-be19-ed2da33dc424','贈張繪秘教九題 詩將','林逋','宋','宋诗','song-poetry','','[]','風騷推上將，千古聳威名。',48,'全唐诗/poet.song.5000.json','["風騷推上將，千古聳威名。", "子美嘗登拜，昌齡合按行。", "籠紗疑旆影，擊鉢認金聲。", "唱和知誰敵，長驅勢已成。"]'),
('2dcc1698-026c-4304-aeea-8c926199efe7','贈張繪秘教九題 詩家','林逋','宋','宋诗','song-poetry','','[]','風月騷人業，相傳能幾家。',48,'全唐诗/poet.song.5000.json','["風月騷人業，相傳能幾家。", "清心長有慮，幽事更無涯。", "隠奧誰知到，陵夷即自嗟。", "千篇如可構，聊擬當豪華。"]'),
('75e251ba-4aa0-4d93-8d7d-befd4626d8f0','贈張繪秘教九題 詩匠','林逋','宋','宋诗','song-poetry','','[]','詩流有匠手，萬象片心通。',48,'全唐诗/poet.song.5000.json','["詩流有匠手，萬象片心通。", "山落分題月，花摇刻句風。", "勞形忘底滯，巧思出樊籠。", "唐律如刪正，斯人合立功。"]'),
('e6ac1b82-1011-4e7e-afac-f0b135f52ea6','贈張繪秘教九題 詩筆','林逋','宋','宋诗','song-poetry','','[]','青鏤墨淋漓，珊瑚架最宜。',48,'全唐诗/poet.song.5000.json','["青鏤墨淋漓，珊瑚架最宜。", "靜援花影轉，孤卓漏聲遲。", "題柱吾無取，如椽彼一時。", "風騷兼草隸，千古有人知。"]'),
('45bb6c70-9cd0-4a9f-bd35-b37dd8a45c6f','贈張繪秘教九題 詩狂','林逋','宋','宋诗','song-poetry','','[]','岸幘都旁若，窮搜無遁形。',48,'全唐诗/poet.song.5000.json','["岸幘都旁若，窮搜無遁形。", "寫嫌僧閣窄，吟怕酒船停。", "絕頂寒曾上，閑門夜不扃。", "興闌猶拍髀，毫末視青冥。"]'),
('4ade863c-3599-4fd5-ac96-59664fe5809f','贈張繪秘教九題 詩魔','林逋','宋','宋诗','song-poetry','','[]','花露濕晴春，秋燈落燼頻。',48,'全唐诗/poet.song.5000.json','["花露濕晴春，秋燈落燼頻。", "祇緣吟有味，不覺坐勞神。", "寄遠情無極，搜奇事轉新。", "此魔降不得，珍重五天人。"]'),
('a9bcebcd-3abf-4794-a728-76efac27db30','贈張繪秘教九題 詩牌','林逋','宋','宋诗','song-poetry','','[]','矗方標勝概，讀處即忘歸。',48,'全唐诗/poet.song.5000.json','["矗方標勝概，讀處即忘歸。", "靜壁懸虛白，危樓釘翠微。", "清銜時亦有，絕唱世還稀。", "一片題誰作，吾廬水石圍。"]'),
('33b8f03b-f418-45c8-a3df-0a4c31add9eb','贈張繪秘教九題 詩筒','林逋','宋','宋诗','song-poetry','','[]','唐賢存雅製，詩筆仰防閑。',48,'全唐诗/poet.song.5000.json','["唐賢存雅製，詩筆仰防閑。", "遞去權應緊，封迴債已還。", "带班猶恐俗，和節不妨山。", "酒篋將書簏，誰言季孟間。"]'),
('0fbb889d-2d36-45c5-9a7e-6a72dccdf32b','贈張繪秘教九題 詩壁','林逋','宋','宋诗','song-poetry','','[]','數題留粉堵，還勝在屏風。',48,'全唐诗/poet.song.5000.json','["數題留粉堵，還勝在屏風。", "坐讀棋慵下，眠看酒恰中。", "僧房秋色冷，山驛晚陽紅。", "更有栖遲句，家徒一畝宮。"]'),
('1381924f-8c83-4c34-974d-e4c5f7fb7925','閔師見寫陋容以詩奉答','林逋','宋','宋诗','song-poetry','','[]','顧我丘壑人，煩師與之寫。',48,'全唐诗/poet.song.5000.json','["顧我丘壑人，煩師與之寫。", "北山終日懸，風調一何野。", "林僧忽焉至，欲揖頃方罷。", "復有條上猿，驚窺未遑下。"]'),
('1edacb47-bd9b-44a1-bbad-fd0e544eaadd','監郡太博惠酒及詩','林逋','宋','宋诗','song-poetry','','[]','塵事久謝絕，園廬方晏陰。',48,'全唐诗/poet.song.5000.json','["塵事久謝絕，園廬方晏陰。", "鏗然郢中唱，伸玩清人心。", "況復對樽酒，百慮安能侵。", "何以比交情，松桂寒蕭森。"]'),
('3f835e1d-fba6-47b4-a3d0-5e210a4e5f5d','送牛秀才之山陽省兄','林逋','宋','宋诗','song-poetry','','[]','之子詠陟岡，別我歲時晏。',48,'全唐诗/poet.song.5000.json','["之子詠陟岡，別我歲時晏。", "後夜失羣鶴，高天著行雁。", "楚山遠近出，江樹青紅間。", "尊酒無足辭，離愁滿行盼。"]'),
('b323186e-999c-4dd2-8803-ca6c45ee34ef','湖上隠居','林逋','宋','宋诗','song-poetry','','[]','湖水入籬山繞舍，隠居應與世相違。',64,'全唐诗/poet.song.5000.json','["湖水入籬山繞舍，隠居應與世相違。", "閑門自掩蒼苔色，來客時驚白鳥飛。", "賣藥比嘗嫌有價，灌園終亦愛無機。", "如何天竺林間路，猶到秋深夢翠微。"]'),
('766eb8e9-ef79-4c53-ac48-e128ce9a5cb9','湖山小隠  其一','林逋','宋','宋诗','song-poetry','','[]','道著權名便絕交，一峰春翠濕衡茅。',64,'全唐诗/poet.song.5000.json','["道著權名便絕交，一峰春翠濕衡茅。", "莊生已憤鴟鳶赫，楊子休譏蝘蜓嘲。", "潏潏藥泉來石竇，霏霏茶藹出松梢。", "琴僧近借南薰譜，且併閑工子細抄。"]'),
('c35bcd16-79c1-4dc8-85f7-d72e530227a8','湖山小隠  其二','林逋','宋','宋诗','song-poetry','','[]','閑搭綸巾擁縹囊，此心隨分識興亡。',64,'全唐诗/poet.song.5000.json','["閑搭綸巾擁縹囊，此心隨分識興亡。", "黑頭爲相雖無謂，白眼看人亦未妨。", "雲噴石花生劍壁，雨敲松子落琴牀。", "清猿幽鳥遥相叫，數筆湖山又夕陽。"]'),
('3900c5e0-3883-498f-9466-08f2b7555f47','西湖泛舟入靈隠寺','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','水天相映淡浟溶，隔水青山無數重。',64,'全唐诗/poet.song.5000.json','["水天相映淡浟溶，隔水青山無數重。", "白鳥背人秋自遠，蒼烟和樹晚來濃。", "桐廬道次七里瀨，彭蠡湖間五老峰。", "輟棹遲迴比未得，上方精舍動疏鐘。"]'),
('bff597cf-e241-453a-b678-ac91555cdb25','湖上晚歸','林逋','宋','宋诗','song-poetry','','[]','卧枕船舷歸思清，望中渾恐是蓬瀛。',64,'全唐诗/poet.song.5000.json','["卧枕船舷歸思清，望中渾恐是蓬瀛。", "橋橫水木已秋色，寺倚雲峰正晚晴。", "翠羽濕飛如見避，紅蕖香嫋似相迎。", "依稀漸近誅茅地，鷄犬林蘿隠隠聲。"]'),
('a84693ac-b375-458f-88fe-be0e0a56db5d','湖上初春偶作','林逋','宋','宋诗','song-poetry','','[]','梅花開盡臘亦盡，春暖便如寒食天。',64,'全唐诗/poet.song.5000.json','["梅花開盡臘亦盡，春暖便如寒食天。", "氣色半歸湖岸柳，人家多上郭門船。", "文禽相並映短草，翠瀲欲生浮嫩煙。", "幾處酒旗山影下，細風時已弄繁絃。"]'),
('4f179cd9-89a3-488c-8bf6-89b1a4005b40','西湖春日','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','爭得才如杜牧之，試來湖上輒題詩。',64,'全唐诗/poet.song.5000.json','["爭得才如杜牧之，試來湖上輒題詩。", "春烟寺院敲齋鼓，夕照樓臺卓酒旗。", "濃吐雜芳薰巘崿，濕飛雙翠破漣漪。", "人間幸有蓑兼笠，且上漁舟作釣師。"]'),
('3cc63423-4651-4f66-baf9-d558115156f1','池上春日','林逋','宋','宋诗','song-poetry','','[]','一池春水綠於苔，水上花枝竹間開。',64,'全唐诗/poet.song.5000.json','["一池春水綠於苔，水上花枝竹間開。", "芳草得時依舊長，文禽無事等閑來。", "年顔近老空多感，風雅含情苦不才。", "獨有浴沂遺想在，使人終日此徘徊。"]'),
('4e603302-4c43-4500-aeb0-452b84b0a3de','池上春日即事','林逋','宋','宋诗','song-poetry','','[]','鴛鴦如綺杜蘅肥，鸂鶒夷猶翠瀲微。',64,'全唐诗/poet.song.5000.json','["鴛鴦如綺杜蘅肥，鸂鶒夷猶翠瀲微。", "但據汀洲長並宿，莫衝煙靄輒驚飛。", "已輸謝客清吟了，未忍山翁爛醉歸。", "釣艇自橫絲雨霽，更從蒲篠媚斜暉。"]'),
('ca877716-0c77-48a1-bd26-e3605d80fc4c','小園春日','林逋','宋','宋诗','song-poetry','','[]','草烟橫碧露華微，乘興春園懶欲歸。',64,'全唐诗/poet.song.5000.json','["草烟橫碧露華微，乘興春園懶欲歸。", "聚散有情輸蛺蝶，淺深無色比薔薇。", "浮名莫惜千鍾貴，急景須防百歲稀。", "一事不堪身衣褐，且偷閑眼看芳菲。"]'),
('37e3f669-a85c-425c-833a-226c1a210b0a','夏日池上','林逋','宋','宋诗','song-poetry','','[]','蓮香如綺細濛濛，翡翠窺魚裊水葓。',64,'全唐诗/poet.song.5000.json','["蓮香如綺細濛濛，翡翠窺魚裊水葓。", "卷箔未生單簟月，凭欄初過一襟風。", "橫欹片石安琴薦，獨倚新篁看鶴籠。", "沉李凍醪無寄與，可憐瀟洒興誰同。"]'),
('d854ec26-c646-4711-99bf-193f0de3d177','西巖夏日','林逋','宋','宋诗','song-poetry','','[]','蕙帳蕭閑掩弊廬，子真巖石坐來初。',64,'全唐诗/poet.song.5000.json','["蕙帳蕭閑掩弊廬，子真巖石坐來初。", "爲驚野鳥巢間乳，懶過隣僧竹裏居。", "新溜迸凉侵靜語，晚雲浮潤上殘書。", "何煩彊捉白團扇，一柄青松自有餘。"]'),
('eea8d791-81cb-4c8b-ad10-f28eb75380f8','夏日即事','林逋','宋','宋诗','song-poetry','','[]','石枕凉生菌閣虛，已應梅潤入圖書。',64,'全唐诗/poet.song.5000.json','["石枕凉生菌閣虛，已應梅潤入圖書。", "不辭齒髮多衰病，所喜林泉有隠居。", "粉竹亞梢垂宿露，翠荷差影聚遊魚。", "北窗人在羲皇上，時爲淵明一起予。"]'),
('1c0d624e-24ed-4e75-98e5-c3081b1e4b5b','隠居秋日','林逋','宋','宋诗','song-poetry','','[]','行藥歸來即杜門，嘯臺秋色背人羣。',64,'全唐诗/poet.song.5000.json','["行藥歸來即杜門，嘯臺秋色背人羣。", "幽蟲傍草晚相映，遠水著烟寒未分。", "高亢可能稱獨行，窮空猶擬頼斯文。", "過從好事今誰是，自笑何如楊子雲。"]'),
('2bb687e5-c11d-4afc-9e33-a563096f4d0b','秋日湖西晚歸舟中書事','林逋','宋','宋诗','song-poetry','','[]','水痕秋落蟹螯肥，閑過黄公酒舍歸。',64,'全唐诗/poet.song.5000.json','["水痕秋落蟹螯肥，閑過黄公酒舍歸。", "魚覺船行沉草岸，犬聞人語出柴扉。", "蒼山半带寒雲重，丹葉疏分夕照微。", "却憶清谿謝太傅，當時未解惜蓑衣。"]'),
('21bbc80d-520f-4b26-8b54-81981b9d1ac4','城中書事','林逋','宋','宋诗','song-poetry','','[]','一門深掩得閑權，純白遺風要獨全。',64,'全唐诗/poet.song.5000.json','["一門深掩得閑權，純白遺風要獨全。", "强接俗庸中反道，敢嫌貧病是欺天。", "圍形古寺諳尋鶴，照蘚秋廊擬疏玄。", "從此免慚巖下者，子真高興未蕭然。"]'),
('52db3510-b33f-4e63-a2de-032ca01bc3bb','深居雜興六首  其一','林逋','宋','宋诗','song-poetry','','[]','隠居松籟細錚然，何獨微之重碧蘚。',64,'全唐诗/poet.song.5000.json','["隠居松籟細錚然，何獨微之重碧蘚。", "已被遠峰擎𡾼𡾼，更禁初月吐娟娟。", "門庭靜極霖苔露，籬援凉生裊菊煙。", "中有病夫披白搭，瘦行清坐詠遺篇。"]'),
('ffce1359-d3a7-4747-b727-1ae629ea915c','深居雜興六首  其二','林逋','宋','宋诗','song-poetry','','[]','四壁垣衣釣具腥，已甘衡泌號沉冥。',64,'全唐诗/poet.song.5000.json','["四壁垣衣釣具腥，已甘衡泌號沉冥。", "伶倫近日無侯白，奴僕當時有衛青。", "花月病懷看酒譜，雲蘿幽信寄茶經。", "茅君使者蕭閑甚，獨理叢毛向戶庭。"]'),
('1820f894-e278-4fc1-9e1b-97d663c9fdb1','深居雜興六首  其三','林逋','宋','宋诗','song-poetry','','[]','薄夫何苦事姦姦，一室琴書自解顔。',64,'全唐诗/poet.song.5000.json','["薄夫何苦事姦姦，一室琴書自解顔。", "峰後月明秋嘯去，水邊林影晚樵還。", "文章敢道長於古，光景渾疑剩却閑。", "多少烟霞好魚鳥，令人惆悵謝東山。"]'),
('b839b314-0d05-4dae-a7f6-d942be2455dd','深居雜興六首  其四','林逋','宋','宋诗','song-poetry','','[]','冉冉秋雲抱嘯臺，一兵松竹是閑媒。',64,'全唐诗/poet.song.5000.json','["冉冉秋雲抱嘯臺，一兵松竹是閑媒。", "誰聞濟北傳兵略，枉說山東出相才。", "樵褐短長披搕膝，丹爐高下壘懸胎。", "三千功行無圭角，可望虛皇九錫來。"]'),
('e3a634fe-2c0e-4510-b171-571a55425276','深居雜興六首  其五','林逋','宋','宋诗','song-poetry','','[]','上書可有三千牘，下筆曾無一百函。',64,'全唐诗/poet.song.5000.json','["上書可有三千牘，下筆曾無一百函。", "閒卷孤懷背塵世，獨營幽事傍雲巖。", "僧分乳食來陰洞，鶴觸茶薪落蠹杉。", "未似周顒少貞勝，北山應免略相銜。"]'),
('5af51b28-87fa-4364-a6a9-1527eedd5f63','深居雜興六首  其六','林逋','宋','宋诗','song-poetry','','[]','松竹封侯尚未尊，石爲公輔亦云云。',64,'全唐诗/poet.song.5000.json','["松竹封侯尚未尊，石爲公輔亦云云。", "清華自合論閑客，玄默何妨事靜君。", "鶴料免慚尸厚祿，茶功兼擬策元勛。", "幽人不作山中相，且擁圖書卧白雲。"]'),
('8c7b3cc4-1e6a-48cc-b629-cc558bb81543','雜興四首  其一','林逋','宋','宋诗','song-poetry','','[]','短褐蕭蕭頂幅巾，擁書纔罷即嚬呻。',64,'全唐诗/poet.song.5000.json','["短褐蕭蕭頂幅巾，擁書纔罷即嚬呻。", "耕樵可似居山者，飲饌長如病酒人。", "閉戶不無慵答客，焚香除是靜朝貞。", "前賢風概聊希擬，一刺偏多井大春。"]'),
('a8274f37-a7ca-4789-ae91-440a8b276fe6','雜興四首  其二','林逋','宋','宋诗','song-poetry','','[]','散帙揮毫總不忺，病懷愁緒坐相兼。',64,'全唐诗/poet.song.5000.json','["散帙揮毫總不忺，病懷愁緒坐相兼。", "苔痕作意生秋壁，樹影無端上古簾。", "一壑等閑甘汩汩，五門平昔避炎炎。", "惟應數刻清凉夢，時曲顔肱興未厭。"]'),
('d83104ad-5ea9-4129-a503-a6de1ad5bc03','雜興四首  其三','林逋','宋','宋诗','song-poetry','','[]','湖上山林畫不如，霜天時候屬園廬。',64,'全唐诗/poet.song.5000.json','["湖上山林畫不如，霜天時候屬園廬。", "梯斜晚樹收紅柿，筒直寒流得白魚。", "石上琴尊苔野凈，籬陰鷄犬竹叢疏。", "一關兼是和雲掩，敢道門無卿相車。"]'),
('7c8fe3ec-48d9-4439-989b-8b94178e975b','雜興四首  其四','林逋','宋','宋诗','song-poetry','','[]','掉臂何妨入隠淪，高賢應總貴全真。',64,'全唐诗/poet.song.5000.json','["掉臂何妨入隠淪，高賢應總貴全真。", "次山有以稱聱叟，魯望兼之傳散人。", "拂水遠天孤榜晚，夾村微雨一犂春。", "不知圖畫誰名手，狀取江湖太古民。"]'),
('c1be7ae9-ccc2-4be0-819b-529cef3832bb','孤山後寫望','林逋','宋','宋诗','song-poetry','','[]','水墨屏風狀總非，作詩除是謝玄暉。',64,'全唐诗/poet.song.5000.json','["水墨屏風狀總非，作詩除是謝玄暉。", "溪橋裊裊穿黄葉，樵斧丁丁斫翠微。", "返照未沉僧獨往，長煙如淡鳥橫飛。", "南峰有客鋤園罷，閑倚籬門忘却歸。"]'),
('f85a343f-f9b3-4b83-b1da-deffd50df233','孤山寺端上人房寫望','林逋','宋','宋诗','song-poetry','','["\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929", "\u9690\u5c45"]','底處憑闌思眇然，孤山塔後閣西偏。',64,'全唐诗/poet.song.5000.json','["底處憑闌思眇然，孤山塔後閣西偏。", "陰沉畫軸林間寺，零落棋枰葑上田。", "秋景有時飛獨鳥，夕陽無事起寒烟。", "遲留更愛吾廬近，祇待重來看雪天。"]'),
('9af95c3c-d8d1-4e9a-8834-8354d09928f3','山閣偶書','林逋','宋','宋诗','song-poetry','','[]','遶舍青山看未足，故穿林表架危軒。',64,'全唐诗/poet.song.5000.json','["遶舍青山看未足，故穿林表架危軒。", "但將松籟延佳客，常带嵐霏認遠村。", "吳榜自能凌晚汰，湘纍何苦屬芳蓀。", "餘生多病期怡養，聊此棲遲一避喧。"]'),
('4fa9050d-c674-48ea-8779-601b70e37359','孤山寺','林逋','宋','宋诗','song-poetry','','[]','雲峰水樹南朝寺，祇隔叢篁作並鄰。',64,'全唐诗/poet.song.5000.json','["雲峰水樹南朝寺，祇隔叢篁作並鄰。", "破殿靜披虀臼古，齋房閑試酪奴春。", "白公睡閣幽如畫，張祜詩牌妙入神。", "乘興醉來拖木突，翠苔蒼蘚石磷磷。"]'),
('dc641793-b90a-4edf-8c5d-3ce0fcee3dce','西湖','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','混元神巧本無形，匠出西湖作畫屏。',64,'全唐诗/poet.song.5000.json','["混元神巧本無形，匠出西湖作畫屏。", "春水凈於僧眼碧，晚山濃似佛頭青。", "欒櫨粉堵摇魚影，蘭杜煙叢閣鷺翎。", "往往鳴榔與橫笛，細風斜雨不堪聽。"]'),
('70ed8fbd-834f-4120-b345-085a86613783','平居遣興','林逋','宋','宋诗','song-poetry','','[]','有甚餘閑得解嘲，高慵時把几桯敲。',64,'全唐诗/poet.song.5000.json','["有甚餘閑得解嘲，高慵時把几桯敲。", "卑孜晚鳥沉幽語，歷剌烟篁露病梢。", "草野交遊披褐見，神仙書史點朱抄。", "皇朝不是甘逃遁，爭向心如許與巢。"]'),
('4e5d465c-4dca-45a4-908d-750c1fa4db1a','山谷寺','林逋','宋','宋诗','song-poetry','','[]','纔入禪林便懶還，衆峰深壑共孱顔。',64,'全唐诗/poet.song.5000.json','["纔入禪林便懶還，衆峰深壑共孱顔。", "樓臺冷簇雲蘿外，鐘磬晴敲水石間。", "茶版手擎童子凈，錫枝肩倚老僧閑。", "獨孤房相碑文在，幾認題名拂蘚斑。"]'),
('5154445a-2fc8-4c8f-851d-5450696410fa','峽石寺','林逋','宋','宋诗','song-poetry','','[]','長淮如練楚山青，禹鑿招提甲畫屏。',64,'全唐诗/poet.song.5000.json','["長淮如練楚山青，禹鑿招提甲畫屏。", "數崦林蘿攢野色，一崖樓閣貯天形。", "燈驚獨鳥迴晴塢，鐘送遥帆落晚汀。", "不會剃頭無事者，幾人能老此禪扃。"]'),
('0422cf2b-e5a0-4af6-b705-6708b56c11ec','池陽山店','林逋','宋','宋诗','song-poetry','','[]','數家村店簇山旁，下馬危橋已夕陽。',64,'全唐诗/poet.song.5000.json','["數家村店簇山旁，下馬危橋已夕陽。", "驚鳥忽衝谿靄破，暗花閑墮塹風香。", "時間盤泊心猶戀，日後尋思興必狂。", "可惜迴頭一聲笛，酒旗斜曳出疏篁。"]'),
('5597882c-f4d0-41b8-80db-e3595eace67f','寺居','林逋','宋','宋诗','song-poetry','','[]','浩然巾杖立秋鐘，院舍門門細徑通。',64,'全唐诗/poet.song.5000.json','["浩然巾杖立秋鐘，院舍門門細徑通。", "柏子有芽生塔地，鶴毛無響墮廊風。", "閑棲已合稱高士，清論除非對遠公。", "不厭浮塵擬何了，片心難舍此緣中。"]'),
('39210c12-ea1b-4374-8f07-54b831b14a81','采石山','林逋','宋','宋诗','song-poetry','','[]','危閣閑登日漸曛，整屏晴雨枕江濆。',64,'全唐诗/poet.song.5000.json','["危閣閑登日漸曛，整屏晴雨枕江濆。", "秋稜瘦出無多寺，古翠濃連一半雲。", "坐卧不拋輸釣叟，往來長見屬鷗羣。", "翻然却怪宣城守，是甚移將李白墳。"]'),
('265e4aa2-19df-46ba-87bd-4aeeb974a50e','易從上人山亭','林逋','宋','宋诗','song-poetry','','[]','湖水江灣隔數峰，籬門和竹夾西東。',64,'全唐诗/poet.song.5000.json','["湖水江灣隔數峰，籬門和竹夾西東。", "閑來此地行無厭，又共吾廬看不同。", "靈隠路歸秋色裏，招賢菴在鳥行中。", "屏風若欲相攙見，合把巉巖與畫工。"]'),
('53bc3001-ed7b-4d87-a1df-d293d1c5305b','園池','林逋','宋','宋诗','song-poetry','','[]','一徑衡門數畝池，平湖分張草含滋。',64,'全唐诗/poet.song.5000.json','["一徑衡門數畝池，平湖分張草含滋。", "微風幾入扁舟意，新霽難忘獨繭期。", "島上鶴毛遺野迹，岸旁花影動春枝。", "東嘉層構名今在，獨愧憑闌負碧漪。"]'),
('9a5086dd-d409-4f1f-b146-bcd414ab5bfa','林間石','林逋','宋','宋诗','song-poetry','','[]','入夜跏趺多待月，移時箕踞爲看山。',64,'全唐诗/poet.song.5000.json','["入夜跏趺多待月，移時箕踞爲看山。", "苔生晚片應知靜，雲動秋根合見閑。", "瘦鶴獨隨行藥後，高僧相對試茶間。", "疏篁百本松千尺，莫怪頻頻此往還。"]'),
('082e2b1c-2d0b-4d13-9977-1cfe2d50d674','黄家莊','林逋','宋','宋诗','song-poetry','','[]','黄家莊畔一維舟，總是沿流好宿頭。',64,'全唐诗/poet.song.5000.json','["黄家莊畔一維舟，總是沿流好宿頭。", "野興幾多尋竹徑，風情些小上茶樓。", "遥村雨暗鳴寒犢，淺溆沙平下晚鷗。", "更有錦帆荒蕩事，茫茫隨分起詩愁。"]'),
('de20a580-95f0-4d0c-a7d3-e7da18057cb1','過蕪湖縣','林逋','宋','宋诗','song-poetry','','[]','詩中長愛杜池州，說著蕪湖是勝遊。',64,'全唐诗/poet.song.5000.json','["詩中長愛杜池州，說著蕪湖是勝遊。", "山掩縣城當北起，渡衝官道向西流。", "風稍檣碇綱初下，雨擺魚薪市未收。", "更好兩三僧院舍，松衣石髮鬭山幽。"]'),
('b00719fd-c011-4eae-8a44-dcc456a375b0','無爲軍','林逋','宋','宋诗','song-poetry','','[]','掩映軍城隔水鄉，人煙景物共蒼蒼。',64,'全唐诗/poet.song.5000.json','["掩映軍城隔水鄉，人煙景物共蒼蒼。", "酒家樓閣摇風旆，茶客舟船簇雨檣。", "殘笛遠砧聞野墅，老苔寒檜看僧房。", "狎鷗更有江湖興，珍重江頭白一行。"]'),
('9cfdc282-0d79-47ff-b077-28a2fe8c1bc5','出泉水驛','林逋','宋','宋诗','song-poetry','','[]','曉城寒水共蕭蕭，濕碧吹青路一條。',64,'全唐诗/poet.song.5000.json','["曉城寒水共蕭蕭，濕碧吹青路一條。", "煙靄濃間出山驛，林蘿深裏過溪橋。", "閑情謾會吟兼畫，隠事猶輸釣與樵。", "多謝孤村人落外，酒旗風急更相招。"]'),
('ccb32146-289e-4089-bea1-fd96c55abf2c','淮甸南遊','林逋','宋','宋诗','song-poetry','','[]','幽勝程程擬徧尋，不妨淮楚入搜吟。',64,'全唐诗/poet.song.5000.json','["幽勝程程擬徧尋，不妨淮楚入搜吟。", "蘚莎籬落谿莊靜，松竹樓臺塢寺深。", "數抹晚霞憐野笛，一篩寒水羨沙禽。", "腰間組綬誰能愛，時得閑遊是此心。"]'),
('ec0913f5-b634-4442-9aba-2875833a0855','耿濟口舟行','林逋','宋','宋诗','song-poetry','','[]','環迴幾合似江干，刺眼詩幽盡狀難。',64,'全唐诗/poet.song.5000.json','["環迴幾合似江干，刺眼詩幽盡狀難。", "沙嘴半平春晚濕，水痕無底照秋寬。", "老霜蒲葦交千刃，怕雨鳬鷗著一攢。", "擬就孤峰寄蓑笠，舊鄉漁業久凋殘。"]'),
('ef5d7f01-5f2d-44c7-9815-b548bc75587d','留題李休山居','林逋','宋','宋诗','song-poetry','','[]','俗口喧喧利與名，到君風品即難憑。',64,'全唐诗/poet.song.5000.json','["俗口喧喧利與名，到君風品即難憑。", "曾將五老關秋夢，只愛南薰是正聲。", "鳥戀藥棚長獨立，樹欺詩壁半旁生。", "公車便不能徵出，搔首吾皇負聖明。"]'),
('4c2c274f-de65-4609-81bf-bdd00cbb1f65','園廬','林逋','宋','宋诗','song-poetry','','[]','柴關寒井對蕭辰，自愛棲遲近古人。',64,'全唐诗/poet.song.5000.json','["柴關寒井對蕭辰，自愛棲遲近古人。", "閑草徧庭終勝俗，好書堆案轉甘貧。", "橋邊野水通漁路，籬外青山見寺鄰。", "懶爲躬耕詠梁甫，吾生已是太平民。"]'),
('d8594583-cb54-4140-ab3d-6946accacaad','安福縣途中作','林逋','宋','宋诗','song-poetry','','[]','詩景紛拏且按鞭，壞橋危磴已鳴泉。',64,'全唐诗/poet.song.5000.json','["詩景紛拏且按鞭，壞橋危磴已鳴泉。", "雲根道店多沽酒，山崦人家亦種田。", "谷鳥驚啼衝宿雨，野梅愁絕閉寒煙。", "玉梁閣皂堪行徧，回得臨江即上船。"]'),
('1d96e2c1-defe-48b3-869a-a78c8fd0bec2','雪三首  其一','林逋','宋','宋诗','song-poetry','','[]','瓦溝如粉疊樓腰，高會誰能解酒貂。',64,'全唐诗/poet.song.5000.json','["瓦溝如粉疊樓腰，高會誰能解酒貂。", "清夾曉林初落索，冷和春雨轉飄蕭。", "堪憐雀避來閑地，最愛僧衝過短橋。", "獨有閉關孤隠者，一軒貧病在顔瓢。"]'),
('e53da81c-3b6a-422b-b8d7-d8b45b620b15','雪三首  其二','林逋','宋','宋诗','song-poetry','','[]','濕飄乾墮著谿林，陣猛花尖聚砌陰。',64,'全唐诗/poet.song.5000.json','["濕飄乾墮著谿林，陣猛花尖聚砌陰。", "曉沫平隨茶筯薄，凍痕全共藥鋤深。", "慵多只好披詩看，狂甚無如叩几吟。", "更想天山兩三騎，臂鷹拳蹬簇駸駸。"]'),
('cd505916-fe7f-442f-8afc-7480553c59e3','雪三首  其三','林逋','宋','宋诗','song-poetry','','[]','皓然窗戶曉來新，畫軸碑廳絕點塵。',64,'全唐诗/poet.song.5000.json','["皓然窗戶曉來新，畫軸碑廳絕點塵。", "洛下高眠應有道，山陰清興更無人。", "寒連水石鳴漁墅，猛共松篁壓寺鄰。", "酒渴已醒時味薄，獨援詩筆得天真。"]'),
('f7e84425-eb7a-428a-a282-9281967180db','春陰','林逋','宋','宋诗','song-poetry','','[]','似雨非晴意思深，宿酲牽引卧春陰。',64,'全唐诗/poet.song.5000.json','["似雨非晴意思深，宿酲牽引卧春陰。", "苦憐燕子寒相並，生怕梨花晚不禁。", "薄薄簾幃欺欲透，遥遥歌管壓來沉。", "北園南陌狂無數，只有芳菲會此心。"]'),
('b092e66f-6bbb-4d01-a871-9e867aa647fb','秋懷','林逋','宋','宋诗','song-poetry','','[]','惠連初擬賦秋懷，病束慵纏幾未諧。',64,'全唐诗/poet.song.5000.json','["惠連初擬賦秋懷，病束慵纏幾未諧。", "濕葉墮丹明晚塹，破雲拖粉露晴崖。", "先甘衰落歸雙髩，已覺清凉入百骸。", "試枕離騷校閑品，竹烟杉籟滿蕭齋。"]'),
('6a6849d9-2aaa-41fc-8246-4a789766616f','山園小梅二首  其一','林逋','宋','宋诗','song-poetry','','[]','衆芳摇落獨暄妍，占盡風情向小園。',64,'全唐诗/poet.song.5000.json','["衆芳摇落獨暄妍，占盡風情向小園。", "疏影橫斜水清淺，暗香浮動月黄昏。", "霜禽欲下先偷眼，粉蝶如知合斷魂。", "幸有微吟可相狎，不須檀板共金尊。"]'),
('9d4ad6ba-208f-4a48-82bc-a93246afe699','山園小梅二首  其二','林逋','宋','宋诗','song-poetry','','[]','剪綃零碎點酥乾，向背稀稠畫亦難。',64,'全唐诗/poet.song.5000.json','["剪綃零碎點酥乾，向背稀稠畫亦難。", "日薄從甘春至晚，霜深應怯夜來寒。", "澄鮮衹共鄰僧惜，冷落猶嫌俗客看。", "憶著江南舊行路，酒旗斜拂墮吟鞍。"]'),
('47675ef1-79ee-47ff-9649-ffb6d4851378','又詠小梅','林逋','宋','宋诗','song-poetry','','[]','數年閑作園林主，未有新詩到小梅。',64,'全唐诗/poet.song.5000.json','["數年閑作園林主，未有新詩到小梅。", "摘索又開三兩朵，團欒空繞百千迴。", "荒鄰獨映山初盡，晚景相禁雪欲來。", "寄語清香少愁結，爲君吟罷一銜杯。"]'),
('ba3c54f5-c84b-4752-bb88-042495fffa3d','梅花  其一','林逋','宋','宋诗','song-poetry','','[]','吟懷長恨負芳時，爲見梅花輒入詩。',64,'全唐诗/poet.song.5000.json','["吟懷長恨負芳時，爲見梅花輒入詩。", "雪後園林纔半樹，水邊籬落忽橫枝。", "人憐紅艷多應俗，天與清香似有私。", "堪笑胡雛亦風味，解將聲調角中吹。"]'),
('1f4452dd-f19a-4c59-9038-bd818ccc864c','梅花  其二','林逋','宋','宋诗','song-poetry','','[]','幾回山脚又江頭，繞著孤芳看不休。',64,'全唐诗/poet.song.5000.json','["幾回山脚又江頭，繞著孤芳看不休。", "一味清新無我愛，十分孤靜與伊愁。", "任教月老須微見，却爲春寒得少留。", "終共公言數來者，海棠端的免包羞。"]'),
('b3252422-9e33-4741-9809-e5f1cc0d80ef','梅花  其三','林逋','宋','宋诗','song-poetry','','[]','小園烟景正凄迷，陳陣寒香壓麝臍。',64,'全唐诗/poet.song.5000.json','["小園烟景正凄迷，陳陣寒香壓麝臍。", "湖水倒窺疏影動，屋簷斜入一枝低。", "畫工空向閒時看，詩客休徵故事題。", "慚愧黄鸝與蝴蝶，只知春色在桃溪。"]'),
('644ea61e-ed7a-4627-8ec5-b46a9fa99d12','杏花','林逋','宋','宋诗','song-poetry','','[]','蓓蕾枝梢血點乾，粉紅腮頰露春寒。',64,'全唐诗/poet.song.5000.json','["蓓蕾枝梢血點乾，粉紅腮頰露春寒。", "不禁烟雨輕欺著，只好亭臺愛惜看。", "隈柳旁桃斜欲墜，等鶑期蝶猛成團。", "京師巷陌新晴後，賣得風流更一端。"]'),
('8bb9c629-d866-4d60-8aa1-a514ab8be33c','桃花','林逋','宋','宋诗','song-poetry','','[]','柳墜梅飄半月初，小園孤榭更庭除。',64,'全唐诗/poet.song.5000.json','["柳墜梅飄半月初，小園孤榭更庭除。", "任應雨杏情無別，最與烟篁分不疏。", "比並合饒皮博士，形相偏屬薛尚書。", "薄紅深茜尖尖葉，亦有愁腸未負渠。"]'),
('8f94843d-19a9-498b-957e-da0f955f63a9','山舍小軒有石竹二叢鬨然秀發因成二章  其一','林逋','宋','宋诗','song-poetry','','[]','麝香眠後露檀勻，繡在羅衣色未真。',64,'全唐诗/poet.song.5000.json','["麝香眠後露檀勻，繡在羅衣色未真。", "斜倚細叢如有恨，冷摇疏朵欲生春。", "階前紅藥推詞客，籬下黄花重古人。", "今日含毫與題品，可憐殊不愧清新。"]'),
('50bd6925-a7b7-497c-9ac9-5b41582916b1','山舍小軒有石竹二叢鬨然秀發因成二章  其二','林逋','宋','宋诗','song-poetry','','[]','青簾有酒不妨賒，素壁無詩未足誇。',64,'全唐诗/poet.song.5000.json','["青簾有酒不妨賒，素壁無詩未足誇。", "所重晚芳猶在日，可關秋色易爲花。", "深枝苒苒粧溪翠，碎片英英剪海霞。", "莫管金錢好行市，寂寥相對是山家。"]'),
('7f4598cd-339d-4b40-997e-d870875b1e25','新竹','林逋','宋','宋诗','song-poetry','','[]','粉環勻束綠沉槍，裊露差烟𡾼𡾼長。',64,'全唐诗/poet.song.5000.json','["粉環勻束綠沉槍，裊露差烟𡾼𡾼長。", "卷箔乍驚雙眼健，倚闌尋覺百毛凉。", "齊披古錦圍山閣，背迸寒犀過寺牆。", "堪笑數根蒼翠者，强顔如立少年場。"]'),
('313829c6-11df-4670-8d37-827b04d42ba5','榮家鶴','林逋','宋','宋诗','song-poetry','','[]','種莎池館久淹留，品格堪憐絕比儔。',64,'全唐诗/poet.song.5000.json','["種莎池館久淹留，品格堪憐絕比儔。", "春靜棋邊窺野客，雨寒廊底夢滄洲。", "清形已入僊經說，冷格曾爲古畫偷。", "數啄稻粱無事外，報言雞雀懶迴頭。"]'),
('92bf5cdd-cc54-46b4-ac45-df3b271a5623','百舌','林逋','宋','宋诗','song-poetry','','[]','柳條初重草初肥，煙濕園林晚未晞。',64,'全唐诗/poet.song.5000.json','["柳條初重草初肥，煙濕園林晚未晞。", "百種堪憐巧言語，一般惟久好毛衣。", "欺凌紅杏從頭宿，諷刺黄鸝趁背飛。", "誰道關關便多事，更能緘默送芳菲。"]'),
('70530f22-31ef-4aae-88dc-85dad827d75d','蝶','林逋','宋','宋诗','song-poetry','','[]','細眉雙聳敵秋毫，冉冉芳園日幾遭。',64,'全唐诗/poet.song.5000.json','["細眉雙聳敵秋毫，冉冉芳園日幾遭。", "清宿露花應自得，暖爭風絮欲相高。", "情人歿後魂猶在，傲吏齊來夢亦勞。", "閑掩遺編苦堪恨，不并香草入離騷。"]'),
('3b902b72-c63c-42e5-94d5-ec3a282812d3','病中  其一','林逋','宋','宋诗','song-poetry','','[]','坐釣行樵那不倦，尋雲看月亦應勞。',64,'全唐诗/poet.song.5000.json','["坐釣行樵那不倦，尋雲看月亦應勞。", "煩襟入夜權宜減，瘦格乘秋斗頓高。", "猿下任窺煎藥鼎，客來慵動碾茶槽。", "牀頭卧架直閑却，免有情憀揭悼騷。"]'),
('015a0ba2-49d2-4566-baf6-84de3d16ef8f','病中  其二','林逋','宋','宋诗','song-poetry','','[]','遺編坐罷披三豕，小軸行當倦伍禽。',64,'全唐诗/poet.song.5000.json','["遺編坐罷披三豕，小軸行當倦伍禽。", "廉肆有徵常遇困，刀圭無狀爲攻深。", "長卿痟渴應難奈，玄晏清羸已不禁。", "約縛隠囊聊閣膝，忘懷未得是微吟。"]'),
('a4c9bfe9-bb93-40f3-b819-e6ad48560708','送范寺丞','林逋','宋','宋诗','song-poetry','','[]','林中蕭寂款吾廬，亹亹猶欣接緒餘。',64,'全唐诗/poet.song.5000.json','["林中蕭寂款吾廬，亹亹猶欣接緒餘。", "去棹看當辨江樹，離尊聊爲摘園蔬。", "馬卿才大常能賦，梅福官卑數上書。", "黼座垂精正求治，何時條對召公車。"]'),
('f648486e-cf82-4555-ae19-c109670e6a1e','送史殿丞之任封州','林逋','宋','宋诗','song-poetry','','[]','炎方將命選朝倫，治行何嘗下古人。',64,'全唐诗/poet.song.5000.json','["炎方將命選朝倫，治行何嘗下古人。", "擁旆肯辭臨遠郡，登艫還喜奉慈親。", "水連芳草江南地，煙隔寒梅嶺上春。", "若過中途值歸雁，慰懷能與致音塵。"]'),
('940571d2-d3dc-43df-b9d5-6ba78d7de2ac','送史宮贊蘭溪解印歸闕','林逋','宋','宋诗','song-poetry','','[]','杜若萋萋天似水，一檣風信快吟懷。',64,'全唐诗/poet.song.5000.json','["杜若萋萋天似水，一檣風信快吟懷。", "春坊冠蓋還朝籍，寶婺谿山別縣齋。", "訪舊約僧登北固，破程乘月宿清淮。", "東南出宰才居最，疇爲言揚向玉階。"]'),
('10107495-9267-4020-a34c-0bd5b313d662','送馬程知江州德安','林逋','宋','宋诗','song-poetry','','[]','酒酣無復耿離腸，一路之官盡水鄉。',64,'全唐诗/poet.song.5000.json','["酒酣無復耿離腸，一路之官盡水鄉。", "公廨寒生對廬阜，客帆風定泊潯陽。", "波涵洲渚初收潦，露浥蒹葭未作霜。", "到日何人先刺謁，二林開士在琴堂。"]'),
('c3d8bccf-b8d7-44aa-a1f5-877bb827f9ec','送楚執中隨侍入蜀','林逋','宋','宋诗','song-poetry','','[]','嚴君將命之邛蜀，令子和家且侍行。',64,'全唐诗/poet.song.5000.json','["嚴君將命之邛蜀，令子和家且侍行。", "洛汭好山歸別業，江南芳草動離情。", "詩題寺壁雲根潤，書檢松窗野色明。", "他日林間無所望，只求金榜看嘉名。"]'),
('00bb1ad5-05f3-4c2e-9c87-c43ffea4ef40','送馬程員外之任烏江','林逋','宋','宋诗','song-poetry','','[]','空色青蒼寒日明，遲遲携手出柴荆。',64,'全唐诗/poet.song.5000.json','["空色青蒼寒日明，遲遲携手出柴荆。", "長貧少得交游者，漸老不禁離索情。", "去路浦帆當晚落，到官江草已春生。", "州監縣尹多才識，當念吾宗負大名。"]'),
('0b652eaf-cd4b-49f3-a42f-7dd8c6f636f2','送趙時校書之任臨川司理','林逋','宋','宋诗','song-poetry','','[]','南國古來風物好，早時游覽熟登臨。',64,'全唐诗/poet.song.5000.json','["南國古來風物好，早時游覽熟登臨。", "青山滿路人家遠，丹橘隔江秋色深。", "官况暫應勞折獄，病懷終自重分襟。", "三年解罷當求試，多草新文慰我心。"]'),
('47db5ff7-81a0-4c0c-bd85-b902910c92a3','送吳秀才赴舉','林逋','宋','宋诗','song-poetry','','[]','一戰詞場定策勛，麻衣西笑仕紛紛。',64,'全唐诗/poet.song.5000.json','["一戰詞場定策勛，麻衣西笑仕紛紛。", "風神已負青雲氣，藝業兼携白地文。", "輦下春華期縱轡，野中林色惜離羣。", "明年新榜看看見，第甲嘉名且認君。"]'),
('e532f739-5c32-41e6-a903-464698852753','送陳縱之無爲軍','林逋','宋','宋诗','song-poetry','','[]','淮天時節少春寒，幾蒂梅花雪欲殘。',64,'全唐诗/poet.song.5000.json','["淮天時節少春寒，幾蒂梅花雪欲殘。", "水次軍城囊劍入，雨餘村塢鐙馿看。", "名緣未出知誰異，道爲深窮却自難。", "第一京師早西入，廟廊題字可無韓。"]'),
('659c79bc-7158-4bc1-ab76-cb297f85dc2d','送文光師遊天台','林逋','宋','宋诗','song-poetry','','[]','天姥山深摇錫杖，野芳春翠共葳蕤。',64,'全唐诗/poet.song.5000.json','["天姥山深摇錫杖，野芳春翠共葳蕤。", "松門過水無重數，石壁看霞到盡時。", "閑避鳥啼應作觀，忽聞人迹自留詩。", "秦中河朔嘗遊覽，莫恨此方行脚遲。"]'),
('645a5a56-aab8-4700-abc2-7a62b0987db7','贈胡明府','林逋','宋','宋诗','song-poetry','','[]','一琴牢落倚松窗，孤澹天君得趣長。',64,'全唐诗/poet.song.5000.json','["一琴牢落倚松窗，孤澹天君得趣長。", "謁廟有時封縣版，坐衙終日著公裳。", "爲收牌印教村僕，偶檢圖書見古方。", "微足稅糧人更靜，却搘吟策立秋廊。"]'),
('c8727917-6e54-41be-96d1-793fc80d71b1','贈當塗朱仲敏','林逋','宋','宋诗','song-poetry','','[]','甚與時流道不同，南朝臺閣是家風。',64,'全唐诗/poet.song.5000.json','["甚與時流道不同，南朝臺閣是家風。", "高閑几格圖書畔，冷澹門庭樹石中。", "因寄詩牌尋勝景，擬投文卷數名公。", "榮登顯達他年後，應笑冥冥弋者鴻。"]'),
('f8dc8c03-b684-4e53-8a64-7299f0f6845e','舒城僧舍呈贈李仲宣文學','林逋','宋','宋诗','song-poetry','','[]','竹深淮寺雪蕭騷，一壁寒燈伴寂寥。',64,'全唐诗/poet.song.5000.json','["竹深淮寺雪蕭騷，一壁寒燈伴寂寥。", "瘦盡骨毛終騕褭，蝕來鋒刃轉豪曹。", "宦情冷落詩中見，談態軒昂酒後高。", "莫爲無辜惜才術，聖明求治正焦勞。"]'),
('c1edcae9-48b4-473a-bf9e-111924afb9ae','贈錢唐邑長高秘校','林逋','宋','宋诗','song-poetry','','[]','幾萬人家山水中，爲官古雅少人同。',64,'全唐诗/poet.song.5000.json','["幾萬人家山水中，爲官古雅少人同。", "疏簾衙退卷花軸，曲檻客來憑竹風。", "唯道簿書多傍俗，自憐琴酒未妨公。", "等閑呵出郭門近，輕棹繞湖尋佛宮。"]'),
('e8745582-36c5-49b8-bca3-eb4fa88ae146','喜皎然師見訪書贈','林逋','宋','宋诗','song-poetry','','[]','金錫鏘然款蠹關，雲膏濃渚對跳巒。',64,'全唐诗/poet.song.5000.json','["金錫鏘然款蠹關，雲膏濃渚對跳巒。", "清如霜月三五夕，瘦似煙篁一兩竿。", "舊社久拋魂夢破，近詩纔舉骨毛寒。", "池軒夜靜且留宿，往往自將秋籟彈。"]'),
('2e2ed983-36eb-4c81-bec2-ebd35dc4eb1c','寄解州李學士','林逋','宋','宋诗','song-poetry','','[]','解梁賢守古難同，張蓋垂鞭自士風。',64,'全唐诗/poet.song.5000.json','["解梁賢守古難同，張蓋垂鞭自士風。", "館職久銜疏舊地，郡符重剖枉名公。", "印廳孤坐琴尊外，鈴閣清談易老中。", "聞演絲綸徵詔近，相如文學動天聰。"]'),
('6872bd7d-4b65-432f-8691-11ccfd5c1165','寄薛學士','林逋','宋','宋诗','song-poetry','','[]','飛徵偶未下天衢，古郡寬閑且寄居。',64,'全唐诗/poet.song.5000.json','["飛徵偶未下天衢，古郡寬閑且寄居。", "曾許布衣通一刺，每留蔬食看羣書。", "高齋已想閑丹竈，清夢誰同話直廬。", "江外敢知無別計，只携琴鶴聽新除。"]'),
('8f7bac73-37c7-4eb3-b8a2-0c0814d7c771','寄傅霖','林逋','宋','宋诗','song-poetry','','[]','葛蔓煙枯束六經，高廉渾與昔賢停。',64,'全唐诗/poet.song.5000.json','["葛蔓煙枯束六經，高廉渾與昔賢停。", "黄牙稚子跨牛犢，白眼山人識劍形。", "寒睡草旁林酒壯，曉思河曲雨槎腥。", "傳聞曾說平生事，不要清朝夢武丁。"]'),
('cf8abc90-eed2-4c11-8f9c-bd7d5a833563','寄岑迪','林逋','宋','宋诗','song-poetry','','[]','久辜才術向吾朝，公罪應該洗雪條。',64,'全唐诗/poet.song.5000.json','["久辜才術向吾朝，公罪應該洗雪條。", "佐邑舊曾居府寺，轉官新合入京僚。", "門庭冷落閑中住，僮僕生疏賤價招。", "別後交遊定相憶，酒燈棋雨幾清宵。"]'),
('92909f2b-e7a5-4c6d-9dc7-90cb1b795bf0','寄耏門梁進士','林逋','宋','宋诗','song-poetry','','[]','退隠無山進乏媒，杜門芳草與蒼苔。',64,'全唐诗/poet.song.5000.json','["退隠無山進乏媒，杜門芳草與蒼苔。", "貧爲吾道應關命，達似他途亦是才。", "人靜合尋衙北寺，野凉還上郭西臺。", "江干昨夜情多少，風雨吹燈一夢迴。"]'),
('c1bd4895-0cd9-4ffb-b685-5aa34f0ec1fa','曹州寄任獨復','林逋','宋','宋诗','song-poetry','','[]','交結文章盡世驚，城中幽隠更無營。',64,'全唐诗/poet.song.5000.json','["交結文章盡世驚，城中幽隠更無營。", "敢將古道爲吾事，耻對常流語子名。", "秋思病彈曾獨聽，太玄閑寫待誰評。", "清朝故實蒲輪在，合爲高賢下帝京。"]'),
('d311cb13-beda-4b8a-bd39-726d718107d7','山中寄招葉秀才','林逋','宋','宋诗','song-poetry','','[]','夜鶴曉猿時復聞，寥寥長似耿離羣。',64,'全唐诗/poet.song.5000.json','["夜鶴曉猿時復聞，寥寥長似耿離羣。", "月中未要恨丹桂，嶺上且來看白雲。", "棋子不妨臨水著，詩題兼好共僧分。", "新憂他日榮名後，難得幽栖事靜君。"]'),
('8b8e659e-43e2-4f7b-bc00-1ae113027ba3','嘗茶次寄越僧靈皎','林逋','宋','宋诗','song-poetry','','[]','白雲峰下兩槍新，膩綠長鮮穀雨春。',64,'全唐诗/poet.song.5000.json','["白雲峰下兩槍新，膩綠長鮮穀雨春。", "靜試恰如湖上雪，對嘗兼憶剡中人。", "瓶懸金粉師應有，筯點瓊花我自珍。", "清話幾時搔首後，願和松色勸三巡。"]'),
('4f27972a-3b38-4b13-a55f-a1fe2bfef0b0','寄宣城宗言姪','林逋','宋','宋诗','song-poetry','','[]','春水涵波綠渺瀰，江南芳草又離離。',64,'全唐诗/poet.song.5000.json','["春水涵波綠渺瀰，江南芳草又離離。", "謝家元住青山郭，郄氏近攀丹桂枝。", "衣下香囊非爾好，床頭詩卷愧吾癡。", "中林獨處仍多病，早晚能來慰所思。"]'),
('44641daa-211e-4fde-bc8f-99522456d551','寄西山勤道人','林逋','宋','宋诗','song-poetry','','[]','天竺山深桂子丹，白猿啼在白雲間。',64,'全唐诗/poet.song.5000.json','["天竺山深桂子丹，白猿啼在白雲間。", "死生不出千門事，坐卧無如一室閑。", "誰伴錫痕過寂歷，自憑茶色對孱顔。", "忘機亦有龐居士，園井蕭疏病掩關。"]'),
('bd93ac38-6f26-4127-b0e1-6e09ed133667','寄呈張元禮','林逋','宋','宋诗','song-poetry','','[]','君棲枳棘官將滿，我住蓬蒿歲正窮。',64,'全唐诗/poet.song.5000.json','["君棲枳棘官將滿，我住蓬蒿歲正窮。", "駟馬交遊從此少，一瓢生事不勝空。", "衡門但枕盈盈水，羣木方摇摵摵風。", "若念故人兼久病，公餘無惜寄詩筒。"]'),
('b553f8c1-9b22-4b89-8ff8-0d396837b36b','寄玉梁施道士','林逋','宋','宋诗','song-poetry','','[]','子雲遺構住丹房，天鼓時聞數叩霜。',64,'全唐诗/poet.song.5000.json','["子雲遺構住丹房，天鼓時聞數叩霜。", "真景截波尋鐵柱，怪書披月看銅牆。", "氳氳顥氣朝胎息，熠熠辰輝夜步綱。", "大靜入來諸事罷，靈蕪盤穗卷良常。"]'),
('cadcb6df-85d0-49e9-ae45-4d8e1dfd388d','寄太白李山人','林逋','宋','宋诗','song-poetry','','[]','顔如童子髮如黳，卜築深當太白西。',64,'全唐诗/poet.song.5000.json','["顔如童子髮如黳，卜築深當太白西。", "身上祇衣粗直掇，馬前長带古偏提。", "鵾鵬懶擊三千水，龍虎閑封六一泥。", "幾度枕肱人迹外，半窗松雪論天倪。"]'),
('76b2af18-9072-4a4c-87b2-c884eb94028b','歷陽寄金陵衍上人','林逋','宋','宋诗','song-poetry','','[]','蘚暈莎叢古石房，寺和松竹背秋岡。',64,'全唐诗/poet.song.5000.json','["蘚暈莎叢古石房，寺和松竹背秋岡。", "騷吟未斷雲生褐，梵偈重開月照香。", "五老舊遊應悄默，六朝閑事肯悲凉。", "西州獨客心摇甚，抹碧江天鳥一行。"]'),
('0952d873-2756-4446-b00c-846970432cda','春日寄錢都使','林逋','宋','宋诗','song-poetry','','[]','桃花枝重肉紅垂，萱草抽苗抹綠肥。',64,'全唐诗/poet.song.5000.json','["桃花枝重肉紅垂，萱草抽苗抹綠肥。", "正語暖鶑風細細，著雙寒燕雨稀稀。", "亭臺物景兼飄絮，宅院時情漸夾衣。", "指背挾肩行樂事，不甘離索向芳菲。"]'),
('71982a72-1630-4b10-843d-e2f3185563c8','寄題歷陽馬仲文水軒','林逋','宋','宋诗','song-poetry','','[]','構得幽居近郭西，水軒風景獨難齊。',64,'全唐诗/poet.song.5000.json','["構得幽居近郭西，水軒風景獨難齊。", "烟含晚樹人家遠，雨濕春蒲燕子低。", "紅燭酒醒多聚會，粉牋詩敵幾招携。", "旅遊今日堪搔首，摇落山城困馬蹄。"]'),
('84aa6623-1727-485d-b084-c66af0878a74','暮春寄懷曹南通任寺丞','林逋','宋','宋诗','song-poetry','','[]','跌蕩情懷每事同，十年曹社醉春風。',64,'全唐诗/poet.song.5000.json','["跌蕩情懷每事同，十年曹社醉春風。", "彈弓園圃陰森下，棋子廳堂寂靜中。", "赤脚我猶無一婢，黑頭君合作三公。", "江湖今日還勞結，目送歸飛點點鴻。"]'),
('ba6140ac-0975-4483-8a9d-45d0db3354de','和西湖霽上人寄然社師','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','竹下經房號白蓮，社師高行出人天。',64,'全唐诗/poet.song.5000.json','["竹下經房號白蓮，社師高行出人天。", "一齋巾拂晨鐘次，數禮香燈夜像前。", "瞑目幾閑松下月，凈頭時動石盆泉。", "西湖舊侶因吟寄，憶著深峰萬萬年。"]'),
('415e660c-faf8-4e23-8e99-c8322b2e88b4','和陳湜贈希社師','林逋','宋','宋诗','song-poetry','','[]','瘦靠闌干搭梵襟，綠荷階面雨花深。',64,'全唐诗/poet.song.5000.json','["瘦靠闌干搭梵襟，綠荷階面雨花深。", "迢迢海寺浮杯興，杳杳秋空放鶴心。", "齋磬冷摇松吹雜，定燈孤坐竹風侵。", "鏘然更有金書偈，祇許龍神聽靜吟。"]'),
('06470445-1480-4248-9264-3245325e9e36','追和彭城太尉夏月寄題湖上湛源大師房','林逋','宋','宋诗','song-poetry','','[]','碧蒲紅蓼白蓮房，一片欒櫨撼水光。',64,'全唐诗/poet.song.5000.json','["碧蒲紅蓼白蓮房，一片欒櫨撼水光。", "海岸空聞有孤絕，山中休道更清凉。", "驚飛翡翠當軒鳥，裊過旃檀別院香。", "最愛晚天吟枕上，好雲遥聳數峰長。"]'),
('9ede27a4-58f0-4425-9727-d39ab02e93a9','集賢李建中工部嘗以七言長韻見寄感存懷沒因用追和','林逋','宋','宋诗','song-poetry','','[]','清絕門牆冷似冰，野人懷刺昔曾登。',64,'全唐诗/poet.song.5000.json','["清絕門牆冷似冰，野人懷刺昔曾登。", "新題對雨分蕭寺，舊夢經秋說杜陵。", "貧典郡符資月給，老持臺憲減霜稜。", "開元文字鍾王筆，惆悵臨風一燼燈。"]'),
('9f03ebd4-8d0b-4e9d-8be2-0dc532462ab6','和酬周啟明賢良見寄','林逋','宋','宋诗','song-poetry','','[]','治世誰能弔屈平，且披湘帙散幽經。',64,'全唐诗/poet.song.5000.json','["治世誰能弔屈平，且披湘帙散幽經。", "春陽盡吐芊芊草，霄極長垂兩兩星。", "半壁烟嵐圖太華，一筇風雪訪支硎。", "雅吟爲惠將何比，明月珊瑚海氣腥。"]'),
('c7f4b740-1543-4d08-a713-d341971621a5','酬晝師西湖春望','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','笛聲風暖野梅香，湖上憑闌日漸長。',64,'全唐诗/poet.song.5000.json','["笛聲風暖野梅香，湖上憑闌日漸長。", "一樣樓臺圍佛寺，十分煙雨簇漁鄉。", "鷗橫殘葑多成陣，柳映危橋未著行。", "終約吾師指芳草，靜吟閑步岸華陽。"]'),
('c484f7b9-b701-4674-ba4e-7791f757f377','虢略秀才以七言四韻詩爲寄輒敢酬和幸惟采覽','林逋','宋','宋诗','song-poetry','','[]','本無高亮似陽城，但愛松風入耳聲。',64,'全唐诗/poet.song.5000.json','["本無高亮似陽城，但愛松風入耳聲。", "五畝自開林下隠，一尊聊敵世間名。", "交談不遠樵農客，弄翰慵誇子墨卿。", "異日青冥肯迴顧，夫君門族舊和羹。"]'),
('0e727893-4b33-4a9a-b118-6246b478faff','壽陽城南寫望懷歷陽故友','林逋','宋','宋诗','song-poetry','','[]','楚山重疊矗淮濆，堪與王維立畫勳。',64,'全唐诗/poet.song.5000.json','["楚山重疊矗淮濆，堪與王維立畫勳。", "白鳥一行天在水，綠蕪千陣野平雲。", "孤崖拂閣晴光見，極浦漁舟曉未分。", "吟罷騷然略回首，歷陽詩社久離羣。"]'),
('3e29dbfc-b0cf-4fe4-9898-ed94ff864a0e','玉梁峽口懷朱嚴從事之官嶺外兩夕舟次于此','林逋','宋','宋诗','song-poetry','','[]','蒼莽江灣盡入深，數家村塢在山陰。',64,'全唐诗/poet.song.5000.json','["蒼莽江灣盡入深，數家村塢在山陰。", "烟橫落木寒初靜，水带微陽晚未沉。", "極覽定非他輩事，不來終負此生心。", "鱸魚斫鱠松醪酒，曾屬詩人兩日吟。"]'),
('2a535325-9f54-48a2-84f3-021da83352ab','西梁山下泊船懷別潤州杲上人','林逋','宋','宋诗','song-poetry','','[]','畫圖行李是隨緣，立別江頭雨霽天。',64,'全唐诗/poet.song.5000.json','["畫圖行李是隨緣，立別江頭雨霽天。", "鐵甕獨歸三月寺，銅瓶輕掛兩潮船。", "吟焚篆籀香初竭，老擁雲霞衲已穿。", "昨夜西梁山下月，爲師懷想幾凄然。"]'),
('f40a1b94-e148-4694-a7d0-fc398f00f269','春日懷歷陽後園遊兼寄宣城天使','林逋','宋','宋诗','song-poetry','','[]','昔年行樂伴王孫，事盡清狂是後園。',64,'全唐诗/poet.song.5000.json','["昔年行樂伴王孫，事盡清狂是後園。", "一榻竹風橫懶架，半軒花月到頑盆。", "佳人暗引鶑言語，芳草閑迷蝶夢魂。", "今日凄凉舊春色，可堪烟雨近黄昏。"]'),
('4b18af71-1df0-4379-9d83-01937349d18a','招思齊上人','林逋','宋','宋诗','song-poetry','','[]','兩槍未試泠泠水，五鬣長閑淅淅風。',64,'全唐诗/poet.song.5000.json','["兩槍未試泠泠水，五鬣長閑淅淅風。", "清會幾時搔首後，病懷無復曲肱中。", "寒雲片段浮重巘，白鳥橫斜入遠空。", "一帙逍遥不能解，牛頭焚盡待支公。"]'),
('5ee959f2-20f0-456a-b5a1-8ef3aa8b94e5','聞靈皎師自信州歸越以詩招之','林逋','宋','宋诗','song-poetry','','[]','天師蒼翠橫金錫，地藏清凉掩竹扉。',64,'全唐诗/poet.song.5000.json','["天師蒼翠橫金錫，地藏清凉掩竹扉。", "千里白雲隨野步，一湖明月上秋衣。", "詩尋靜語應無極，琴弄寒聲轉入微。", "我亦孤山有泉石，肯來松下共忘機。"]'),
('7d925a37-4f6b-43cf-ae75-0c4a22230e29','復賡前韻且以陋居幽勝詫而誘之','林逋','宋','宋诗','song-poetry','','[]','畫共藥材懸屋壁，琴兼茶具入船扉。',64,'全唐诗/poet.song.5000.json','["畫共藥材懸屋壁，琴兼茶具入船扉。", "秋花挹露如紅粉，水鳥衝烟濕翠衣。", "石磴背穿林寺近，竹烟橫點海山微。", "百千幽勝無人見，說向吾師是洩機。"]'),
('4c50b094-9528-41ae-ba91-85f4b793e7b6','詩招南陽秀才','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','莫因公薦偶失意，便擬飄蓬作旅人。',64,'全唐诗/poet.song.5000.json','["莫因公薦偶失意，便擬飄蓬作旅人。", "志壯任存題柱事，病多爭向倚門親。", "危堤柳色休傷別，上苑杏花長自春。", "況有西湖好山水，歸來且濯錦衣塵。"]'),
('8b943665-2923-4bb6-a375-d31c6135bad5','謝馬程先輩惠蜀牋','林逋','宋','宋诗','song-poetry','','[]','數幅丹霞夾白雲，封題何事寄幽人。',64,'全唐诗/poet.song.5000.json','["數幅丹霞夾白雲，封題何事寄幽人。", "虧君視草禁中客，乞我浣花谿上春。", "且與巾箱爲玩好，更無篇什寫清新。", "我來卧病還多感，一筆蛛絲滿硯塵。"]'),
('8b980e4b-f912-417b-bc43-69fd40787989','讀王黄州詩集','林逋','宋','宋诗','song-poetry','','[]','坐吟行看對清秋，懶架仍移近枕頭。',64,'全唐诗/poet.song.5000.json','["坐吟行看對清秋，懶架仍移近枕頭。", "放達有唐惟白傅，縱橫吾宋是黄州。", "左遷商嶺題無數，三入承明興未休。", "紅藥紫薇千一古，又添楊子伴牢愁。"]'),
('042cc6ed-5ab4-4faa-a6d5-afcbb948a463','讀种先生丁密諫詩','林逋','宋','宋诗','song-poetry','','[]','舊草閑看即自卑，聖朝空道苦於詩。',64,'全唐诗/poet.song.5000.json','["舊草閑看即自卑，聖朝空道苦於詩。", "高才眩望如明逸，新句無因似謂之。", "淮甸月華欹枕靜，秣陵春色按鞭遲。", "邯鄲獨步西施笑，落得星星兩鬢絲。"]'),
('fd8126df-993f-4d2d-b4c8-677ab0ee72e9','喜姪宥及第','林逋','宋','宋诗','song-poetry','','[]','新榜傳聞事可驚，單平於爾一何榮。',64,'全唐诗/poet.song.5000.json','["新榜傳聞事可驚，單平於爾一何榮。", "玉階已忝登高第，金口仍教改舊名。", "聞喜宴遊秋色雅，慈恩題記墨行清。", "巖扉掩罷無他意，但爇靈蕪感盛明。"]'),
('9e4ab872-2e5a-4a6f-8d7a-5c75a4cd2e71','傷白積殿丞','林逋','宋','宋诗','song-poetry','','[]','吏散門牆轉寂然，疏狂投分向生前。',64,'全唐诗/poet.song.5000.json','["吏散門牆轉寂然，疏狂投分向生前。", "苦無名位高今世，空有文章出古賢。", "遺傳得誰修闕下，孤墳應祇客江邊。", "池陽渺渺堪垂睫，奠罷秋枝一叫蟬。"]'),
('e581487e-fc57-4c16-a9cb-6058ed63a39d','傷朱寺丞','林逋','宋','宋诗','song-poetry','','[]','妻女飄零五嶺頭，爲君南望涕橫流。',64,'全唐诗/poet.song.5000.json','["妻女飄零五嶺頭，爲君南望涕橫流。", "浮榮暫得衣朱紱，遠宦尋聞喪白州。", "天與聲名還自折，瘴侵編什有誰收。", "朝中交舊知多少，應惜無兒似鄧攸。"]'),
('640f6cf9-dec8-461f-9055-c551259c9d8f','弔薛公孟','林逋','宋','宋诗','song-poetry','','[]','未第身魂歿帝京，東還長欠奠幽靈。',64,'全唐诗/poet.song.5000.json','["未第身魂歿帝京，東還長欠奠幽靈。", "遺文盡合編家傳，高行誰堪撰墓銘。", "談柄寂寥塵久暗，墨池荒廢草空青。", "三招不見山巾濕，擬畫軒昂太白星。"]'),
('4aa4cfdc-1be7-4213-b641-1b39d120250f','閔師自天台見寄石枕','林逋','宋','宋诗','song-poetry','','[]','斵石自何許，枕之懷赤城。',24,'全唐诗/poet.song.5000.json','["斵石自何許，枕之懷赤城。", "空廬復蕙帳，旦暮白雲生。"]'),
('cdad01f0-6fac-4b20-bc63-69dc2934445e','西湖與性上人話別','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','秋山與湖水，遠近如相送。',24,'全唐诗/poet.song.5000.json','["秋山與湖水，遠近如相送。", "後府宿扁舟，知師有歸夢。"]'),
('beb033c3-8c9d-4dcf-9a80-29be0889b67d','送謝尉','林逋','宋','宋诗','song-poetry','','[]','試吏才未申，食貧同古人。',24,'全唐诗/poet.song.5000.json','["試吏才未申，食貧同古人。", "何以贈行色，一酌湖上春。"]'),
('e79c664a-bc8c-45e3-a316-0e5cc591b32f','贈中師草聖','林逋','宋','宋诗','song-poetry','','[]','行草得三昧，林間嘗與語。',24,'全唐诗/poet.song.5000.json','["行草得三昧，林間嘗與語。", "秋風忽捲衣，別我之何所。"]'),
('4b1775bc-d6e9-460b-9200-0fdeda6c05bd','送僧之京師','林逋','宋','宋诗','song-poetry','','[]','皇城十二衢，埃塵滿香裓。',24,'全唐诗/poet.song.5000.json','["皇城十二衢，埃塵滿香裓。", "何以待歸期，山中桂花色。"]'),
('ae0a8ba8-f520-49a0-a09a-5331039164a1','孤山隠居書壁','林逋','宋','宋诗','song-poetry','','[]','山水未深猿鳥少，此生猶擬別移居。',32,'全唐诗/poet.song.5000.json','["山水未深猿鳥少，此生猶擬別移居。", "直過天竺溪流上，獨樹爲橋小結廬。"]'),
