('bc00c4ff-9b06-4559-916d-aeb53ad1e7aa','送慈師北遊','林逋','宋','宋诗','song-poetry','','[]','鬰鬰蒲茸染水田，渡淮閒寄賈人船。',32,'全唐诗/poet.song.5000.json','["鬰鬰蒲茸染水田，渡淮閒寄賈人船。", "知師一枕清秋夢，多爲林間放鶴天。"]'),
('a852fecc-1d6c-482c-8a5a-dbae34e33faf','復送慈公還虎丘山','林逋','宋','宋诗','song-poetry','','[]','孑孑歸檣五兩翻，香林禪石抱雲根。',32,'全唐诗/poet.song.5000.json','["孑孑歸檣五兩翻，香林禪石抱雲根。", "單囊憩罷還微笑，却是青山不出門。"]'),
('ad651f01-74a6-4083-8795-b809f9bc078e','即席送江夏茂才','林逋','宋','宋诗','song-poetry','','[]','與君未別且酣飲，別後令人空倚樓。',32,'全唐诗/poet.song.5000.json','["與君未別且酣飲，別後令人空倚樓。", "一點風帆若爲望，海門平闊鷺濤秋。"]'),
('d1d4e5ef-7ac5-493f-ad6a-71bb9d1d8f14','送易從師還金華','林逋','宋','宋诗','song-poetry','','[]','吟卷田衣歲向殘，孤舟夜泊大江寒。',32,'全唐诗/poet.song.5000.json','["吟卷田衣歲向殘，孤舟夜泊大江寒。", "前巖百本長松色，及早回來带雪看。"]'),
('3b60dcb2-0dd9-4525-a935-aecdbd573697','送丁秀才歸四明','林逋','宋','宋诗','song-poetry','','[]','有似東浮滄海君，乘槎泛泛逐歸雲。',32,'全唐诗/poet.song.5000.json','["有似東浮滄海君，乘槎泛泛逐歸雲。", "蛟綃市得能爲寄，擬寫清真隠秘文。"]'),
('dd315546-82b5-4b50-98e1-b5b5ceef459c','送謝氏昆仲歸閩中','林逋','宋','宋诗','song-poetry','','[]','清邵才高雲與機，林間文會忽相違。',32,'全唐诗/poet.song.5000.json','["清邵才高雲與機，林間文會忽相違。", "南中草木正黄落，或羨冥鴻兩兩飛。"]'),
('43a3cafa-acac-4db4-9731-c54a5cc5565e','送遂良師遊天台','林逋','宋','宋诗','song-poetry','','[]','貝葉松枝想暫閒，半囊乘興幾時還。',32,'全唐诗/poet.song.5000.json','["貝葉松枝想暫閒，半囊乘興幾時還。", "船窗月上滄洲遠，應有詩題憶舊山。"]'),
('0f53d200-2dd4-4b6f-aa62-ac336c23ed52','送遵式師謁金陵王相國  其一','林逋','宋','宋诗','song-poetry','','[]','杯渡當過白鷺灘，石城春氣尚微寒。',32,'全唐诗/poet.song.5000.json','["杯渡當過白鷺灘，石城春氣尚微寒。", "公台謁罷如乘興，試訪南朝事迹看。"]'),
('56c3d6aa-66c7-4ae7-ae79-ea8a6fabc9c4','送遵式師謁金陵王相國  其二','林逋','宋','宋诗','song-poetry','','[]','高牙熊軾隠鈴齋，棠樹陰濃長綠苔。',32,'全唐诗/poet.song.5000.json','["高牙熊軾隠鈴齋，棠樹陰濃長綠苔。", "丞相望尊賓謁少，清言應喜道人來。"]'),
('16ba8d59-38dc-4645-ada7-c1d337fe2061','送遵式師謁金陵王相國  其三','林逋','宋','宋诗','song-poetry','','[]','天竺孱顔暫掩扉，講香浮穗上行衣。',32,'全唐诗/poet.song.5000.json','["天竺孱顔暫掩扉，講香浮穗上行衣。", "白猿聲裏生公石，莫遣移文怨晚歸。"]'),
('3b6ae23f-ecca-40ed-ad5b-f2d8435af29b','送善中師歸四明','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','四明山水別多時，老病心閒事事違。',32,'全唐诗/poet.song.5000.json','["四明山水別多時，老病心閒事事違。", "夢想西湖古蘭若，又和秋色送僧歸。"]'),
('a92f034a-ca76-4ab8-8633-f898fbb83a31','送人遊金山','林逋','宋','宋诗','song-poetry','','[]','水烟霜樹矗層巒，點破江心一簇寒。',32,'全唐诗/poet.song.5000.json','["水烟霜樹矗層巒，點破江心一簇寒。", "見說天多剩得月，爲予間上上方看。"]'),
('1a41d8eb-0d26-4409-8c7a-e7e74724b594','送然上人南還','林逋','宋','宋诗','song-poetry','','[]','囊携琴譜與詩稿，寄卧船窗一榻深。',32,'全唐诗/poet.song.5000.json','["囊携琴譜與詩稿，寄卧船窗一榻深。", "莫向雲中認江樹，等閒驚起故園心。"]'),
('3e2ee8e9-8ff9-44ea-a6d2-6e258861734d','送人之蒼梧','林逋','宋','宋诗','song-poetry','','[]','側身南望但依依，片席乘風去似飛。',32,'全唐诗/poet.song.5000.json','["側身南望但依依，片席乘風去似飛。", "莫謂蒼梧在天末，帝鄉看逐白雲歸。"]'),
('03d7530a-22c3-40fa-bb28-be3747ec1c0b','送有交師輦下','林逋','宋','宋诗','song-poetry','','[]','濾羅閒佩氎巾輕，秋籟隨身指去程。',32,'全唐诗/poet.song.5000.json','["濾羅閒佩氎巾輕，秋籟隨身指去程。", "輦下大僚多好事，退朝誰著道衣迎。"]'),
('ecd9ba4f-26f7-4caf-9b1c-67e48c994dac','送大方師歸金陵','林逋','宋','宋诗','song-poetry','','[]','渺渺江天白鳥飛，石城秋色送僧歸。',32,'全唐诗/poet.song.5000.json','["渺渺江天白鳥飛，石城秋色送僧歸。", "長干古寺經行了，爲到清凉看翠微。"]'),
('f13d5ac9-45fd-4d54-9abe-693fd3105456','監郡吳殿丞惠以筆墨建茶各吟一絕謝之 筆','林逋','宋','宋诗','song-poetry','','[]','犀利鋒鋩敵五兵，夢中青鏤未爲靈。',32,'全唐诗/poet.song.5000.json','["犀利鋒鋩敵五兵，夢中青鏤未爲靈。", "空山日午南窗暖，擬寫黄庭內景經。"]'),
('bba39465-daf2-40b1-b000-263ce9264bdd','監郡吳殿丞惠以筆墨建茶各吟一絕謝之 墨','林逋','宋','宋诗','song-poetry','','[]','青暈時磨半硯雲，更將書帖拂秋塵。',32,'全唐诗/poet.song.5000.json','["青暈時磨半硯雲，更將書帖拂秋塵。", "衰羸自顧空多感，不是臨池苦學人。"]'),
('e6f56f6a-50eb-44c8-986b-09762050f7f9','監郡吳殿丞惠以筆墨建茶各吟一絕謝之 茶','林逋','宋','宋诗','song-poetry','','[]','石輾輕飛瑟瑟塵，乳花烹出建溪春。',32,'全唐诗/poet.song.5000.json','["石輾輕飛瑟瑟塵，乳花烹出建溪春。", "世間絕品人難識，閒對茶經憶古人。"]'),
('79a5d3f1-ba17-4667-baef-c6a7dcb78292','鳧','林逋','宋','宋诗','song-poetry','','[]','三三兩兩自相隨，檀頸回看{發色}赩衣。',35,'全唐诗/poet.song.5000.json','["三三兩兩自相隨，檀頸回看{發色}赩衣。", "野水無波秋色凈，不知何事忽驚飛。"]'),
('e546482f-55d7-46af-aafa-af683f2e6170','貓兒','林逋','宋','宋诗','song-poetry','','[]','纖鈎時得小溪魚，飽卧花陰興有餘。',32,'全唐诗/poet.song.5000.json','["纖鈎時得小溪魚，飽卧花陰興有餘。", "自是鼠嫌貧不到，莫慚尸素在吾廬。"]'),
('309f32d1-2bdb-47ca-84c4-b38b6d4a4d5e','鳴皋','林逋','宋','宋诗','song-poetry','','[]','皋禽名祇有前聞，孤引圓吭夜正分。',32,'全唐诗/poet.song.5000.json','["皋禽名祇有前聞，孤引圓吭夜正分。", "一唳便驚寥泬破，亦無閒意到青雲。"]'),
('2deb3089-8566-44bd-a968-6886753d0878','呦呦','林逋','宋','宋诗','song-poetry','','[]','深林摵摵分行響，淺葑茸茸疊浪痕。',32,'全唐诗/poet.song.5000.json','["深林摵摵分行響，淺葑茸茸疊浪痕。", "春雪滿山人起晚，數聲低叫喚籬門。"]'),
('36218fec-6881-40ee-8fd8-eb7d2abdc9c8','小舟','林逋','宋','宋诗','song-poetry','','[]','舷低冷戛荷千柄，底𦨖斜穿月半輪。',32,'全唐诗/poet.song.5000.json','["舷低冷戛荷千柄，底𦨖斜穿月半輪。", "一笠一蓑人穩坐，晚風蕭颯弄青蘋。"]'),
('23a8016b-fde3-493b-8081-482b89d009d3','槐木紙椎','林逋','宋','宋诗','song-poetry','','[]','入手輕乾是古槐，幾聲清響徹池臺。',32,'全唐诗/poet.song.5000.json','["入手輕乾是古槐，幾聲清響徹池臺。", "椎餘魚網如脂滑，時寫新詩肯寄來。"]'),
('b4a75304-3f18-4687-9984-fd9fa356d078','自作壽堂因書一絕以誌之','林逋','宋','宋诗','song-poetry','','[]','湖上青山對結廬，墳頭秋色亦蕭疏。',32,'全唐诗/poet.song.5000.json','["湖上青山對結廬，墳頭秋色亦蕭疏。", "茂陵他日求遺稿，猶喜曾無封禪書。"]'),
('6be1dcb7-e408-4025-9bf3-118195aa838b','和運使陳學士遊靈隠寺寓懷','林逋','宋','宋诗','song-poetry','','[]','山壑氣相合，旦暮生秋陰。',144,'全唐诗/poet.song.5000.json','["山壑氣相合，旦暮生秋陰。", "松門韵虛籟，錚若鳴瑶琴。", "舉目羣狀動，傾耳百慮沉。", "按部既優游，時此振衣襟。", "泓澄冷泉色，寫我清曠心。", "飄颻白猿聲，答我雅正吟。", "經臺復丹井，捫蘿常遍臨。", "鶴蓋青霞映，玉趾蒼苔侵。", "溫顔煦槁木，真性馴幽禽。", "所以仁惠政，及物一一深。", "洒翰嶙峋壁，返駕旃檀林。", "回睨窣堵峰，天半千萬尋。"]'),
('b11da5bc-89c8-409f-ae27-dca24b210a93','西湖孤山寺後舟中寫望','林逋','宋','宋诗','song-poetry','','["\u897f\u6e56"]','天竺橫分景色寬，孤山背後泊船看。',64,'全唐诗/poet.song.5000.json','["天竺橫分景色寬，孤山背後泊船看。", "林藏野路秋偏靜，水映漁家晚自寒。", "拂拂烟雲初淡蕩，蕭蕭蘆葦半衰殘。", "舂鋤數點誰驚起，書破晴雲粉字乾。"]'),
('16fd56f7-fe7a-4369-bd88-cb1ab79df3ca','小隠','林逋','宋','宋诗','song-poetry','','[]','魯望無來已百年，又生吾輩在林泉。',64,'全唐诗/poet.song.5000.json','["魯望無來已百年，又生吾輩在林泉。", "誰知隠遁爲高尚，敢道文章到聖賢。", "月界曉窗琴嶽潤，竹摇秋機墨雲鮮。", "南塘一霎霏微雨，更擁漁蓑上釣船。"]'),
('0b0eb7fe-5f7b-44ac-80af-77f2368d1404','梅花二首  其一','林逋','宋','宋诗','song-poetry','','[]','宿靄相粘凍雪殘，一枝深映竹叢寒。',64,'全唐诗/poet.song.5000.json','["宿靄相粘凍雪殘，一枝深映竹叢寒。", "不辭日日旁邊立，長願年年末上看。", "蕊訝粉綃裁太碎，蒂疑紅蠟綴初乾。", "香蒭獨酌聊爲壽，從此羣芳興亦闌。"]'),
('06a965ff-9341-41e0-8afa-7c235f20fedd','梅花二首  其二','林逋','宋','宋诗','song-poetry','','[]','孤根何事在柴荆，村色仍將臘候并。',64,'全唐诗/poet.song.5000.json','["孤根何事在柴荆，村色仍將臘候并。", "橫隔片烟爭向靜，半粘殘雪不勝清。", "等閑題詠誰爲愧，子細相看似有情。", "搔首壽陽千載後，可堪青草雜芳英。"]'),
('199e472e-016d-4be2-a32e-2d7ab5426939','孤山雪中寫望','林逋','宋','宋诗','song-poetry','','[]','片山兼水繞，晴雪復漫漫。',48,'全唐诗/poet.song.5000.json','["片山兼水繞，晴雪復漫漫。", "一徑何人到，中林盡日看。", "遠分樵載重，斜壓葦叢乾。", "樓閣嚴城寺，疏鐘動晚寒。"]'),
('1b324b75-eb45-4c3e-87de-7487f8d96ef8','洞霄宮','林逋','宋','宋诗','song-poetry','','[]','大滌山相向，華陽路暗通。',48,'全唐诗/poet.song.5000.json','["大滌山相向，華陽路暗通。", "風霜唐碣久，草木漢祠空。", "劍石苔花碧，丹池水氣紅。", "幽人天柱側，茅屋灑松風。"]'),
('d941601d-130d-4ce7-9117-454aa484ce3f','宿洞霄宮','林逋','宋','宋诗','song-poetry','','[]','秋山不可盡，秋思亦無根。',48,'全唐诗/poet.song.5000.json','["秋山不可盡，秋思亦無根。", "碧澗流紅葉，青林點白雲。", "凉陰一鳥下，落日亂蟬分。", "此夜芭蕉雨，何人枕上聞。"]'),
('ca45bf5f-d4fb-4d41-85df-13473f3d4d9c','秋懷','林逋','宋','宋诗','song-poetry','','[]','霏霏煙雨拂西窗，緗帙披殘卧縹缸。',64,'全唐诗/poet.song.5000.json','["霏霏煙雨拂西窗，緗帙披殘卧縹缸。", "林木細分山去削，水波微動鶴丁樁。", "凉沈欲睡何妨縱，靜壯詩魔未易降。", "搔首舊遊堪入畫，一檣如練下澄江。"]'),
('b8b00512-7b76-43be-9e87-513d485a3a10','和酬泉南陳賢良見贈','林逋','宋','宋诗','song-poetry','','[]','湛盧生澀鞘秋塵，方冊誰談禮樂因。',64,'全唐诗/poet.song.5000.json','["湛盧生澀鞘秋塵，方冊誰談禮樂因。", "兩地貴遊無舊識，五天清會有高人。", "泉關茶井當猶惜，火養丹爐看獨頻。", "揚袂公車莫相調，浮名應未似身親。"]'),
('8722f52f-e4d4-490e-b571-8836128e5531','寄輦下莫降秀才','林逋','宋','宋诗','song-poetry','','[]','犀圍古暗革靴鳴，楚楚衣裾白苧輕。',64,'全唐诗/poet.song.5000.json','["犀圍古暗革靴鳴，楚楚衣裾白苧輕。", "節概平時長獨立，文章近日合雙行。", "且看輦轂千蹄曉，復憶溪山數峰晴。", "一第臨臨杏花宴，滿都春色叫遷鶑。"]'),
('4b798ab3-9efd-4245-a62f-a5f1bc6978e6','風水洞','林逋','宋','宋诗','song-poetry','','[]','平昔常聞風水洞，重山復水去無窮。',32,'全唐诗/poet.song.5000.json','["平昔常聞風水洞，重山復水去無窮。", "因緣偶入雲泉路，林下先聞接客鐘。"]'),
('14efef3d-190d-4794-83fc-16c479cff0db','華陽洞','林逋','宋','宋诗','song-poetry','','[]','華陽山雨拂輕塵，獨步煙霞訪隠真。',64,'全唐诗/poet.song.5000.json','["華陽山雨拂輕塵，獨步煙霞訪隠真。", "笑傲太平雲外客，安閒清世夢中身。", "金章名重人稱貴，布褐才高道不貧。", "吟罷洞天風正淡，自知凡骨定逢人。"]'),
('1f2ae42b-5120-4943-9153-f7ae89521254','村居書事兼簡陳賢良','林逋','宋','宋诗','song-poetry','','[]','抱關隨俗本無能，却掩深居避愛憎。',64,'全唐诗/poet.song.5000.json','["抱關隨俗本無能，却掩深居避愛憎。", "兩岸解驚秋釣石，風窗花落夜棋燈。", "穿雲寄藥多山叟，刻竹留詩半野僧。", "吟閣晚凉堪共望，遠峰蒼翠勢層層。"]'),
('a7cccd62-0086-4e03-aa13-2893e499d52e','句  其一','林逋','宋','宋诗','song-poetry','','[]','草泥行郭索，雲木叫鉤輈。',12,'全唐诗/poet.song.5000.json','["草泥行郭索，雲木叫鉤輈。"]'),
('50d58d00-68d0-4655-bf73-7b5107940fe5','句  其二','林逋','宋','宋诗','song-poetry','','[]','珠繁楊氏果，翠耀孔家禽。',12,'全唐诗/poet.song.5000.json','["珠繁楊氏果，翠耀孔家禽。"]'),
('58dc5dfe-4827-4540-a750-bd1e770f33b2','句  其三','林逋','宋','宋诗','song-poetry','','[]','陰沉天氣連翩醉，摘索花枝料峭寒。',16,'全唐诗/poet.song.5000.json','["陰沉天氣連翩醉，摘索花枝料峭寒。"]'),
