('ce490b06-5a59-4b8e-937b-5ad700bfd586','句  其一二','林逋','宋','宋诗','song-poetry','','[]','天寒絡緯悲向壁，秋高風露聲入懷。',16,'全唐诗/poet.song.5000.json','["天寒絡緯悲向壁，秋高風露聲入懷。"]'),
('00553b74-40cf-44d9-a940-7caa751ce7f7','存目  其一','林逋','宋','宋诗','song-poetry','','[]','詩題：酒首句：溫如春色爽如秋。',15,'全唐诗/poet.song.5000.json','["詩題：酒首句：溫如春色爽如秋。"]'),
('dac7de79-957c-4193-98e2-9a71b8df7357','存目  其二','林逋','宋','宋诗','song-poetry','','[]','詩題：殘詩二句首句：巢由不願仕，堯舜豈遺人。',22,'全唐诗/poet.song.5000.json','["詩題：殘詩二句首句：巢由不願仕，堯舜豈遺人。"]'),
('28c66d86-ca6d-4ad2-99e6-c47e51055d2f','庶子泉','盛度','宋','宋诗','song-poetry','','[]','深藏西竹寺，寒擁北譙城。',24,'全唐诗/poet.song.5000.json','["深藏西竹寺，寒擁北譙城。", "石字贊皇古，泉銘庶子清。"]'),
('98541462-ae1d-416d-864c-b6cabe7dc18e','送何水部蒙出牧袁州','盛度','宋','宋诗','song-poetry','','[]','文昌郎位改清資，乞領魚符賦式微。',64,'全唐诗/poet.song.5000.json','["文昌郎位改清資，乞領魚符賦式微。", "雉省月寒慵夜直，隼旟風細喜秋歸。", "宜春酒助新開宴，侍史香餘舊賜衣。", "客向西山思井舊，莫教漚鳥見人飛。"]'),
('cc102a27-c234-41f1-823f-ac4410232e9d','修竹臺','盛度','宋','宋诗','song-poetry','','[]','我來小小郡，愛此高高臺。',24,'全唐诗/poet.song.5000.json','["我來小小郡，愛此高高臺。", "前對蒼筤竹，萬竿球琳材。"]'),
('96e4b0bb-c7b8-4a84-b994-c856884ac162','句  其一','盛度','宋','宋诗','song-poetry','','[]','我來佩竹使，方且憩熊轓。',12,'全唐诗/poet.song.5000.json','["我來佩竹使，方且憩熊轓。"]'),
('dc2b0eb7-89e7-47cb-8a54-5556b7905ef1','句  其二','盛度','宋','宋诗','song-poetry','','[]','南國松楸舊，東湖水石凉。',12,'全唐诗/poet.song.5000.json','["南國松楸舊，東湖水石凉。"]'),
('49a43644-6487-413c-b3e9-3c2e71b4d7ad','寄荔枝與盛參政','田從易','宋','宋诗','song-poetry','','[]','櫻桃真小子，龍眼是凡姿。',24,'全唐诗/poet.song.5000.json','["櫻桃真小子，龍眼是凡姿。", "橄欖爲下輩，枇杷作客兒。"]'),
('a2a472e5-e94e-418f-8a55-0901fdaad3da','賦新繁周表權如詔亭','馮彭年','宋','宋诗','song-poetry','','[]','先生教子作通儒，詩禮親闈伯鯉趨。',64,'全唐诗/poet.song.5000.json','["先生教子作通儒，詩禮親闈伯鯉趨。", "亭構義方名昔著，詔頒封爵語今符。", "榮因慈孝家聲振，默契絲綸寵數殊。", "善慶誰能肩懿躅，賢哉奮達美相須。"]'),
('10864f5c-3eab-49ef-ba37-075952eeeb68','寄嵩嶽吉上人','李若谷','宋','宋诗','song-poetry','','[]','結庵嵩少深，高道恐難偏。',48,'全唐诗/poet.song.5000.json','["結庵嵩少深，高道恐難偏。", "苦海好求寶，天花莫著身。", "一心俱已了，五字更應新。", "誰謂孤雲跡，名曾達紫宸。"]'),
('803f5186-cfa7-4dad-8704-c59dcdab0aea','題方干舊隠  其一','李若谷','宋','宋诗','song-poetry','','[]','世占桐江籍，君真處士家。',50,'全唐诗/poet.song.5000.json','["世占桐江籍，君真處士家。", "風騷傳旨趣，林⿰木養是生涯。", "垂釣嚴灘近，求名帝里賒。", "扁舟我相訪，遠岸日初斜。"]'),
('2a4a7055-60d6-44cc-a01b-0b4312573ca2','題方干舊隠  其二','李若谷','宋','宋诗','song-poetry','','[]','奇峰重復疊，宅在翠屏間。',48,'全唐诗/poet.song.5000.json','["奇峰重復疊，宅在翠屏間。", "僧到偏憐靜，雲留自共閑。", "巖前樵徑接，門外釣舟還。", "老約爲鄰並，須求一畝山。"]'),
('6214ee00-080a-48c3-82ea-69ea841087a8','訪徐沖晦','郎簡','宋','宋诗','song-poetry','','[]','湖上訪高士，徑深行綠苔。',48,'全唐诗/poet.song.5000.json','["湖上訪高士，徑深行綠苔。", "應聞山犬吠，知是野人來。", "岸幘出相接，柴門自爲開。", "林閒清話久，薄暮榜舟回。"]'),
('02761a30-779c-496d-bbec-22c86767f997','登太山','郭賁','宋','宋诗','song-poetry','','[]','雙屐衝煙上泰臺，欲將老眼傍天開。',64,'全唐诗/poet.song.5000.json','["雙屐衝煙上泰臺，欲將老眼傍天開。", "春深疊嶂晴看雪，雨後飛泉夜聽雷。", "玉節攢蒼烟浩渺，羣山裂翠壁崔嵬。", "目前齊魯何須問，千古登封只草萊。"]'),
('2b06d82f-cf71-427d-83b4-1654ccc1a5d0','雲峰寺','樂黄庭','宋','宋诗','song-poetry','','[]','巍峨山半寺，幽景獨牽吟。',48,'全唐诗/poet.song.5000.json','["巍峨山半寺，幽景獨牽吟。", "雲鎖定僧室，鹿眠庭檜陰。", "石峰岑隠隠，金殿氣森森。", "到即無他念，令人有道心。"]'),
('cb33e435-5f0c-4342-bab7-b3de18851c24','題楊凝式書','安鴻漸','宋','宋诗','song-poetry','','[]','端州石硯宣城管，王屋松煙紫兔毫。',32,'全唐诗/poet.song.5000.json','["端州石硯宣城管，王屋松煙紫兔毫。", "更得孤卿老書札，人間無此五般高。"]'),
('9f5f2e81-385e-4f94-b04a-a7975a50d04b','句  其一','李慶孫','宋','宋诗','song-poetry','','[]','軸裝曲譜金書字，樹記花名玉篆牌。',16,'全唐诗/poet.song.5000.json','["軸裝曲譜金書字，樹記花名玉篆牌。"]'),
('582a17ff-e11c-4a70-9983-67c02887fde8','句  其二','李慶孫','宋','宋诗','song-poetry','','[]','四夷妙賦無人誦，三酌酸文舉世傳。',16,'全唐诗/poet.song.5000.json','["四夷妙賦無人誦，三酌酸文舉世傳。"]'),
('b5258b03-0b0c-4ec3-8db8-ba25605ed0f5','送僧歸護國寺','黄宗旦','宋','宋诗','song-poetry','','[]','一缾一鉢是生涯，來扣樞扉带礪家。',64,'全唐诗/poet.song.5000.json','["一缾一鉢是生涯，來扣樞扉带礪家。", "寵服降從丹鳳闕，禪房歸掩赤城霞。", "五芝巖下傳心印，八桂峰前散雨花。", "還伴白雲重到此，會看恩館築堤沙。"]'),
('ef8e37a7-1926-4e28-abae-d5205dab0c24','句','黄宗旦','宋','宋诗','song-poetry','','[]','就中喜有龍門客，躍出洪波只待雷。',16,'全唐诗/poet.song.5000.json','["就中喜有龍門客，躍出洪波只待雷。"]'),
('55d7565f-bf8a-4316-be21-92a9224807f1','和陳倅遊西湖','于九流','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高城連水石，對景未能還。',48,'全唐诗/poet.song.5000.json','["高城連水石，對景未能還。", "白日臨流坐，清風伴我閒。", "縱心移棹去，半醉入花間。", "未必逢僧語，蓮香已解顔。"]'),
('63f3fd15-6ae5-468a-893e-4d0e646502c8','送何水部蒙出牧袁州','錢丕','宋','宋诗','song-poetry','','[]','白首名郎有幾人，雙旌晝錦不如君。',64,'全唐诗/poet.song.5000.json','["白首名郎有幾人，雙旌晝錦不如君。", "楚江萍暖烘朝日，玉女衣輕挂曉雲。", "極浦仙舟煙澹澹，高秘郡閣葉紛紛。", "政成更與他州別，從古宜陽重藝文。"]'),
('dbc0b826-031b-442a-b442-1c5efcfc3141','勘書','孫僅','宋','宋诗','song-poetry','','[]','儒家無外事，招客勘青編。',120,'全唐诗/poet.song.5000.json','["儒家無外事，招客勘青編。", "筆墨東西置，朱黄次第研。", "頻憂傷點竄，細恐誤流傳。", "改易文辭正，增加字數全。", "目因繁處倦，心向注中專。", "端坐窮今古，披襟見聖賢。", "疲勞時舉白，遊息或談玄。", "得興忘昏旭，題名記歲年。", "棲毫思確論，廢卷恨忘篇。", "魚魯皆刊定，誰人敢間然。"]'),
('d46a894b-6fc4-49cb-b09c-35259f348486','贈种徵君放','孫僅','宋','宋诗','song-poetry','','[]','雄文英概比君難，二十高名滿世間。',144,'全唐诗/poet.song.5000.json','["雄文英概比君難，二十高名滿世間。", "飛詔幾回來北闕，草玄終不出南山。", "詩篇落處風雷動，筆力停時造化閑。", "仙術每將丹訣解，史才曾把逸書刪。", "家僮只有猿隨從，坐客唯聞鶴往還。", "兩制詞臣求識面，九重天子望祇顔。", "處士星孤輕世俗，大夫松好賤官班。", "棋殘夜石秦雲斷，琴徹秋巖蜀月彎。", "朝議蒲輪看再降，肯教從此老柴關。"]');
